-- Poems batch 336
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('035b12f0-6160-4364-aed6-ec888d577e36','留題黄山院','楊億','宋','宋诗','song-poetry','','[]','禾黍離離一逕通，遊人攬轡即過從。',64,'全唐诗/poet.song.6000.json','["禾黍離離一逕通，遊人攬轡即過從。", "趁齋幽鳥聞疏磬，出定高僧見偃松。", "夜靜龕燈凝古殿，雨餘巖溜迸前峰。", "昔年曾此題名處，素壁欹斜翠蘚重。"]'),
('e0ce48d1-bd74-4a2f-9f35-fa8aa48e03a6','題弟晦所居壁','楊億','宋','宋诗','song-poetry','','[]','制宅何其巧，連山復带溪。',72,'全唐诗/poet.song.6000.json','["制宅何其巧，連山復带溪。", "芳樽長有酒，嘉樹自成蹊。", "學舍祥鱣墮，歌梁賀燕迷。", "調琴明月榭，繫馬綠楊堤。", "好畤田園美，南華物我齊。", "終當解簪組，同此味天倪。"]'),
('493787cb-b88a-45d0-ab3a-5b48bbba5379','留别桐城主簿','楊億','宋','宋诗','song-poetry','','[]','早曾兔苑傳詞賦，屈在桐鄉勾簿書。',64,'全唐诗/poet.song.6000.json','["早曾兔苑傳詞賦，屈在桐鄉勾簿書。", "薄宦交朋嗟絆驥，清貧人吏說懸魚。", "二年領郡睽離久，一夕當樽鄙恡袪。", "苦恨秋風動行色，徘徊無計駐征車。"]'),
('440e0f40-2fbf-4361-b104-5bbf237eb12e','行次潁州值雨留駐數日因貽郡守秘閣刁公','楊億','宋','宋诗','song-poetry','','[]','夢想蒼龍闕，盤桓汝水濱。',48,'全唐诗/poet.song.6000.json','["夢想蒼龍闕，盤桓汝水濱。", "郡侯偏愛客，秋雨更留人。", "饌盛嘗鱸鱠，樽空倒角巾。", "羈愁不能遣，唯恐二毛新。"]'),
('a10183d6-e7e7-495b-a491-5e1e2d03f97f','旅中重陽有懷鄉國','楊億','宋','宋诗','song-poetry','','[]','嘉節臨重九，羈遊託異鄉。',48,'全唐诗/poet.song.6000.json','["嘉節臨重九，羈遊託異鄉。", "茰房誰繫臂，菊蘂懶浮觴。", "野渡賓鴻急，村田晚稻黄。", "悲秋更懷土，只恐鬢成霜。"]'),
('0b198421-637b-44f5-816d-1d8a9af281ea','重陽日憶遠','楊億','宋','宋诗','song-poetry','','[]','逆旅重陽節，窮秋萬里身。',48,'全唐诗/poet.song.6000.json','["逆旅重陽節，窮秋萬里身。", "金英浮酒盞，珠泪濕衣巾。", "爲客飄蓬遠，思家落葉頻。", "只應蝴蝶夢，夜夜得相親。"]'),
('d3d40b2f-ec7b-4526-8a60-0f4e83a033a4','代答','楊億','宋','宋诗','song-poetry','','[]','征車苦迢遞，節物感愁辛。',48,'全唐诗/poet.song.6000.json','["征車苦迢遞，節物感愁辛。", "已入授衣月，那經落帽辰。", "金樽難獨酌，寶瑟任生塵。", "把菊流雙泪，誰知憶遠人。"]'),
('2d961d8c-43fc-4408-a589-336fdec0431a','戲贈潁州萬壽尉吳待問','楊億','宋','宋诗','song-poetry','','[]','宦途南北最情親，歲晏相逢潁水濱。',64,'全唐诗/poet.song.6000.json','["宦途南北最情親，歲晏相逢潁水濱。", "舊日青衿同學校，暫時黄綬困埃塵。", "樽中滿酌香醪美，門外高懸綵棒新。", "鷄黍留歡已慵發，可堪經雨折紗巾。"]'),
('ddb00e2f-b98b-4290-9b00-4e6e72614de3','題顯道人壁','楊億','宋','宋诗','song-poetry','','[]','心似寒灰不復然，尋常談論即彌天。',64,'全唐诗/poet.song.6000.json','["心似寒灰不復然，尋常談論即彌天。", "門臨潁水多年住，法自曹溪幾世傳。", "儒士誰同翻貝葉，都人長見施金錢。", "翰林詩版分明在，曾與吾家有舊緣。"]'),
('b80d160c-f924-485a-bea2-99603e096f95','史館阮比部知衢州因歸建陽别墅二首  其一','楊億','宋','宋诗','song-poetry','','[]','再入蓬丘席未暖，飄飄又建隼旟行。',64,'全唐诗/poet.song.6000.json','["再入蓬丘席未暖，飄飄又建隼旟行。", "交朋莫惜河梁别，鄉曲初期晝錦榮。", "竹箭波聲隨一棹，斧柯山色對雙旌。", "子牟江海心應在，頻上高樓望帝京。"]'),
('b42ecb9d-de98-4870-aa67-8273b6a099c8','史館阮比部知衢州因歸建陽别墅二首  其二','楊億','宋','宋诗','song-poetry','','[]','少小鄉關振大名，武夷山翠落門庭。',64,'全唐诗/poet.song.6000.json','["少小鄉關振大名，武夷山翠落門庭。", "郎君近折仙人桂，伯氏高分處士星。", "城郭遼東應改易，芝蘭謝圃自分馨。", "吳民正待隨車雨，莫苦淹留醉醁醽。"]'),
('a44fb682-b0f1-4a57-972b-edca02de203d','集賢宿直寄中書李梁二舍人','楊億','宋','宋诗','song-poetry','','[]','耿耿銀釭照直廬，西風黄葉滿庭除。',160,'全唐诗/poet.song.6000.json','["耿耿銀釭照直廬，西風黄葉滿庭除。", "愁心不忍聞賓雁，病眼猶能拾蠧魚。", "欹枕微吟空展轉，遶廊閑步自躊躇。", "銅龍漏滴傳鈎盾，玉兔光芒射綺疏。", "薄宦久淹滄海郡，故交多入紫垣居。", "洛陽已在拜塵後，宣室那逢膝席初。", "投閣寂寥深自愧，抱關憔悴擬何如。", "寧思西掖五花判，且補河東三篋書。", "桑梓任抛萬里外，蓬萊試住十年餘。", "釋之不調嵇康懶，終待休官學灌蔬。"]'),
('42df8f70-f1f5-4537-8205-fc5c757fdc2e','翰林王學士奉使兩川','楊億','宋','宋诗','song-poetry','','[]','萬里征西頻告捷，九重喻蜀正裁書。',96,'全唐诗/poet.song.6000.json','["萬里征西頻告捷，九重喻蜀正裁書。", "忽聞召對浴堂殿，元是親乘使者車。", "井邑凋殘經亂後，軍城鼓舞拜恩初。", "銅梁迢遞驅騶騎，玉署深嚴鎖直廬。", "星曆更須占李郃，雪園應恨欠相如。", "歸來便在三台席，轉與交親禮數疏。"]'),
('850de59d-2902-4c74-a0e5-fd4a365d1ecc','董給事知洪州','楊億','宋','宋诗','song-poetry','','[]','豫章南國一都會，夕拜東臺最上流。',64,'全唐诗/poet.song.6000.json','["豫章南國一都會，夕拜東臺最上流。", "捧詔暫辭青鎖闥，攜家便汎木蘭舟。", "褰帷聽訟民謠洽，解榻延賓主禮優。", "只恐徵黄在朝暮，西山靈藥未容求。"]'),
('20b1cb51-786d-45fa-9e36-d91a08b53b05','梁舍人奉使巴中','楊億','宋','宋诗','song-poetry','','[]','藥署深嚴纔草詔，劍關迢遞忽乘軺。',64,'全唐诗/poet.song.6000.json','["藥署深嚴纔草詔，劍關迢遞忽乘軺。", "霜天歷歷巴猿苦，山路駸駸莋馬驕。", "梁苑寒風吹别袂，瞿塘春水送歸橈。", "紫垣遣使非常例，應有星文動九霄。"]'),
('599016fc-9951-4a48-90a1-31c8542f243f','次韻和族弟日華寄編修諸學士之什','楊億','宋','宋诗','song-poetry','','[]','鎖闈漫喜塵通籍，蓬巷無人肯顧廬。',64,'全唐诗/poet.song.6000.json','["鎖闈漫喜塵通籍，蓬巷無人肯顧廬。", "天禄解嘲纔答客，集仙置使又修書。", "非煙繚繞縈珠網，流水潺湲逗石渠。", "何必銀臺號三昧，此中更好味真如。"]'),
('db8e223a-79b6-4eb7-acf6-23487af9a005','次韻和光禄黄少卿學士感恩書事十六韻','楊億','宋','宋诗','song-poetry','','[]','江夏門風盛，東吳族望高。',192,'全唐诗/poet.song.6000.json','["江夏門風盛，東吳族望高。", "才雄吐白鳳，志大釣靈鼇。", "昔日參珠履，多年汎碧桃。", "陳琳巧書檄，謝客占風騷。", "曲宴飛三雅，沈機佐六韜。", "玳筵頻岸幘，楯鼻幾揮毫。", "託乘同歸闕，臨軒别賜袍。", "未離王儉幕，獨得吕虔刀。", "粉署因揚歷，朱門更鬱陶。", "淮南荒桂苑，騎省泣霜毛。", "去國踰千里，爲郎歷幾曹。", "和鉛兼秘府，懸磬寓神臯。", "室靜秋生白，庭閒雨長蒿。", "禁林俄召試，卿寺果垂褒。", "道在心無悶，恩深首重搔。", "依前領圖史，紬繹肯辭勞。"]'),
('3610da77-70c3-409f-b0aa-1830cbeb0d6d','次韻和史館盛學士朝退書懷之什','楊億','宋','宋诗','song-poetry','','[]','金壺待傳點，瑤墀初辨色。',48,'全唐诗/poet.song.6000.json','["金壺待傳點，瑤墀初辨色。", "闢仗開天閽，垂旒操斗極。", "百辟瞻堯眉，九州蒙禹力。", "朝政無闕遺，諫官慚曠職。"]'),
('6ae5f803-0170-4efa-a648-e4cfd695cce3','次韻和盛博士寄贈李四寺丞因以述懷','楊億','宋','宋诗','song-poetry','','[]','錢郎滿腹貯精神，坐上詩成壓倒人。',64,'全唐诗/poet.song.6000.json','["錢郎滿腹貯精神，坐上詩成壓倒人。", "相識只從抛竹馬，留歡長是鱠金鱗。", "西園宴喜期清夜，曲水追隨約暮春。", "不到門墻欲旬浹，已應懸榻滿埃塵。"]'),
('603e82bf-fe76-48d2-8563-739929ec53ac','次韻和盛博士寄贈虞部李郎中之什','楊億','宋','宋诗','song-poetry','','[]','門墻日以峻，德望闇然彰。',72,'全唐诗/poet.song.6000.json','["門墻日以峻，德望闇然彰。", "弟草西垣詔，身爲南省郎。", "塤箎歡並奏，龍虎儼成行。", "宴客牛心炙，朝天雞舌香。", "曲池春漲水，碧瓦曉飛霜。", "此景知何事，留賓汎羽觴。"]'),
('87ac7cac-a3ce-4458-a053-91b237e34185','次韻和守邦道人寄編修諸學士之什','楊億','宋','宋诗','song-poetry','','[]','修書何幸佐鉛黄，日接羣英道自光。',64,'全唐诗/poet.song.6000.json','["修書何幸佐鉛黄，日接羣英道自光。", "署近承明叨謁帝，賦成平樂謬爲郎。", "孟堅已分酬賓戲，嚴助還思佩郡章。", "共憶東林社中客，滿池蓮葉吐清香。"]'),
('750209aa-700e-4b12-b97d-51a3a5084eaa','大名府大安閣主道者','楊億','宋','宋诗','song-poetry','','[]','釋子修行與衆殊，銅臺連接起精廬。',64,'全唐诗/poet.song.6000.json','["釋子修行與衆殊，銅臺連接起精廬。", "羣公共結二林社，萬乘曾迴六尺輿。", "衣惹天香親御座，閣成雲構倚晴虛。", "浮生自恨猶貪禄，未得同翻貝葉書。"]'),
('e4f1b407-8f06-49da-8351-759d81922486','次韻和盛博士寄許州任從事之什','楊億','宋','宋诗','song-poetry','','[]','射策曾攀郄桂枝，從軍猶賦仲宣詩。',64,'全唐诗/poet.song.6000.json','["射策曾攀郄桂枝，從軍猶賦仲宣詩。", "陳琳草檄應非久，貢禹彈冠素有期。", "梁苑勝遊思霰雪，潯陽舊隱廢茅茨。", "初筵樽斝不須戀，正好公車自薦時。"]'),
('03e0f5d0-8511-4daa-b9ac-50a92b1d4498','次韻和盛博士雪霽之什','楊億','宋','宋诗','song-poetry','','[]','六花新霽白皚皚，爽氣颼颼拂面來。',64,'全唐诗/poet.song.6000.json','["六花新霽白皚皚，爽氣颼颼拂面來。", "梁苑酒濃寒力減，謝池風細凍文開。", "天邊幾陣聞歸鴈，江外千家見早梅。", "此際何人能訪戴，剡溪清景好銜杯。"]'),
('d172b295-d6b5-478e-bd27-79bb89017129','次韻和太僕錢少卿寄贈編修主人宋承旨李舍人之什','楊億','宋','宋诗','song-poetry','','[]','春官宗伯魯諸生，翰苑綸闈占大名。',64,'全唐诗/poet.song.6000.json','["春官宗伯魯諸生，翰苑綸闈占大名。", "一代典謨資潤色，滿朝文物仰懸衡。", "分班月殿趨金馬，侍宴天池見石鯨。", "即日雲屏應隔坐，不須東觀待書成。"]'),
('f2d387e2-f74a-4990-bbe5-ef38120ec863','宋殿丞廣南東路轉運','楊億','宋','宋诗','song-poetry','','[]','天子憂南越，公卿薦陸生。',48,'全唐诗/poet.song.6000.json','["天子憂南越，公卿薦陸生。", "九年須富國，萬里便揚旌。", "封部諸蠻接，官曹六尚榮。", "交州何日到，鼓吹定相迎。"]'),
('354cbe59-4a1f-4267-915f-d5a18b2ae38b','次韻和中書李舍人勉元氏道宗奉宗兄弟之什','楊億','宋','宋诗','song-poetry','','[]','二難文彩少人過，落筆尋常只患多。',64,'全唐诗/poet.song.6000.json','["二難文彩少人過，落筆尋常只患多。", "兔苑暫遊衝霰雪，龍門曾上困風波。", "一囊負米猶爲客，百步穿楊待决科。", "更得詞臣贈詩句，機雲入洛擬如何。"]'),
('59bf5d3f-11d2-4323-b99d-e28deb2eee82','送僧之棣州謁王工部','楊億','宋','宋诗','song-poetry','','[]','雪晴河水正流澌，風卷驚蓬滿眼飛。',64,'全唐诗/poet.song.6000.json','["雪晴河水正流澌，風卷驚蓬滿眼飛。", "客路飄飄攜一錫，禪房寂寂掩雙扉。", "曹溪衣鉢何年得，廬阜香燈幾日歸。", "賢守相逢膜拜後，都人爭勸施珠璣。"]'),
('3412b327-1476-476d-990d-8e7c8da09d95','次韻和錢少卿早春對景有懷諸學士','楊億','宋','宋诗','song-poetry','','[]','草樹欣欣暖律迴，謝家池沼凍紋開。',64,'全唐诗/poet.song.6000.json','["草樹欣欣暖律迴，謝家池沼凍紋開。", "晴天獨向高臺望，春色先從上苑來。", "且待郢人歌白雪，莫聽羌笛怨殘梅。", "乞逢休沐便須去，引滿何曾訴玉杯。"]'),
('e25631e9-2442-4e34-a678-00b77d927383','閣門廖舍人知袁州','楊億','宋','宋诗','song-poetry','','[]','駸駸五馬動征塵，太守風流世絕倫。',64,'全唐诗/poet.song.6000.json','["駸駸五馬動征塵，太守風流世絕倫。", "身事漢庭爲小相，家傳楚國是騷人。", "煙波莫歎重湖遠，桑梓仍將别墅鄰。", "麥穗微黄稻苗綠，朱轓入境便行春。"]'),
('541748ba-7b0f-4c40-b1d1-33cbfa27984a','次韻和李舍人拜命書懷寄館殿舊僚之什','楊億','宋','宋诗','song-poetry','','[]','拜命入星垣，偏承聖主恩。',48,'全唐诗/poet.song.6000.json','["拜命入星垣，偏承聖主恩。", "黄扉陪漢相，彩筆代堯言。", "佩玉天顔近，籝金世望喧。", "下僚今隔品，雲路仰高軒。"]'),
('2d841db9-9d96-42a5-bde2-1f8b65e44a23','上元夜會慎大詹西齋分題得歌字','楊億','宋','宋诗','song-poetry','','[]','帝里風光上元節，烏衣舊巷喜經過。',64,'全唐诗/poet.song.6000.json','["帝里風光上元節，烏衣舊巷喜經過。", "樽中酒渌寧辭醉，梁上塵飛只欠歌。", "坐聽禁城傳玉漏，起看河漢轉金波。", "主人愛客春宵永，彩筆題詩奈樂何。"]'),
('43798d82-4626-4b08-b091-663bc1e9458a','次韻和主人喜諸客見過之什','楊億','宋','宋诗','song-poetry','','[]','金鴨噴香繞燭臺，輕雲散盡月光來。',64,'全唐诗/poet.song.6000.json','["金鴨噴香繞燭臺，輕雲散盡月光來。", "三千賓客連宵醉，十二城門徹曉開。", "何幸紫微容託乘，更煩紅袖與傳盃。", "明朝猶自放朝謁，心喜當關不見催。"]'),
('19ba22b6-e064-4bac-bf05-75f78c3a624d','坐中朱博士言今荆南張諫議典襄陽日嘗留意一妓公頗畏內終不得近及移郡荆渚泣别郵亭乃爲歌詞流布巴郢予感其事賡而成詩','楊億','宋','宋诗','song-poetry','','[]','駸駸五馬江陵去，寂寂雙娥漢水頭。',64,'全唐诗/poet.song.6000.json','["駸駸五馬江陵去，寂寂雙娥漢水頭。", "一曲歌終眉黛斂，十分酒盡涙珠流。", "陽春郢客傳新唱，暮雨高堂夢昔遊。", "瓊樹無人敢親近，章臺京兆不勝愁。"]'),
('fe316970-d1a5-4a31-b02e-b9cd92854ff1','次韻和慎詹事述上元宵會之歡寄諸同舍之什','楊億','宋','宋诗','song-poetry','','[]','休沐忻逢上元節，華堂高宴且盤桓。',64,'全唐诗/poet.song.6000.json','["休沐忻逢上元節，華堂高宴且盤桓。", "峨冠屢舞人多醉，刻燭狂吟夜向闌。", "月上珠簾侵坐白，霜飛碧瓦透衣寒。", "銅壺漏徹東方曙，歸騎紛紛未盡歡。"]'),
('f9fe9d4f-780e-4cda-8fe0-8937e92dc138','次韻和李舍人立秋祠太一宫宿齋書事之什','楊億','宋','宋诗','song-poetry','','[]','太乙祠宫肅，齋居薦至誠。',72,'全唐诗/poet.song.6000.json','["太乙祠宫肅，齋居薦至誠。", "已將茅縮酒，應用麵爲牲。", "月映金天朗，風來玉宇清。", "玄談知理勝，蔬食覺身輕。", "仙馭排雲下，空歌遶殿聲。", "仍聞得丹訣，簪紱頓忘情。"]'),
('3f2011bd-40df-4cdd-9454-4c6b7afb83e8','同諸公寄閬州隆靈山王處士','楊億','宋','宋诗','song-poetry','','[]','玄晏先生早著書，聖朝未降輭輪車。',64,'全唐诗/poet.song.6000.json','["玄晏先生早著書，聖朝未降輭輪車。", "滿頭霜雪機心息，三徑蓬蒿俗客疏。", "千首好詩傳輦轂，一枝仙桂耀門閭。", "漢庭得意真知己，應爲清宵誦子虛。"]'),
('d8afba8a-f450-46eb-a0b4-bb67841d3a1e','送僧之大名府謁長城侍郎','楊億','宋','宋诗','song-poetry','','[]','東吳舊寺寄巖隈，駐錫神州久未迴。',64,'全唐诗/poet.song.6000.json','["東吳舊寺寄巖隈，駐錫神州久未迴。", "琴曲誰知流水意，詩篇自占碧雲才。", "廬峰已結白蓮社，鄴下暫尋銅雀臺。", "仙殿主人偏好事，春風鈴閣且徘徊。"]'),
('9dc02594-0798-4f30-b699-8dd14b3f2b04','次韻和李寺丞寄石同院之作','楊億','宋','宋诗','song-poetry','','[]','子雲常在草玄臺，不覺春風滿眼來。',64,'全唐诗/poet.song.6000.json','["子雲常在草玄臺，不覺春風滿眼來。", "聞道後車長載酒，無因曲水共流杯。", "石渠盡日芸籖擁，金谷何時綺席開。", "珍重主人偏愛客，乞逢休沐便追陪。"]'),
('87a606b2-854b-4378-b3a0-89f72ecb05f2','賀太僕錢少卿直秘閣','楊億','宋','宋诗','song-poetry','','[]','幾年宿衛向周廬，頻貢文章白玉除。',96,'全唐诗/poet.song.6000.json','["幾年宿衛向周廬，頻貢文章白玉除。", "纔換月卿歸少列，又來天禄校中書。", "東吳世胄王孫貴，北第門闌太僕居。", "春草題詩欺謝客，上林奏賦慕相如。", "石渠講論應重席，翠輦巡遊且奉車。", "禁籞風光暮春月，彯纓看是綴嚴徐。"]'),
('6ed95d84-8a7d-48d8-a2f5-f314b9c3f8d7','次韻和盛博士喜梅大丞授户部判官','楊億','宋','宋诗','song-poetry','','[]','新來乘傳抵秦川，會府須才果峻遷。',64,'全唐诗/poet.song.6000.json','["新來乘傳抵秦川，會府須才果峻遷。", "應見流錢從地上，特聞聚米向君前。", "聲華南國推高士，名姓丹臺綴列仙。", "每話官曹苦拘束，歸家長是夕陽天。"]'),
('adc9e722-5c7b-4306-accc-b453c99d44e0','次韻和李舍人憶北園尋春之作','楊億','宋','宋诗','song-poetry','','[]','謝公别墅枕城闉，蕭灑都無紫陌塵。',64,'全唐诗/poet.song.6000.json','["謝公别墅枕城闉，蕭灑都無紫陌塵。", "五色絲綸貪草詔，一園桃李阻尋春。", "早朝禁漏猶傳點，下直殘陽已滿身。", "除是禁煙容洗沐，直須偷暇賞芳辰。"]'),
('001941cc-c130-4d77-a187-93e838e8e64b','次韻和閣長李舍人喜薛梁二舍人及予同時拜命之什','楊億','宋','宋诗','song-poetry','','[]','西垣清切本無倫，虛薄將何綴侍臣。',64,'全唐诗/poet.song.6000.json','["西垣清切本無倫，虛薄將何綴侍臣。", "承露盤高雲際曉，棲鷄樹綠省中春。", "言成綸綍終非稱，室藹芝蘭幸得親。", "從此煙霄連步武，宸遊長奉屬車塵。"]'),
('f6e8d6be-376c-4776-b2b5-22193a8023b7','次韻和承旨侍郎宿齋太乙宫之什','楊億','宋','宋诗','song-poetry','','[]','北斗城南太乙祠，羽人多著九霞衣。',64,'全唐诗/poet.song.6000.json','["北斗城南太乙祠，羽人多著九霞衣。", "竹宫肅穆珠旒拜，華表飄颻鶴馭歸。", "遶殿步虛幢影密，登壇酌獻珮聲微。", "質明禮畢還臺去，廐馬翩翩速似飛。"]'),
('e08e35b2-d745-406e-9171-294ed0ba2682','十九哥赴舒州太湖簿仍得假歸鄉','楊億','宋','宋诗','song-poetry','','["\u592a\u6e56"]','初官佐邑少嗟咨，且喜鄉關得告歸。',64,'全唐诗/poet.song.6000.json','["初官佐邑少嗟咨，且喜鄉關得告歸。", "松菊門前三徑在，煙波江上片帆飛。", "枌榆舊社雖堪戀，星火嚴程不可違。", "莫爲棲鸞尚卑屑，悔將錦襖換蓑衣。"]'),
('5756d56e-2197-45df-aede-5edfa5c59845','酬謝光丞四丈見慶新命之什','楊億','宋','宋诗','song-poetry','','[]','武夷歸路苦迢遙，延閣官曹正寂寥。',96,'全唐诗/poet.song.6000.json','["武夷歸路苦迢遙，延閣官曹正寂寥。", "彩鳳銜書俄錫命，黄金刻印便懸腰。", "紫微署近時當制，建禮門深日趁朝。", "咫尺天顔曾賜對，熒煌台座得爲僚。", "鬼神清問憂前席，松柏深情見後凋。", "一曲陽春特相寄，慚將木李報瓊瑤。"]'),
('e494d09b-b6d1-4a8a-823a-a503b8a501a0','信道人歸西京','楊億','宋','宋诗','song-poetry','','[]','寢邱遺業廢多年，衣祴空藏命說篇。',64,'全唐诗/poet.song.6000.json','["寢邱遺業廢多年，衣祴空藏命說篇。", "北闕上書陳祖德，上林結社會時賢。", "風塵不肯留京邑，龍象重歸啟梵筵。", "聞有道安雖未識，定應談論已彌天。"]'),
('8565f735-1773-403b-a846-351aa3c70f9a','邵奉禮歸鄉','楊億','宋','宋诗','song-poetry','','[]','應制曾親白玉除，桐君溪畔是幽居。',64,'全唐诗/poet.song.6000.json','["應制曾親白玉除，桐君溪畔是幽居。", "末登王子洛賓歲，已讀黄香東觀書。", "萬里歸寜承漢詔，三牲供膳奉潘輿。", "水衡得俸誠堪喜，莫便揮金學二疏。"]'),
('595d4102-9373-4a0f-aae7-39fac62ec2f5','史館盛學士以詩相賀因而答之','楊億','宋','宋诗','song-poetry','','[]','前年出守縉雲城，曾枉驪歌慰遠行。',64,'全唐诗/poet.song.6000.json','["前年出守縉雲城，曾枉驪歌慰遠行。", "今日代言青鎖闥，又披郢唱見深情。", "側聆九奏都忘味，連得雙金自滿籝。", "紅藥階前試吟嚼，胸中鄙吝一時平。"]'),
('f43537c9-72c1-4ffc-97d5-e3ae8110f73d','衢州阮比部學士得假歸鄉見過陋止留題詩什因以謝之','楊億','宋','宋诗','song-poetry','','[]','千騎駸駸赴郡初，曾迂旌斾訪吾廬。',64,'全唐诗/poet.song.6000.json','["千騎駸駸赴郡初，曾迂旌斾訪吾廬。", "天邊誰識郎官宿，門外空迴長者車。", "勸酒樽罍應引滿，題詩屋壁是親書。", "鄉人聞有神仙客，遠近爭來看隼旟。"]'),
('ce51c1ec-6c16-4dfc-8cc0-1b1636a8bee8','致仕朱侍郎歸江陵','楊億','宋','宋诗','song-poetry','','[]','二年分直浴堂門，簪筆垂紳奉至尊。',128,'全唐诗/poet.song.6000.json','["二年分直浴堂門，簪筆垂紳奉至尊。", "日過八甎批漢詔，宴開三殿挹堯樽。", "忽聞抗表干君父，切要懸車示子孫。", "碧落改官旌舊德，黄金加賜見深恩。", "羣公祖道爭飛蓋，故吏沾襟亦戀軒。", "定是遼東嘆城郭，肯同彭澤慮田園。", "捧觴莫訴前爲壽，上馬猶能左屬鞬。", "臨别延英對數刻，已應惇史記嘉言。"]'),
('6877cec8-d8f4-4039-8130-18e1a6215cc9','朱侍郎致仕南歸上特錫宴於玉津園仍詔兩制三館並預其會以伸祖送輙賦詩美之','楊億','宋','宋诗','song-poetry','','[]','征輪軋軋出皇都，行路咨嗟賢丈夫。',96,'全唐诗/poet.song.6000.json','["征輪軋軋出皇都，行路咨嗟賢丈夫。", "天子特令供祖帳，國門聊且駐驪駒。", "舊僚送别傾三省，御醴分甘倒百壺。", "下詔已聞推異禮，乞言猶自渴嘉謨。", "馮公不是沉郎署，賀老緣何歸鑑湖。", "明主恩深若爲捨，夢魂應繞博山鑪。"]'),
('72bec266-b16a-4eee-bf5d-41164e60adcd','元道宗弟兄東遊','楊億','宋','宋诗','song-poetry','','[]','王謝江東推世胄，機雲洛下振才名。',96,'全唐诗/poet.song.6000.json','["王謝江東推世胄，機雲洛下振才名。", "忽思油幕從知去，便挈幐囊冐暑行。", "高第自須求甲乙，嘉招未用赴弓旌。", "待看萬里摶羊角，即是三秋聽鹿鳴。", "朝彦賦詩爭送别，藩侯置驛定相迎。", "不知誰啖牛心炙，又見清談一座傾。"]'),
('dbe9f4a7-88ef-46d8-9152-22d67eca05c9','殿院卞侍御赴淮南轉運','楊億','宋','宋诗','song-poetry','','[]','莎庭治行推尤異，梁苑聲華占上流。',96,'全唐诗/poet.song.6000.json','["莎庭治行推尤異，梁苑聲華占上流。", "早是都人避驄馬，近陪計相運牙籌。", "東南轉粟承新命，淮海揚旌到舊遊。", "騎置非時陳密啓，壺漿幾處望行舟。", "黄金刻印大如斗，白簡飛霜凛若秋。", "歲滿功成來會課，多應便拜富人侯。"]'),
('21c2d6c7-270d-44cc-a75f-292346d210b1','省中當直即事書懷兼簡閣長李舍人','楊億','宋','宋诗','song-poetry','','[]','兩掖深沉大帝居，紫微西省掌泥書。',128,'全唐诗/poet.song.6000.json','["兩掖深沉大帝居，紫微西省掌泥書。", "天閽啟鑰趨朝後，侍史焚香起草初。", "五吏援毫才患少，萬錢分膳食無餘。", "鳳池荀令連賓閣，騎省潘郎對直廬。", "煙氣霏霏生屋瓦，雷聲隱隱度宫車。", "滄波滿壁浮蘭橑，修竹當軒蔭綺疏。", "性懶無堪過叔夜，思遲多病似相如。", "繚垣直北銀臺路，拭目看君侍玉除。"]'),
('3dbd6746-8d9d-413c-9b58-cda65bf96b37','中伏日省中當直','楊億','宋','宋诗','song-poetry','','[]','火雲烘爀臨中伏，青鎖深嚴直右曹。',96,'全唐诗/poet.song.6000.json','["火雲烘爀臨中伏，青鎖深嚴直右曹。", "吏散階庭時縱步，詩成几案獨揮毫。", "相烏影轉風微起，仙掌陰斜日漸高。", "何處賜冰和郢酒，誰人割炙動鸞刀。", "紫泥封詔防稽緩，寒水浮瓜散鬱陶。", "丞相憂邊稀出沐，延英三刻豈知勞。"]'),
('5243dfc6-3dad-4a74-b187-7d52675e1934','七夕','楊億','宋','宋诗','song-poetry','','[]','東西燕子伯勞飛，新月如鈎玉露垂。',64,'全唐诗/poet.song.6000.json','["東西燕子伯勞飛，新月如鈎玉露垂。", "河鼓天孫信靈匹，鵲橋星渚有佳期。", "穿針乞巧佇立久，織素成章報答遲。", "定與黄姑享偕老，晉宫休插奈花枝。"]'),
('9731a8e8-717e-499c-812b-70bb3adf114d','胡秘丞知潯州','楊億','宋','宋诗','song-poetry','','[]','蘭臺進秩通閨籍，熊軾臨民奉詔條。',64,'全唐诗/poet.song.6000.json','["蘭臺進秩通閨籍，熊軾臨民奉詔條。", "風俗重尋南越志，鄉關猶隔浙江潮。", "懸知坐嘯謳謠洽，更想行春意氣饒。", "遠宦逢秋少悲吒，潘郎玄鬢恐先凋。"]'),
('794fb863-b6e6-4ba6-bcba-a8e5ec8bae7b','次韻和盛太博寄贈閣長宿齋太乙宫之什','楊億','宋','宋诗','song-poetry','','[]','漢武親祈太乙壇，國朝特祭領祠官。',64,'全唐诗/poet.song.6000.json','["漢武親祈太乙壇，國朝特祭領祠官。", "羽旗搖曳晨曦上，素瑟淒清夜漏寒。", "駕鶴浮丘應暫下，偷桃方朔合留殘。", "齋居數宿徧蔬食，定憶中厨政事餐。"]'),
('bfdd5f6e-2dbe-4c3c-a229-0a30633c71be','次韻和集賢李博士中元日見寄','楊億','宋','宋诗','song-poetry','','[]','鳳池容出沐，蝸舍喜端居。',72,'全唐诗/poet.song.6000.json','["鳳池容出沐，蝸舍喜端居。", "罷草芝泥詔，閑看紫素書。", "曲肱銷永晝，行藥遶前除。", "鬢換二毛近，林凋一葉初。", "香街連甲第，席户望朝車。", "暫别同心友，還嗟會面疏。"]'),
('0cd6f623-9a1c-4051-be62-84be43d3e5d9','次韻奉和知府温尚書送致政朱侍郎十六韻','楊億','宋','宋诗','song-poetry','','[]','拜章納禄便歸休，秘殿親辭十二旒。',256,'全唐诗/poet.song.6000.json','["拜章納禄便歸休，秘殿親辭十二旒。", "閣筆罷批丹鳯尾，拂衣初下六鰲頭。", "非緣荆渚依劉表，定欲箕山訪許由。", "北闕子牟終眷戀，南朝安石本風流。", "明庭顧遇違三接，别墅生涯治一邱。", "身健寧煩策鳩杖，心閑無復夢刀州。", "素風有子堪傳遺，禪論將誰共對酬。", "白璧賜多應尚在，黄金散盡不須留。", "人欽雅譽芝蘭馥，帝憶嘉言水石投。", "祖帳特令開上苑，歸帆那肯待高秋。", "幾程郵驛經濃暑，千里山川見舊遊。", "已是抛官玉堂署，尚思陪宴井幹樓。", "時裁奏牘猶規諫，旋冩丹經自校讎。", "鄉里高門表陰德，國朝惇史紀嘉猷。", "枌榆舊業須重葺，香火前緣莫廢修。", "歲計將何資伏臘，龍陽千樹木奴洲。"]'),
('28b42b83-9bc9-4dee-9df9-347edc379f97','鄭漙赴汀州判官','楊億','宋','宋诗','song-poetry','','[]','家近祝融峰，登科遇至公。',72,'全唐诗/poet.song.6000.json','["家近祝融峰，登科遇至公。", "悲秋雙鬢改，佐幕十年中。", "食蘗心常苦，占蓍命未通。", "甌閩路雖遠，荆楚俗多同。", "投刃應餘地，當樽莫暫空。", "援毫如草檄，又是愈頭風。"]'),
('fa76a1b0-cc42-4435-9935-d80069139007','次韻和宗人安期見賀恩命之什','楊億','宋','宋诗','song-poetry','','[]','分班曉入翔鸞闕，直閣旁連浴鳳池。',64,'全唐诗/poet.song.6000.json','["分班曉入翔鸞闕，直閣旁連浴鳳池。", "彩筆閑批五色詔，好風時動萬年枝。", "勒移鍾阜慚歸晚，稱疾文園恨思遲。", "何事吾宗心倍喜，春塘夢徹寄新詩。"]'),
('5dded49d-8ebe-49c0-b399-a0d6a9198436','早秋','楊億','宋','宋诗','song-poetry','','[]','楚客悲秋至，庭柯一葉凋。',48,'全唐诗/poet.song.6000.json','["楚客悲秋至，庭柯一葉凋。", "鶴天驚曉露，蘭畹怯凉飈。", "團扇流塵暗，單衣爽氣饒。", "江東菰米熟，歸夢隔寒潮。"]'),
('893d617b-d1a9-4646-a26d-9c2e481f172b','義門胡生南歸','楊億','宋','宋诗','song-poetry','','[]','南國烏衣族，東京伯始孫。',48,'全唐诗/poet.song.6000.json','["南國烏衣族，東京伯始孫。", "一枝須折桂，六闕舊旌門。", "歸思鱸魚膾，離筵竹葉樽。", "秋風正搖落，楚客莫銷魂。"]'),
('90b19f54-a44f-4c9f-b5b6-ce6534d84a76','首座昇大師赴西京知教門事','楊億','宋','宋诗','song-poetry','','[]','高論彌天四海聞，久爲龍象主空門。',64,'全唐诗/poet.song.6000.json','["高論彌天四海聞，久爲龍象主空門。", "雪峰傳法稱開士，麟殿談經奉至尊。", "香滿賜衣歸洛社，苔封文室寄梁園。", "梵書貝葉應攜去，齋罷與誰相對翻。"]'),
('ee8da3e6-7343-41f3-8513-7045e33986ca','度支梁諫議請病告以詩寄之','楊億','宋','宋诗','song-poetry','','[]','經旬不謁未央宫，宴坐將誰笑語同。',64,'全唐诗/poet.song.6000.json','["經旬不謁未央宫，宴坐將誰笑語同。", "蜀郡相如非避事，浄名居士欲談空。", "門前賓客窺行馬，篋裏方書拾蠧蟲。", "西省舊僚疏會面，頓驚鄙吝滿胸中。"]'),
('6de3da75-05e0-41e3-8998-31503aa81acc','諸公於石氏東齋宴鄭工部分韻得愁秋浮','楊億','宋','宋诗','song-poetry','','[]','楚客登臨處，離懷重隱憂。',48,'全唐诗/poet.song.6000.json','["楚客登臨處，離懷重隱憂。", "二毛初入髩，一葉早驚秋。", "旅鴈他鄉思，悲笳絕塞愁。", "憑何遣羈緒，菊蘂滿杯浮。"]'),
('ca883f48-12a6-4656-965c-ec86d5414871','次韻和慎大詹中秋待月寄西掖三舍人之什','楊億','宋','宋诗','song-poetry','','[]','涼飈送殘暑，秋色望中新。',48,'全唐诗/poet.song.6000.json','["涼飈送殘暑，秋色望中新。", "天迥迷星斗，宵寒待月輪。", "境同牛渚上，詩寄鳳池人。", "僚友東牀客，冰清合許親。"]'),
('8111d220-5e1a-4fbb-b982-96ffbf381cf3','成都鳳道人遊終南山謁种徵君','楊億','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','何年出蜀訪南宗，深鎖閑房翠蘚重。',64,'全唐诗/poet.song.6000.json','["何年出蜀訪南宗，深鎖閑房翠蘚重。", "振錫忽聞遊地肺，題門兼得謁人龍。", "行吟一路高秋月，投宿斜陽遠寺鍾。", "到日彌天清論罷，徧尋紫閣與圭峰。"]'),
('764cf19a-88db-41b8-9278-9f44ab7da8c1','何大博知晉州','楊億','宋','宋诗','song-poetry','','[]','平明東省發魚書，便擁彤襜出上都。',64,'全唐诗/poet.song.6000.json','["平明東省發魚書，便擁彤襜出上都。", "别酒金英泛籬菊，去程黄葉墮關榆。", "叔孫舊禮妨綿蕝，廉范新歌待袴襦。", "滿腹經綸殊未展，歸來看踐赤墀塗。"]'),
('edd36129-a037-45c6-9d8c-4ff04fb4348a','孫寺丞知考城縣','楊億','宋','宋诗','song-poetry','','[]','早得東堂桂一枝，凌雲詞賦漢皇知。',64,'全唐诗/poet.song.6000.json','["早得東堂桂一枝，凌雲詞賦漢皇知。", "從軍久在紅蓮幕，對策曾臨白玉墀。", "霰雪陪遊應不晚，絃歌爲政莫嫌卑。", "春官宗伯大京兆，喜見門生趨府時。"]'),
('557854d1-f693-47fe-97db-b88486a13658','次韻和閣長修書畢退朝下直寄諸學士之什','楊億','宋','宋诗','song-poetry','','[]','名園甲第接康衢，國典新成下直初。',64,'全唐诗/poet.song.6000.json','["名園甲第接康衢，國典新成下直初。", "庭竹碧鮮吟不足，盤飱方丈食無餘。", "爐中九轉神仙藥，案上百函親故書。", "仍說顔回今飲酒，秋來寧遣宴遊疏。"]'),
('f1262c59-d0db-46d0-9134-1e8ab579a099','威道人歸鄉','楊億','宋','宋诗','song-poetry','','[]','聞法靈山真佛子，馳名南國本詩流。',64,'全唐诗/poet.song.6000.json','["聞法靈山真佛子，馳名南國本詩流。", "二林曾有香燈約，一鉢因爲輦轂遊。", "塵土化衣慵駐錫，江湖收潦憶歸舟。", "何年應制登麟殿，犀柄談空對冕旒。"]'),
('0bd0f1de-08be-4dd2-a9b9-f7af99bf01d7','弟偁歸鄉','楊億','宋','宋诗','song-poetry','','[]','吾家文雅占關西，五十年來桂兩枝。',64,'全唐诗/poet.song.6000.json','["吾家文雅占關西，五十年來桂兩枝。", "突弁後生還可畏，籝金素業未應衰。", "江湖去爲思鱸鱠，霧雨還歸養豹姿。", "摩厲詞鋒莫中輟，驚人專聽一鳴時。"]'),
('2bb98c8c-8e85-47f1-9a82-ea79e77070a8','史館高司諫紳知華州','楊億','宋','宋诗','song-poetry','','["\u534e\u5c71"]','諫署纔聞滿歲遷，分符便見入秦川。',64,'全唐诗/poet.song.6000.json','["諫署纔聞滿歲遷，分符便見入秦川。", "援毫厭賦梁園雪，緩轡閑看華嶽蓮。", "竹簡汗青妨約史，縑囊封皂且論邊。", "三峰洞穴多靈藥，莫便抛官去學仙。"]'),
('75a99ad6-1bab-48c9-b729-f4e46d01b466','送張蜕秀才','楊億','宋','宋诗','song-poetry','','[]','許由流寓因相識，歲歷今移十二辰。',64,'全唐诗/poet.song.6000.json','["許由流寓因相識，歲歷今移十二辰。", "别墅已荒三徑草，素衣猶化九衢塵。", "懸瓢顔巷安貧久，泣玉荆山失意頻。", "莫向明時便招隱，重來須醉杏園春。"]'),
('66f01888-ec3a-42cc-8fe7-81ebb62e3a56','次韻和翰林師學士贈倫上人新居之什','楊億','宋','宋诗','song-poetry','','[]','一逕雨苔深，新居雅稱心。',48,'全唐诗/poet.song.6000.json','["一逕雨苔深，新居雅稱心。", "天花飄晝講，池草伴春吟。", "施食山禽下，題門野客尋。", "此中堪宴坐，何必在雙林。"]'),
('f882e869-7dec-4a03-9949-d9ab933da2d4','李殿丞知廣濟軍','楊億','宋','宋诗','song-poetry','','[]','鈎盾從來司六尚，上林尋見惣三官。',64,'全唐诗/poet.song.6000.json','["鈎盾從來司六尚，上林尋見惣三官。", "頒條忽去憑熊軾，賜對還曾近露盤。", "民瘼乍求應有術，天倫少别不成歡。", "陶朱舊邑無多遠，魏闕歸心且自寛。"]'),
('ae94d715-1b7d-4a1d-97e6-586137e0b180','章頻得解後之陜府謁嚴洪二從事','楊億','宋','宋诗','song-poetry','','[]','春闈猶隔閏，逆旅苦栖遑。',72,'全唐诗/poet.song.6000.json','["春闈猶隔閏，逆旅苦栖遑。", "忽爾遊分陜，飄然出大梁。", "食貧憂桂玉，策蹇冐風霜。", "杏苑歸期近，棠郊去路長。", "幕中逢舊友，歲晚在他鄉。", "鷄黍且相對，休嗟髩髪蒼。"]'),
('cd682560-f65a-4cbb-a8da-d5e030bfb93b','路學士知河中府','楊億','宋','宋诗','song-poetry','','[]','一麾新自海濱還，又佩魚符入故關。',96,'全唐诗/poet.song.6000.json','["一麾新自海濱還，又佩魚符入故關。", "千里山河臨劇郡，九天鴛鷺别通班。", "樓經往聖迴清蹕，路接邊夷獻白環。", "版籍素多田賦錯，干戈初息羽書閒。", "從軍上客彫龍藻，佐酒妖姬墮馬鬟。", "更遣府公吟思發，中條新霽碧孱顔。"]'),
('cd084109-e713-47a9-83b4-e06f8aa94cdd','即席賦得筆送宗人大著通判廣州','楊億','宋','宋诗','song-poetry','','[]','著作蓬山局，職司華衮褒。',48,'全唐诗/poet.song.6000.json','["著作蓬山局，職司華衮褒。", "已能成馬史，何况夢江毫。", "金勁鷄搖距，霜寒兔墮毛。", "歸來批鳳詔，弄翰莫辭勞。"]'),
('7631da8a-7949-49ba-9bdb-fb28196f50b3','職方彭員外惟節知韶州','楊億','宋','宋诗','song-poetry','','[]','仙經舊得還丹訣，郎位高分列宿光。',64,'全唐诗/poet.song.6000.json','["仙經舊得還丹訣，郎位高分列宿光。", "太守雙旌指南越，使君千騎冠東方。", "飲冰清白臨遐俗，晝錦輝榮過故鄉。", "曾是重華張樂地，九韶聞處味應忘。"]'),
('44519bf4-f18d-451b-9062-0389b68c37ec','宗人大著令問通判廣州','楊億','宋','宋诗','song-poetry','','[]','蘭臺大著作，族派共關西。',96,'全唐诗/poet.song.6000.json','["蘭臺大著作，族派共關西。", "南海分憂寄，東門叙解攜。", "離城衝臘雪，宿館聽晨鷄。", "畫鷁江波遠，鳴騶嶺路迷。", "陸梅香已盡，越鳥暖初啼。", "入境風生扇，行春柳拂堤。", "殺青前事在，飲水古人齊。", "卧理應多暇，無忘寄尺題。"]'),
('214d8952-03ae-4cae-af86-92e6482e21df','冬夕與諸公宴集賢梅學士西齋分得今夕何夕探得雲字','楊億','宋','宋诗','song-poetry','','[]','今夕知何夕，良交會以文。',72,'全唐诗/poet.song.6000.json','["今夕知何夕，良交會以文。", "燭花寒旋落，漏滴遠稀聞。", "酒面輕浮蟻，歌喉細遏雲。", "明河光未没，候管氣初分。", "玉笛梅花怨，金爐蕙草焚。", "唯愁曙光發，搔首歎離羣。"]'),
('c3c0d2be-4f78-4753-b191-b2016485f168','鄭工部陜西隨軍轉運','楊億','宋','宋诗','song-poetry','','[]','西鄙欃槍未掃除，營中慷慨請行初。',128,'全唐诗/poet.song.6000.json','["西鄙欃槍未掃除，營中慷慨請行初。", "三軍粒食資心計，一月星郵待捷書。", "宣室喜聞延賈誼，茂陵久歎滯相如。", "謗言盈篋親曾見，反間千金計豈疏。", "遺愛道傍喧竹馬，先聲塞外懾穹廬。", "馮唐莫歎淹郎署，博望還忻擁使車。", "隴右行收萬里地，關中坐致九年儲。", "牙籌羽檄皆吾事，才刃飄飄兩有餘。"]'),
('094466de-6473-4c1a-b22f-5b0355d5013d','黄從事隨軍','楊億','宋','宋诗','song-poetry','','[]','買符來赴調，負羽去從軍。',48,'全唐诗/poet.song.6000.json','["買符來赴調，負羽去從軍。", "五夜聞邊角，三時看陣雲。", "樽前還料敵，楯上更摛文。", "手筆人多許，須銘竇憲勳。"]'),
('037e349f-571d-41b4-a674-eee4e78e25fd','聞李四光丞頻遊北園因有懷寄','楊億','宋','宋诗','song-poetry','','[]','漢相沙堤連甲第，石家金谷有名園。',64,'全唐诗/poet.song.6000.json','["漢相沙堤連甲第，石家金谷有名園。", "雍容陌上臨邛騎，瀲灔齋中北海樽。", "過閏已驚春色早，離城殊少俗塵喧。", "無由一寄南窗傲，相望迢迢西掖垣。"]'),
('c9524cff-6aff-4eee-bda2-e7ad33732e60','次韻和集賢李學士寒食即事之什','楊億','宋','宋诗','song-poetry','','[]','九逵初旭滿輜軿，寒食東風二月天。',64,'全唐诗/poet.song.6000.json','["九逵初旭滿輜軿，寒食東風二月天。", "陌上墊巾誰傲睨，江邊解佩自嬋娟。", "新粧幾處登牆見，沉醉何人藉草眠。", "豪俠追歡殊未足，歸蹄躞蹀夕陽前。"]'),
('acd93db5-510b-425a-8625-257b20446a3c','和集賢李學士千字詩','楊億','宋','宋诗','song-poetry','','[]','千仞谿何險，千倉稻已收。',48,'全唐诗/poet.song.6000.json','["千仞谿何險，千倉稻已收。", "出騎千里馬，醉典千金裘。", "千年河誕聖，千樹橘封侯。", "千鍾不及亂，千錢坐上頭。"]'),
('d463ac70-6d85-455b-a101-cc593e0b2918','妹婿黄補下第歸鄉','楊億','宋','宋诗','song-poetry','','[]','家風早占無雙譽，鄉薦曾居第一流。',64,'全唐诗/poet.song.6000.json','["家風早占無雙譽，鄉薦曾居第一流。", "崑嶺本期争片玉，庖刀誰料失全牛。", "風塵不住梁王苑，煙水還依楚客舟。", "應負男兒四方志，故園歸去莫淹留。"]'),
('eda90135-bdd8-4a3b-b863-3d30b6dfef63','黄覺東遊','楊億','宋','宋诗','song-poetry','','[]','鄉關迢遰數千里，塲屋蹉跎二十年。',64,'全唐诗/poet.song.6000.json','["鄉關迢遰數千里，塲屋蹉跎二十年。", "三獻猶垂卞和泪，幾人先著祖生鞭。", "風塵漫索長安米，禾黍全荒負郭田。", "關外賢豪徧投分，趙囊迴日滿金錢。"]'),
('17b589ef-3d56-4128-8585-743240af72d3','葉生歸縉雲','楊億','宋','宋诗','song-poetry','','[]','出門西望長安笑，抱璞來求善價沽。',64,'全唐诗/poet.song.6000.json','["出門西望長安笑，抱璞來求善價沽。", "惟罄囊裝買羣籍，不持刺字謁當塗。", "鱸魚漸熟思歸切，羊酪初嘗得味無。", "送子東還重銷黯，我曾三載守仙都。"]'),
('3305aba0-1cba-4cdb-a18d-dd172d9f1362','慧初道人歸青州養親','楊億','宋','宋诗','song-poetry','','[]','宴坐禪林度幾秋，忽思歸養指營邱。',64,'全唐诗/poet.song.6000.json','["宴坐禪林度幾秋，忽思歸養指營邱。", "遙知北海孔文舉，應重江南湯惠休。", "畏日流金征路遠，長松偃蓋舊房幽。", "庭闈晨夕供甘外，高論彌天不易酬。"]'),
('cb9f919b-21e5-4a30-8c6e-af86267b3c45','省中當直書懷呈諸同舍','楊億','宋','宋诗','song-poetry','','[]','太微西掖鳳池邊，阿閣凌空瓦起煙。',64,'全唐诗/poet.song.6000.json','["太微西掖鳳池邊，阿閣凌空瓦起煙。", "綵筆時批尺一詔，直廬深在九重天。", "早朝螭陛爐香近，晝寢雞人漏唱傳。", "只恐承明難久戀，長安桂玉苦相煎。"]'),
('0d85e20c-3c3c-42c6-b259-c2ec9949c180','王寺丞借西第避暑因有寄贈','楊億','宋','宋诗','song-poetry','','[]','滕公甲第冠神州，晝日青煙瓦上浮。',64,'全唐诗/poet.song.6000.json','["滕公甲第冠神州，晝日青煙瓦上浮。", "南榭薫風偏解愠，北階萱草更忘憂。", "朝迴門閉人疑病，雨過涼生景似秋。", "角枕閒眠支體適，不知胡蝶是莊周。"]'),
('4deb2d29-c1f7-498f-9369-ffbea848bdcc','元道宗下第東遊','楊億','宋','宋诗','song-poetry','','[]','舉宗文雅孰能陪，須信菰蘆出美才。',64,'全唐诗/poet.song.6000.json','["舉宗文雅孰能陪，須信菰蘆出美才。", "失意不勞悲玉璞，投知應得上金臺。", "曉離村店侵殘月，晝歇津亭避疾雷。", "東道諸侯多重士，融樽處處爲君開。"]'),
('112d62ef-d952-4324-b8ba-4497159d1c66','李四赴歙州','楊億','宋','宋诗','song-poetry','','[]','分直蓬邱未再期，江東去去擁旌麾。',64,'全唐诗/poet.song.6000.json','["分直蓬邱未再期，江東去去擁旌麾。", "名通南省郎官籍，卷續新安郡政詩。", "虎觀清風留汗簡，鴒原高韻憶吹篪。", "故人别後頻南望，想見森森瓊樹枝。"]'),
('865bf864-f57e-4025-ae8e-7af3a83350b3','予以縉雲進士周啟明長書呈秘閣黄少卿黄頗歎重作詩六韻美之因次韻和酬','楊億','宋','宋诗','song-poetry','','[]','縉雲江外郡，封略古甌中。',72,'全唐诗/poet.song.6000.json','["縉雲江外郡，封略古甌中。", "早被唐虞化，已成鄒魯風。", "剖符曾出守，解榻值名公。", "失意嗟塲藿，緘書附塞鴻。", "擲金才少敵，泣玉恨還同。", "後夜蓬山宿，知君必薦雄。"]'),
('e5681e8e-7e82-46cc-887b-28150eacfbe6','史館陳太丞知壽州','楊億','宋','宋诗','song-poetry','','[]','忽佩魚符下玉京，長安廐吏駕車迎。',96,'全唐诗/poet.song.6000.json','["忽佩魚符下玉京，長安廐吏駕車迎。", "淮王舊地餘風物，太史新書見姓名。", "弩矢前驅殊覺貴，河梁執别豈勝情。", "小山叢桂圖經古，白馬驪駒道路榮。", "鵬海三千須擊水，隼旟四十且專城。", "長淮月色秋宵好，應助詩人思轉清。"]'),
('d574faae-e5b4-47a5-b538-649f18246774','錢大夫赴并州','楊億','宋','宋诗','song-poetry','','[]','太原西北勁兵處，地直雲中控定襄。',160,'全唐诗/poet.song.6000.json','["太原西北勁兵處，地直雲中控定襄。", "六月出師平玁狁，九天選將下文昌。", "車魚辟士應難得，詩禮臨戎亦未妨。", "緩急羽書須自草，平安烽火鎮相望。", "柳營禀畏將軍令，毳幕懷來塞下羌。", "清嘯肯饒劉越石，長纓終係左賢王。", "關山萬里邊塵靜，亭館三冬朔雪狂。", "笛怨梅花新度曲，樽傾竹葉淺飛觴。", "禦寒應覺重裘暖，料敵懸憂兩髩蒼。", "只待今年破虜後，徵歸論道坐巖廊。"]'),
('60e2bebf-9e5e-464e-b06e-da33bac063bf','次韻和表弟張湜秋霽之什','楊億','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','輕飈習習起青蘋，宿霧全開霽色新。',64,'全唐诗/poet.song.6000.json','["輕飈習習起青蘋，宿霧全開霽色新。", "高閣晴曦射疏牖，虛堂潤氣徹華茵。", "墊餘巾角曾衝雨，晦盡琴徽旋拂塵。", "楚澤潦收湖水白，歸舟遙憶洞庭人。"]'),
('c3c55548-7cb0-4676-a644-be17ae48c1fe','初秋夜坐','楊億','宋','宋诗','song-poetry','','[]','明河如練出城隅，朱火西流暑氣徂。',64,'全唐诗/poet.song.6000.json','["明河如練出城隅，朱火西流暑氣徂。", "顧兔一輪浮月桂，流螢數點入煙蕪。", "迢迢宫漏傳銀箭，淅淅天風下白榆。", "岸幘微吟自忘寐，披衣閒起遶庭梧。"]'),
('80d64591-42a7-4f9f-a9ad-c3b531d6856f','秋日有懷鄉國','楊億','宋','宋诗','song-poetry','','[]','長安久客逢搖落，不獨悲秋更憶鄉。',64,'全唐诗/poet.song.6000.json','["長安久客逢搖落，不獨悲秋更憶鄉。", "潘岳二毛行欲變，淵明三徑已應荒。", "書裁尺素鴻難托，夢遶重湖蝶自狂。", "遊宦十年歸未得，塵纓却悔濯滄浪。"]'),
('aa5fbe1b-2692-4c0a-b556-3f9e79ac38b8','閣門錢舍人知全州','楊億','宋','宋诗','song-poetry','','[]','家傳吳越賢王後，郡壓瀟湘最上游。',96,'全唐诗/poet.song.6000.json','["家傳吳越賢王後，郡壓瀟湘最上游。", "三殿從來奉宸扆，一麾今去典方州。", "蟬吟高柳隋堤暮，水漲平湖楚澤秋。", "入境壺漿填候館，上官鐃吹夾華輈。", "山川徧歷騷人地，宵旰遐分聖主憂。", "應向桑郊停五馬，青春太守本風流。"]'),
('2c243358-e946-4606-960a-2ded8f583006','次韻和章頻下第書懷之什','楊億','宋','宋诗','song-poetry','','[]','春闈三上敗垂成，白雪新吟思轉清。',64,'全唐诗/poet.song.6000.json','["春闈三上敗垂成，白雪新吟思轉清。", "修竹園中曾獻賦，慈恩塔下未題名。", "禹門燒尾他年事，楚客悲秋此日情。", "道在不須憂晚達，摶風九萬是前程。"]'),
('eeed333b-1b55-49bf-836c-40f6453b37ad','七夕','楊億','宋','宋诗','song-poetry','','[]','金壺漏滴正迢迢，靈匹相從在此宵。',64,'全唐诗/poet.song.6000.json','["金壺漏滴正迢迢，靈匹相從在此宵。", "月魄嬋娟烏遶樹，河流清淺鵲成橋。", "雲輕天上榆花没，風細爐中麝炷飄。", "寂寞堪憐觀渡女，無眠耿耿望青霄。"]'),
('9abe7503-80c3-4a3e-830c-11e8fe052af7','石硯','楊億','宋','宋诗','song-poetry','','[]','磊磊澗中石，成形本一拳。',96,'全唐诗/poet.song.6000.json','["磊磊澗中石，成形本一拳。", "墨池遺號古，筆陣用功偏。", "得在燕臺側，採從崑岫巔。", "剖非藏趙璧，鍊合補媧天。", "偶自他山上，來參絳帳前。", "光榮登玉案，揮灑助花牋。", "注水蟾蜍滴，題詩玳瑁筵。", "如何班定遠，發憤便輕捐。"]'),
('48c62195-bba1-4dc6-bbce-1ac7f2e07342','大理趙寺丞世長知益州華陽縣','楊億','宋','宋诗','song-poetry','','[]','帝選循良撫遠民，由來百里應星辰。',64,'全唐诗/poet.song.6000.json','["帝選循良撫遠民，由來百里應星辰。", "征車蜀道聞猿苦，祖帳西郊落葉頻。", "莫爲割鷄輕邑宰，應須叱馭効忠臣。", "錦城自古繁華地，好與風光作主人。"]'),
('05abfab2-0cd0-4e23-9675-4bc6bd56aaf8','詠醉','楊億','宋','宋诗','song-poetry','','[]','劉伶石五斗，康成三百杯。',48,'全唐诗/poet.song.6000.json','["劉伶石五斗，康成三百杯。", "欹斜星弁側，嵬峨玉山頺。", "人語蜩螗沸，天形帟幕開。", "應知是狂藥，何不學顔回。"]'),
('3ee722a1-71a5-4e68-8093-36b24e7e5877','筆','楊億','宋','宋诗','song-poetry','','[]','月兔湘筠巧製全，何人大手稱如椽。',64,'全唐诗/poet.song.6000.json','["月兔湘筠巧製全，何人大手稱如椽。", "禁中鈴索夜批詔，閣上芸香晝草玄。", "墨妙三分慚入木，華褒一字重編年。", "史官遺直真堪畏，千載獨持生殺權。"]'),
('6bce389c-576a-4641-8e48-37292cc0f12a','夜宴','楊億','宋','宋诗','song-poetry','','[]','華堂高宴卜良宵，賓客當筵半珥貂。',64,'全唐诗/poet.song.6000.json','["華堂高宴卜良宵，賓客當筵半珥貂。", "天轉玉繩星落落，風傳銀箭漏迢迢。", "連浮大白須判醉，促駕鳴騶又趁朝。", "月落烏啼人散後，衣香數日未能銷。"]'),
('c1a4d16e-8b7f-4f87-8490-90e96a298747','張兖下第隨桂陽喬監使之湘中','楊億','宋','宋诗','song-poetry','','[]','建溪曾共聽猿聲，十載文塲未策名。',64,'全唐诗/poet.song.6000.json','["建溪曾共聽猿聲，十載文塲未策名。", "流落只應孤劍在，窮愁已有二毛生。", "荆州暫去依劉表，漢殿無由薦馬卿。", "一路騷人舊山水，登臨且莫動歸情。"]'),
('8ee7409c-6e76-4fba-a0c5-e272603e04c5','庭榴','楊億','宋','宋诗','song-poetry','','[]','得種從西域，移根在帝鄉。',72,'全唐诗/poet.song.6000.json','["得種從西域，移根在帝鄉。", "鮮葩猩染血，美味蔗爲漿。", "入獻殊諸果，敷榮後衆芳。", "丹房高照日，綠葉半凋霜。", "釀酒扶南國，題詩白侍郎。", "濃陰兼茂實，相對度炎涼。"]'),
('3252acc9-8166-4679-bcf1-85a533a5fd91','水部何郎中知鄂州','楊億','宋','宋诗','song-poetry','','[]','褒博衣冠漢大儒，三千奏牘到宸居。',160,'全唐诗/poet.song.6000.json','["褒博衣冠漢大儒，三千奏牘到宸居。", "郎官起草歸華省，女史焚香伴直廬。", "出守新恩龜顧印，趨朝舊路雉隨車。", "便分符竹從鸞掖，應有壺漿待隼旟。", "賜對移時親斧扆，隨行兼兩載圖書。", "淮南落木搖鞭裏，湓浦分風挂席初。", "郡閣平窺漢陽樹，盤飱頻薦武昌魚。", "聚徒南郡傳經盛，攜妓東山退食餘。", "天闕九重懸夢想，江關百戰見坵墟。", "清曹祖德詩人後，時寄新吟一起予。"]'),
('b93e7b0b-f22d-41cb-b014-19c39df44bf5','可久道人之歙州兼簡知郡李學士','楊億','宋','宋诗','song-poetry','','[]','獨攜瓶錫新安去，寒雨西風落葉頻。',128,'全唐诗/poet.song.6000.json','["獨攜瓶錫新安去，寒雨西風落葉頻。", "江水淺深清見底，山程高下險摧輪。", "社中香火延開士，肘後方書濟俗人。", "鄉樹再尋南國路，禪房空鎖帝城塵。", "舊傳心印都忘念，自有衣珠豈患貧。", "四衆仰瞻誰見頂，千家應供定分身。", "宰官多結空門友，外護須依守土臣。", "想到臨川逢內史，翻經相對一嚬伸。"]'),
('ee1b3373-9c44-4bf9-b19c-72dfee479367','大理黄丞宗旦使潁州','楊億','宋','宋诗','song-poetry','','[]','祥刑新佐張廷尉，出塞曾隨霍冠軍。',96,'全唐诗/poet.song.6000.json','["祥刑新佐張廷尉，出塞曾隨霍冠軍。", "露版裁書頻倚馬，甘泉獻賦舊凌雲。", "幾瞻龍衮堯階側，暫駕星軺汝水濆。", "百萬提封周制復，三千奏牘漢皇聞。", "依蓮幕府遊從近，聚米山川向背分。", "迴日受釐宣室對，又應前席動吾君。"]'),
('a421bedd-399b-44fe-b74e-fc6b941d0b69','劉太丞仲宣歸華山','楊億','宋','宋诗','song-poetry','','[]','早年通籍蒼龍闕，近日移家仙掌峰。',96,'全唐诗/poet.song.6000.json','["早年通籍蒼龍闕，近日移家仙掌峰。", "方朔上書殊未報，平津開閣杳難逢。", "騷人章句多懷古，陶令田園且養慵。", "近郭離筵黄葉滿，舊山歸路白雲重。", "洪崖餌术修丹竈，叔夜援琴對酒鍾。", "應待輭輪徵入覲，受釐前席始從容。"]'),
('737801da-047e-448a-a0f4-288f6e270792','表弟章廷評得象知邵武軍歸化縣','楊億','宋','宋诗','song-poetry','','[]','幾年索米住京師，新得東堂桂一枝。',160,'全唐诗/poet.song.6000.json','["幾年索米住京師，新得東堂桂一枝。", "宰邑絃歌循吏政，還鄉鷄黍故人期。", "于公陰德知終大，萬石家風喜不衰。", "毛義動容初捧檄，太邱積德舊刊碑。", "甘棠二紀民猶愛，苦蘗三年吏不欺。", "桑梓經過身晝錦，庭闈扶侍鬢垂絲。", "元方惠化傳遒鐸，令伯歡心獻壽巵。", "邦境中分同魯衛，政聲相應似塤篪。", "嘗思竹馬遊從日，又見風鵬奮擊時。", "執手勉君勤素業，歸來更直鳳凰池。"]'),
('eb1e7937-87fc-4740-9573-89ceee76a207','次韻和李光丞見惠長絛之什','楊億','宋','宋诗','song-poetry','','[]','貂裘已敝洛陽塵，空有陶家漉酒巾。',64,'全唐诗/poet.song.6000.json','["貂裘已敝洛陽塵，空有陶家漉酒巾。", "雙闕金章奉朝請，小齋紗帽養天真。", "久持梵行稱居士，猶掌王言作侍臣。", "惠我長絛識君意，欲教蓮社伴遺民。"]'),
('77e1c62d-5637-4120-99a0-3abc674fa06e','秋雨有懷李寺丞','楊億','宋','宋诗','song-poetry','','[]','潤氣先從柱礎知，寒宵滴滴助秋悲。',64,'全唐诗/poet.song.6000.json','["潤氣先從柱礎知，寒宵滴滴助秋悲。", "桐圭遶樹多黄落，苔錦緣階更碧滋。", "爽徹衾裯慵就枕，涼生牋管欲題詩。", "高陽舊侣相思否，此景誰同把酒巵。"]'),
('6e77ad54-3ca6-40c5-963f-a1eaa4b40d7c','王廷評臻知廬州舒城縣','楊億','宋','宋诗','song-poetry','','[]','潁水生賢自古奇，西遊聲價滿京師。',64,'全唐诗/poet.song.6000.json','["潁水生賢自古奇，西遊聲價滿京師。", "梁園獻賦天將雪，潘縣臨民鬢未絲。", "南浦銷魂分袂處，北堂獻壽捧觴時。", "到官卧治成高趣，終日清談吏不欺。"]'),
('e02937a4-697f-43ca-8bba-9d99058be91c','大理徐寺丞元榆知越州諸暨縣','楊億','宋','宋诗','song-poetry','','[]','子山詞賦動南朝，近佐名卿掌玉條。',96,'全唐诗/poet.song.6000.json','["子山詞賦動南朝，近佐名卿掌玉條。", "治邑還持麈尾柄，攜家便汎木蘭橈。", "謝塘春晝偏多思，潘鬢秋風苦未凋。", "種秫公田供酩酊，彈琴官舍助逍遙。", "去程千里隨賓鴈，宿館三更聽落潮。", "聞道臨安有仙穴，莫抛印綬採芝苗。"]'),
('de48be9f-b31c-4402-abe7-790f0af44da1','次韻和錢崇班見寄之什','楊億','宋','宋诗','song-poetry','','[]','蘋末風輕不動塵，承明朝罷見閒身。',64,'全唐诗/poet.song.6000.json','["蘋末風輕不動塵，承明朝罷見閒身。", "從容退食收芝檢，迢遰驅車訪玉人。", "酒貰十千那惜醉，丹封六一已應真。", "春塘麗句偏相寄，傳誦朝來滿縉紳。"]'),
('775376ca-87cc-45f3-93fd-44534b17b70c','次韻和錢崇班再寄之什','楊億','宋','宋诗','song-poetry','','[]','祖禰勤王國史褒，傳家自有吕虔刀。',64,'全唐诗/poet.song.6000.json','["祖禰勤王國史褒，傳家自有吕虔刀。", "雄豪結客欺燕俠，憀慄悲秋笑楚騷。", "奕世勳名金鉞貴，出羣風格玉山高。", "詩中敏手兼無敵，射落霜鵰釣得鼇。"]'),
('c2397bc9-0a5d-4fbc-8898-aa58f25a24ee','盛京宰單州武成縣','楊億','宋','宋诗','song-poetry','','[]','子男印綬諸侯秩，鄒魯閭閻太古風。',64,'全唐诗/poet.song.6000.json','["子男印綬諸侯秩，鄒魯閭閻太古風。", "兔苑勝遊抛霰雪，琴臺善政繼絲桐。", "征途朔吹貂裘暖，祖席清歌蟻酒空。", "令弟嚴君俱應宿，時瞻懸象向南宫。"]'),
('eb738a58-d828-474a-9a5b-ed53d1e2142a','次韻和并州錢大夫夕次豐州道中見寄','楊億','宋','宋诗','song-poetry','','[]','漢將從天下，胡兵值月殘。',48,'全唐诗/poet.song.6000.json','["漢將從天下，胡兵值月殘。", "孤煙戍樓逈，密雪戰袍乾。", "向暮三吹角，臨風一據鞍。", "邊城賴經略，重取地圖看。"]'),
('6d49dd14-017f-4751-8238-44f6ed91aedb','董温其赴淮南幕','楊億','宋','宋诗','song-poetry','','[]','歲晏梁園密雪飛，出關猶憶弃繻時。',64,'全唐诗/poet.song.6000.json','["歲晏梁園密雪飛，出關猶憶弃繻時。", "屬鞬正是從軍樂，插羽那憂草檄遲。", "陪宴初筵揮玉柄，從遊别墅騁金羈。", "只應偏啖牛心炙，自此聲名漢殿知。"]'),
('eeca985f-1ffc-45b8-a4ea-4d32ed0c3474','史館凌職方知廣州','楊億','宋','宋诗','song-poetry','','[]','番禺出守重，漢殿拜恩初。',120,'全唐诗/poet.song.6000.json','["番禺出守重，漢殿拜恩初。", "華省郎官宿，名山太史書。", "剖符從瑣闥，持節上軺車。", "左顧金龜印，前驅畫隼旟。", "由來百粤地，曾督九年儲。", "卉服要荒外，棠陰惠愛餘。", "齎裝天子賜，封部島夷居。", "羽檄招溪洞，壺漿慰里閭。", "國風今已變，民瘼到應除。", "江海思歸否，蓬山有直廬。"]'),
('d8d69ea1-530b-49bd-a34a-8d0d4c0dab0e','十二月四日大雪就賜近臣宴飲即事','楊億','宋','宋诗','song-poetry','','[]','向夕同雲布海涯，豐年呈瑞在京華。',64,'全唐诗/poet.song.6000.json','["向夕同雲布海涯，豐年呈瑞在京華。", "相如賦就梁王苑，穆滿歌傳阿母家。", "農畝三冬偏積潤，朝衣六出旋成花。", "天恩錫宴醉歸處，幾里香街覆玉沙。"]'),
('aeb8e803-5c98-4ea8-85ff-6f938f6a738f','章琮赴廣州東莞簿','楊億','宋','宋诗','song-poetry','','[]','抱璞曾三獻，悲秋忽二毛。',48,'全唐诗/poet.song.6000.json','["抱璞曾三獻，悲秋忽二毛。", "十年嗟不調，一命尚徒勞。", "互市通蠻貨，公田入海濤。", "貪泉雖酌飲，未肯染脂膏。"]'),
('fc4e88c0-e553-4e4f-adf4-ab46bc61122f','文慧大師歸蜀','楊億','宋','宋诗','song-poetry','','[]','南宗傳法了，漢殿賜衣新。',48,'全唐诗/poet.song.6000.json','["南宗傳法了，漢殿賜衣新。", "歸路峨眉雪，舊房京洛塵。", "天花飄講席，海月照吟身。", "誰結香燈社，金門貴近臣。"]'),
('5a31eb0a-0164-4da4-88ad-9ff48523e290','王中庸赴河南鞏縣尉','楊億','宋','宋诗','song-poetry','','[]','春風祖席引香醪，白馬驪駒草色袍。',64,'全唐诗/poet.song.6000.json','["春風祖席引香醪，白馬驪駒草色袍。", "官舍前臨兩京道，居民半雜五陵豪。", "卑飛碌碌猶棲棘，餘地飄飄暫鼓刀。", "捧檄初同昔人喜，不應搔首歎徒勞。"]'),
('7ad7da40-4a05-4ce6-9d6f-866c6592be46','比部朱員外知東明縣','楊億','宋','宋诗','song-poetry','','[]','宰邑承顔帝澤優，春郊數舍躍驊騮。',96,'全唐诗/poet.song.6000.json','["宰邑承顔帝澤優，春郊數舍躍驊騮。", "絃歌平昔有遺愛，桑梓依前訪舊遊。", "鄉里歸時榮晝錦，庭闈到日潔晨羞。", "陶潜未省荒三逕，班嗣何因樂一邱。", "蘭長謝庭傳賦詠，花開潘縣占風流。", "薫爐綾被餘香馥，省闥沉沉侍史愁。"]'),
('0356bd9e-03e7-4974-87bc-70778704d6a8','咸平六年二月十八日扈從宸遊因成紀事二十二韻','楊億','宋','宋诗','song-poetry','','[]','步輦下明光，鳴鞘出未央。',264,'全唐诗/poet.song.6000.json','["步輦下明光，鳴鞘出未央。", "屬車多載酒，夾道競焚香。", "雲管飄梅吹，蜺旌錯鳥章。", "從臣沙苑馬，衛士羽林槍。", "玉輅天行健，金壺晝漏長。", "光風汎蘭蕙，仙霧拂旂常。", "宿雨收林薄，晨曦艷屋梁。", "閭閻空里巷，旄罕隘康莊。", "託乘奉珍使，先驅執戟郎。", "從橋初轉轂，憑軾見垂裳。", "暫駐時龍馭，前臨戲馬塲。", "由來講武事，所以服遐荒。", "電影流機石，鵶羣發大黄。", "千鈞寧覺重，七札豈曾妨。", "卒勇如虓虎，人觀若堵墻。", "腰鞬晉元帥，扈蹕漢諸王。", "聊用誇胡客，還聞讋鬼方。", "迴輿百里囿，錫宴九霞觴。", "射以騶虞節，歌爲白雪倡。", "仙山鯨海上，御苑斗城旁。", "周鎬歡麀鹿，虞韶集鳳凰。", "瑤池春水渌，猶誤濯滄浪。"]'),
('1cd6b8ce-6ba2-4ed8-a185-81a433e9a80a','僕射李相公宅觀花燭','楊億','宋','宋诗','song-poetry','','[]','孫閣相君和鼎貴，秦樓愛婿坦牀賢。',64,'全唐诗/poet.song.6000.json','["孫閣相君和鼎貴，秦樓愛婿坦牀賢。", "東方千騎還居上，南極三星正在天。", "路入桃源花爛漫，橋横銀漢水漪漣。", "乘龍擇對真無比，月桂宫中第一仙。"]'),
('914184a8-cca7-48ef-aa99-e4c949bd239b','竇詠從淮陽軍','楊億','宋','宋诗','song-poetry','','[]','名題仙籍廣寒宫，負羽從軍意氣雄。',64,'全唐诗/poet.song.6000.json','["名題仙籍廣寒宫，負羽從軍意氣雄。", "萬石世家標國史，孔璋書檄愈頭風。", "狂翻竹箭春波急，滿酌榴花别酒空。", "腰佩吳鈎衣楚製，柳堤千里躍青驄。"]'),
('63650b84-b50e-46fb-9440-ebdb2b7de99f','廉上人歸天台','楊億','宋','宋诗','song-poetry','','[]','舊住赤城華頂峰，桂巖芝崦白雲重。',64,'全唐诗/poet.song.6000.json','["舊住赤城華頂峰，桂巖芝崦白雲重。", "彌天曾共習鑿齒，入洛因尋陸士龍。", "寒燭伴吟經臘雪，雨花開講過晨鐘。", "浮漚一念歸心起，本寺房前見偃松。"]'),
('b3d38cdf-fb82-47f8-a7ed-a1f7a4cd576c','次韻和李寺丞見寄之什','楊億','宋','宋诗','song-poetry','','[]','雲章承詔祝高穹，夜聽空歌宿綘宫。',64,'全唐诗/poet.song.6000.json','["雲章承詔祝高穹，夜聽空歌宿綘宫。", "正怯龜腸終日內，忽傳雁信五城中。", "八珍伊鼎鹽梅味，九夏堯厨萐莆風。", "苦恨齋居方慎獨，朵頤大嚼與誰同。"]'),
('740234da-24ee-42e4-816f-5a2dfcec9cd6','次韻和右巡李端公見寄之什','楊億','宋','宋诗','song-poetry','','[]','首夏修時祭，齋居貴洗心。',72,'全唐诗/poet.song.6000.json','["首夏修時祭，齋居貴洗心。", "神光浮漢畤，薰吹發虞琴。", "偃樹枝成蓋，豐碑字有金。", "秘文窺寶籙，榮路厭朝簪。", "捉麈思嘉話，烹魚得好音。", "迴瞻柏臺署，佳氣九門深。"]'),
('edc303b2-81e4-4670-a46a-3a601e72ece6','大理黄丞宗旦通判潁州','楊億','宋','宋诗','song-poetry','','[]','曾隨征虜出蕭關，又案公田汝水灣。',64,'全唐诗/poet.song.6000.json','["曾隨征虜出蕭關，又案公田汝水灣。", "南畝萬箱增地利，西清三刻對天顔。", "一麾通守彤襜貴，九棘評刑赤筆閑。", "閭里歡迎舊從事，隨車雨氣自應還。"]'),
('19f83134-d191-4a04-b7fc-afaf2a0bd4d1','陳小著從易知邵武軍','楊億','宋','宋诗','song-poetry','','[]','奏牘金門奉帝俞，平明鸞省剖銅符。',64,'全唐诗/poet.song.6000.json','["奏牘金門奉帝俞，平明鸞省剖銅符。", "北堂送喜應占鵲，南國思歸不爲鱸。", "歲月天涯鄉樹老，煙波江上客帆孤。", "會稽友婿堪羞死，邑令今來負弩驅。"]'),
('736e934b-07e3-4cf7-b218-3d62ea72c07e','譯經惣持大師致宗之泗上禮塔','楊億','宋','宋诗','song-poetry','','[]','早傳心印得衣珠，不學聲聞證有餘。',64,'全唐诗/poet.song.6000.json','["早傳心印得衣珠，不學聲聞證有餘。", "犀柄屢登三殿講，琅函新譯五天書。", "蓮華塔下焚香去，竹箭波間解纜初。", "隨順世緣無所住，經行宴坐自如如。"]'),
('119f425c-1d41-4e6f-90e7-1168a385df63','歐陽使者監和州軍','楊億','宋','宋诗','song-poetry','','[]','新剖牙璋出護軍，使車歸養指江濆。',64,'全唐诗/poet.song.6000.json','["新剖牙璋出護軍，使車歸養指江濆。", "綵衣楚國老萊子，白首長安萬石君。", "虎眼波狂征棹急，鱸魚鱠美壽杯醺。", "東南極目無氛祲，不假横戈看陣雲。"]'),
('44388c5d-336b-495c-ae5a-e3ba712a2e3e','胡小著克順知泉州惠安縣兼過南昌别墅','楊億','宋','宋诗','song-poetry','','[]','平明束簡下蘭臺，海縣鳴琴亦滯才。',64,'全唐诗/poet.song.6000.json','["平明束簡下蘭臺，海縣鳴琴亦滯才。", "厭說風塵住京洛，貪看雪浪架蓬萊。", "楚江歸思鱸魚鱠，隨岸離筵竹葉杯。", "通德舊居旌闕在，遼東鶴馭少徘徊。"]'),
('e300c573-22e5-4238-a809-b9cbaf72bb43','內當','楊億','宋','宋诗','song-poetry','','[]','芝泥初熟詔書成，紅藥翻階晝景清。',32,'全唐诗/poet.song.6000.json','["芝泥初熟詔書成，紅藥翻階晝景清。", "屋瓦生煙宫漏永，時聞幽鳥自呼名。"]'),
('db9f685d-27af-4ae2-99f3-ba7196357e04','讀史學白體','楊億','宋','宋诗','song-poetry','','[]','易牙昔日曾蒸子，翁叔當年亦殺兒。',32,'全唐诗/poet.song.6000.json','["易牙昔日曾蒸子，翁叔當年亦殺兒。", "史筆是非空自許，世情真僞復誰知。"]'),
('76bdce3c-47f9-4026-913a-e76eeb694dfd','閨思','楊億','宋','宋诗','song-poetry','','[]','征夫萬里戍交河，塞外蕭條朔氣多。',32,'全唐诗/poet.song.6000.json','["征夫萬里戍交河，塞外蕭條朔氣多。", "古壁暗蛩催夜織，朝來一葉下庭柯。"]'),
('8a87c5c3-046d-47f7-aa5f-dd0546ca02b6','李御史','楊億','宋','宋诗','song-poetry','','[]','清曉乘驄出九逵，內朝簪筆坐前墀。',32,'全唐诗/poet.song.6000.json','["清曉乘驄出九逵，內朝簪筆坐前墀。", "天家御史非凡格，曾向崐崘服衆芝。"]'),
('d8037eb2-298f-48af-9899-f7cf3e0937fd','王殿丞舉通判桂州','楊億','宋','宋诗','song-poetry','','[]','科名得玉向崑邱，家世長淮入海流。',64,'全唐诗/poet.song.6000.json','["科名得玉向崑邱，家世長淮入海流。", "通籍殿中鈎盾省，頒條嶺外桂林州。", "漢皇前席期清夜，楚客歸帆指素秋。", "父老歡聞鄰郡政，壺漿千里待鳴騶。"]'),
('6fddf207-3a4a-4387-ad87-19c8e95b297a','大名温尚書之任','楊億','宋','宋诗','song-poetry','','[]','窣雲樓堞古銅臺，幕府池塘菡蓞開。',64,'全唐诗/poet.song.6000.json','["窣雲樓堞古銅臺，幕府池塘菡蓞開。", "畢萬山河千里迥，亞夫鐘鼓九天來。", "屬鞬前隊射鵰手，載筆初筵倚馬才。", "命將文昌非細事，星光昨夜動昭回。"]'),
('4c0badc5-971f-40f2-94c5-a3029404c8de','喜賀梁三入翰林','楊億','宋','宋诗','song-poetry','','[]','六鼇雲海冠蓬萊，玉署深嚴枕斗魁。',64,'全唐诗/poet.song.6000.json','["六鼇雲海冠蓬萊，玉署深嚴枕斗魁。", "漢殿論兵得頗牧，梁園作賦掩鄒枚。", "趨朝御案香盈袖，侍宴仙莖露滿杯。", "五色天書看視草，懸知獨有長卿才。"]'),
('8ceaf658-7bdc-406b-a5f5-614c267b07bd','次韻和昭侯立秋見寄','楊億','宋','宋诗','song-poetry','','[]','雲峰半歛火西流，桃簟微涼忽報秋。',64,'全唐诗/poet.song.6000.json','["雲峰半歛火西流，桃簟微涼忽報秋。", "飲露吸風齊女怨，登山臨水楚人愁。", "珠喉倚瑟華堂暮，桂燼薫衣别院幽。", "美疢已平休沐近，會應投轄一相留。"]'),
('5e082d92-7f76-454b-96cf-9c566c4b0e93','弟伋歸寧','楊億','宋','宋诗','song-poetry','','[]','一夕西風木葉飛，長安久客念庭闈。',64,'全唐诗/poet.song.6000.json','["一夕西風木葉飛，長安久客念庭闈。", "去隨塞鴈銜蘆遠，歸值家鷄啄黍肥。", "負郭生涯同季子，澄江詩景屬玄暉。", "帝城紫陌多塵土，免化輕雲白紵衣。"]'),
('4437b4df-681b-471f-8103-5efa5d9fc8f2','景陽諫議赴餘杭','楊億','宋','宋诗','song-poetry','','[]','浙水東西兩節旄，君今於此握戎韜。',64,'全唐诗/poet.song.6000.json','["浙水東西兩節旄，君今於此握戎韜。", "油囊仙姥流霞酒，鰌穴靈胥白鷺濤。", "盤石起家傳典訓，翹車開幕聘英髦。", "子牟江海終非久，剩鱠鱸魚把蟹螯。"]'),
('8ead4347-45d6-4eca-bcdd-85fbee010380','杭州嚴從事','楊億','宋','宋诗','song-poetry','','[]','柳岸蘭橈片席飛，秋風澤國季鷹歸。',64,'全唐诗/poet.song.6000.json','["柳岸蘭橈片席飛，秋風澤國季鷹歸。", "幕中蓮渚紅衣脱，江外蓴羮紫線肥。", "十部須知從事貴，雙魚莫遣尺書稀。", "西陵正接家山路，試爲因人問釣磯。"]'),
('909bfb90-9518-411a-a887-e420ab1bf5c1','鄱陽皮錄事','楊億','宋','宋诗','song-poetry','','[]','松陵遺集占風騷，故國田園沒海濤。',64,'全唐诗/poet.song.6000.json','["松陵遺集占風騷，故國田園沒海濤。", "三世青氈傳舊物，十年黄綬歎徒勞。", "謝塘春草侵魂夢，潘縣秋霜入鬢毛。", "鄱水黄金漫如粟，想君終不染脂膏。"]'),
('f6d88c3f-5277-4f6c-a5c6-a41bb977ff06','史館楊嵎學士以詩話及空門之事次韻和之','楊億','宋','宋诗','song-poetry','','[]','雙樹金言付囑頻，閻浮外護託王臣。',32,'全唐诗/poet.song.6000.json','["雙樹金言付囑頻，閻浮外護託王臣。", "誰知天禄草玄客，曾是靈山受記人。"]'),
('e9c37767-d68a-45ca-8371-917f454f3966','諸暨簿張慈','楊億','宋','宋诗','song-poetry','','[]','新官佐邑近閩禺，令伯歡心就養初。',64,'全唐诗/poet.song.6000.json','["新官佐邑近閩禺，令伯歡心就養初。", "暫住梁園慵獻賦，因經禹穴更探書。", "忘機海國親鷗鳥，寄信京華託鯉魚。", "迴日殺青兼兩載，想君清俸亦無餘。"]'),
('d06e9b58-9860-4d09-82d8-0c478a441629','次韻和昭收寄銀臺李舍人之什','楊億','宋','宋诗','song-poetry','','[]','柱下方書掌事機，深嚴侍從接論思。',64,'全唐诗/poet.song.6000.json','["柱下方書掌事機，深嚴侍從接論思。", "歸鞍通德香街迥，前席延英晝漏遲。", "菊徑頓疏陶靖節，月樓偏憶庾元規。", "華堂宴集應難去，玉斝醇醪滿勸誰。"]'),
('c3b0bc69-673c-419f-b7ff-81a5ad254e0b','送吳航','楊億','宋','宋诗','song-poetry','','[]','井臼荒涼旅鬢班，經年索米住長安。',64,'全唐诗/poet.song.6000.json','["井臼荒涼旅鬢班，經年索米住長安。", "囊中賣賦金都盡，衣上悲秋泪不乾。", "客路飄蓬殊未定，侯門置醴豈成歡。", "擔簦忽起東遊興，庭樹西風昨夜寒。"]'),
('d2be916f-03a2-4b35-964a-022289b2ce3e','并州王諫議','楊億','宋','宋诗','song-poetry','','[]','鎖闈聊輟皂囊封，晝錦還鄉意氣雄。',64,'全唐诗/poet.song.6000.json','["鎖闈聊輟皂囊封，晝錦還鄉意氣雄。", "别墅揮金延父老，近郊騎竹見兒童。", "蒲盧善化終成政，蟋蟀深思未變風。", "更待出師平黠虜，戎衣獻捷大明宫。"]'),
('08804965-0876-4ff1-89c5-fbc41fa12635','奉和翰林諸公賀閣長李公領銀臺之什','楊億','宋','宋诗','song-poetry','','[]','西漢公車主上章，官曹秘邃接明光。',64,'全唐诗/poet.song.6000.json','["西漢公車主上章，官曹秘邃接明光。", "天書時草鳳凰詔，邊奏親開赤白囊。", "咫尺青規頻借筯，離披金蘂阻飛觴。", "瀛洲仙侣相期處，銅馬門中白玉堂。"]'),
('43831e28-90db-4358-b77e-4c3dadd2890a','姚起居赴兩浙轉運','楊億','宋','宋诗','song-poetry','','[]','吳會商功利，蓬丘輟史臣。',96,'全唐诗/poet.song.6000.json','["吳會商功利，蓬丘輟史臣。", "同僚供祖帳，屬郡望行塵。", "富國催流馬，編年廢獲麟。", "櫜鞬二千石，襦袴幾州人。", "名姓丹臺籍，封疆析木津。", "片言空犴獄，密啟到鈎陳。", "且運方船粟，初嘗千里蓴。", "江山助詩思，新詠掩汀蘋。"]'),
('17742331-2ccf-4e78-9f2c-8ba562e2555f','集賢劉工部隲知衡州','楊億','宋','宋诗','song-poetry','','[]','仁里古湘川，頒條命雋賢。',96,'全唐诗/poet.song.6000.json','["仁里古湘川，頒條命雋賢。", "腰垂丈二組，身下九重天。", "山水登臨思，庭闈喜懼年。", "官曹郎位宿，衣袂御爐煙。", "記事成新史，賡歌有雅篇。", "爲貪驅弩矢，不從汎樓船。", "治道山陰卒，離羣藏室仙。", "衡陽無過鴈，尺素若爲傳。"]'),
('bc5586f9-23ed-4e5c-b63d-f24146b37cae','魏奉禮昭文知吉州龍泉縣','楊億','宋','宋诗','song-poetry','','[]','平昔登龍坂，因緣識玉人。',96,'全唐诗/poet.song.6000.json','["平昔登龍坂，因緣識玉人。", "庭中華轂滿，膝下綵衣新。", "少列悲先露，高堂泣累茵。", "嘉賓碣館閉，遺業寢邱貧。", "弓冶傳家久，絃歌宰邑頻。", "循良同漢吏，惠愛及齊民。", "又出夷門去，還臨灨水濱。", "不須輕百里，自古應星辰。"]'),
('97a82f3d-982e-4b9f-a0f9-e05b2122dc4b','作坊魏使知隰州','楊億','宋','宋诗','song-poetry','','[]','幾年供奉宣徽殿，一旦腰懸刺史魚。',64,'全唐诗/poet.song.6000.json','["幾年供奉宣徽殿，一旦腰懸刺史魚。", "戚里園林甲京洛，將壇家世閲詩書。", "離筵惜别空銀榼，官舍思歸夢玉除。", "四十專城誰不羡，驂驔千騎擁干旟。"]'),
('00078a11-d2f1-487a-b336-5d5c019ecc0a','司農欒少卿知洪州','楊億','宋','宋诗','song-poetry','','[]','大農搜粟漢名卿，千里江西擁斾旌。',64,'全唐诗/poet.song.6000.json','["大農搜粟漢名卿，千里江西擁斾旌。", "腰下金龜三品綬，手中銅虎八州兵。", "屬鞬牧伯趨庭見，騎竹兒童塞路迎。", "洪井主人今重士，肯教懸榻有塵生。"]'),
('61a401cc-e68b-4b6b-b2c5-0e6ea7b4cffb','送邵梁秀才','楊億','宋','宋诗','song-poetry','','[]','君家罨畫溪，歲晚忽思歸。',48,'全唐诗/poet.song.6000.json','["君家罨畫溪，歲晚忽思歸。", "密雪不獻賦，流塵空化衣。", "購書藏屋壁，温席奉庭闈。", "清世莫招隱，垂天待一飛。"]'),
('cb9bc52e-ed96-4917-996f-55e85afa6f3b','酬秘閣黄少卿因見所作洞霄宫碑且有題記','楊億','宋','宋诗','song-poetry','','[]','譙郡增嚴李母祠，神龜矯首負金碑。',64,'全唐诗/poet.song.6000.json','["譙郡增嚴李母祠，神龜矯首負金碑。", "豆萁已乏不休思，韲臼兼無絕妙辭。", "翠琰雄文慚內史，黄庭美翰枉羲之。", "蓬丘麗句偏相許，勝得山龍衮服披。"]'),
('162866db-15e1-4b60-916b-7dd3defa750b','弟僓歸鄉','楊億','宋','宋诗','song-poetry','','[]','客兒詩思掩春塘，杖策來觀上國光。',64,'全唐诗/poet.song.6000.json','["客兒詩思掩春塘，杖策來觀上國光。", "舉白萬錢酤酒飲，殺青千卷買書藏。", "梁園綠篠將欹雪，楚岸蒼葭已變霜。", "躍馬還家那隔歲，預應乾鵲報高堂。"]'),
('b62c26be-d2cb-47dd-ac5f-f0f45c61bc1c','弟伸歸鄉','楊億','宋','宋诗','song-poetry','','[]','澤國思歸詠采蘭，束書攜劍出長安。',64,'全唐诗/poet.song.6000.json','["澤國思歸詠采蘭，束書攜劍出長安。", "天涯朝暮倚門望，歲晏風霜行路難。", "閩嶺夕嵐鄉樹老，楚江寒浪客衣單。", "巖前舊勒移文處，到日重須拂蘚看。"]'),
('90ec3a45-d7c6-4159-831a-96f906426dc3','王尚食知鳳翔','楊億','宋','宋诗','song-poetry','','[]','露冕分憂輟近班，朝陽鳴鳳古岐山。',64,'全唐诗/poet.song.6000.json','["露冕分憂輟近班，朝陽鳴鳳古岐山。", "三刀吉夢頻爲郡，駟馬高車又出關。", "宴客羽觴那有筭，題詩綵筆莫教閒。", "將壇義府平生事，早立邊功振凱還。"]'),
('031570ea-6f6b-4712-9f24-dc7a2b05976c','福州古田宰李堪','楊億','宋','宋诗','song-poetry','','[]','由來百里應華星，何况牛刀乍發硎。',64,'全唐诗/poet.song.6000.json','["由來百里應華星，何况牛刀乍發硎。", "五柳不須輕印綬，七閩聊且訪圖經。", "雪天暢飲連浮白，海縣抄書剩殺青。", "公暇好裁封禪頌，聖皇將欲駕云亭。"]'),
('252f50fe-e29f-4b71-a714-1742a76797b4','黄旦宰江州德化縣','楊億','宋','宋诗','song-poetry','','[]','外臺論薦達乘輿，花縣絃歌製錦初。',64,'全唐诗/poet.song.6000.json','["外臺論薦達乘輿，花縣絃歌製錦初。", "氣直公車曾諫獵，政清官舍舊懸魚。", "二林重結遺民社，五柳閒尋靖節居。", "好繼謫仙留絕唱，雲屏九叠倚晴虛。"]'),
('74625cca-ac69-409c-b32e-a6a151e16cef','贈文照大師','楊億','宋','宋诗','song-poetry','','[]','讀徧龍宫七佛書，一塵無念得衣珠。',64,'全唐诗/poet.song.6000.json','["讀徧龍宫七佛書，一塵無念得衣珠。", "金園講席天花滿，沙界禪心水月孤。", "擁衲夜霜凝屋瓦，閉關春雨長庭蕪。", "公卿半是空門友，瓶錫因循寄上都。"]'),
('86ccf8df-c107-4891-b30e-45d1dd0e0541','慎大詹以吳柑見貺','楊億','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','龍陽休說木奴洲，震澤黄柑占上流。',64,'全唐诗/poet.song.6000.json','["龍陽休說木奴洲，震澤黄柑占上流。", "承露玉漿仙掌曙，亞霜金顆洞庭秋。", "香黏素手吳娃麗，冷滌朝酲楚客愁。", "應似荔支催入貢，隨河飛鳥逐鳴騶。"]'),
('4e4605aa-ba24-4d1e-8235-3be8b8087ed9','秘閣舒職方知舒州','楊億','宋','宋诗','song-poetry','','[]','西崑册府控千廬，鈆筆多年校魯魚。',64,'全唐诗/poet.song.6000.json','["西崑册府控千廬，鈆筆多年校魯魚。", "厭享雙鷄太官膳，貪乘五馬使君車。", "明光畫省辭青瑣，天柱仙壇訪紫書。", "只恐政成抛印綬，攜家深入白雲居。"]'),
('6efc7ccc-18e3-4da5-88dd-688985798249','夜宴','楊億','宋','宋诗','song-poetry','','[]','玉壺春漏咽銅龍，畫棟塵飛曲未終。',64,'全唐诗/poet.song.6000.json','["玉壺春漏咽銅龍，畫棟塵飛曲未終。", "樽酒渌醅和蟻汎，窗燈紅熖隔紗烘。", "水沉煙裊風微起，霜檜陰圓月正中。", "苦恨當關催夙駕，平明入謁未央宫。"]'),
('8fa6fe15-54c1-4d59-965e-1fa550cfe38f','陳太博知建州','楊億','宋','宋诗','song-poetry','','[]','夢筆山連化劍津，兩鄉人看錦衣新。',64,'全唐诗/poet.song.6000.json','["夢筆山連化劍津，兩鄉人看錦衣新。", "北堂滫瀡三牲膳，南陌驂驔五馬塵。", "畫角聲殘鈴閣暮，露牙香細茗園春。", "甌閩自昔多居士，誰是賢侯席上珍。"]'),
('0c15cb21-c796-4474-8bd9-5b45817caa7d','再别陳建州因以抒意','楊億','宋','宋诗','song-poetry','','[]','北闕多年作侍臣，一枝煙雨憶南閩。',64,'全唐诗/poet.song.6000.json','["北闕多年作侍臣，一枝煙雨憶南閩。", "留連五鼓趨丹禁，健羡雙旌擁畫輪。", "籬畔菊荒環堵宅，山中鶴怨未歸人。", "州民刺字空漫滅，目斷東方千騎塵。"]'),
('a0958ed0-8486-40db-a042-e4d6e3569a4c','梁四諫議知鳳翔府','楊億','宋','宋诗','song-poetry','','[]','幾日銀臺閲副封，岐陽西顧委秦中。',64,'全唐诗/poet.song.6000.json','["幾日銀臺閲副封，岐陽西顧委秦中。", "函關叱馭經天險，豳國聞鷄接土風。", "雲幕杯盤三省近，星郵章奏九門通。", "下車卧理應無事，莫遣融樽酒暫空。"]'),
('37b92093-9f01-4b5e-964f-a49e5d29e490','錢易赴蘄春','楊億','宋','宋诗','song-poetry','','[]','名重星垣試，官閒月寺中。',72,'全唐诗/poet.song.6000.json','["名重星垣試，官閒月寺中。", "竹符千里郡，花浪一帆風。", "塵隙駒從度，霞觴酒莫空。", "公堂封筆塜，郵舍遞詩筒。", "騷客休懷楚，詞臣合薦雄。", "長庚謫仙骨，須入抃鼇宫。"]'),
('bb4fdc88-6cd7-4c3a-bc4e-de4e10af37c6','福州張從事','楊億','宋','宋诗','song-poetry','','[]','萬人都督古閩州，幕府旌門映碧油。',64,'全唐诗/poet.song.6000.json','["萬人都督古閩州，幕府旌門映碧油。", "閫外依蓮滯英俊，樽前噉薤占風流。", "犀燈照水窺龍劍，鯨浪噴空見蜃樓。", "暇日登高賦滄海，添鹽堪爲昔賢羞。"]'),
('8eaf30b8-9ef7-4a9f-b293-cf77ff16e510','元淨上人之新安謁李學士兼遊廬阜','楊億','宋','宋诗','song-poetry','','[]','雙闕重城到幾迴，兩遊千里忽浮杯。',64,'全唐诗/poet.song.6000.json','["雙闕重城到幾迴，兩遊千里忽浮杯。", "黟江春水淺深渌，廬岳夏蓮傾倒開。", "謝守同翻貝葉字，湯師獨占碧雲才。", "舊房京寺門空閉，坐榻凝塵砌長苔。"]'),
('0c351b57-d90b-44f8-8894-37a90e102a33','京府獄空降詔因寄大尹學士','楊億','宋','宋诗','song-poetry','','[]','長安惡少罷探丸，桴鼓聲沉禁網寛。',64,'全唐诗/poet.song.6000.json','["長安惡少罷探丸，桴鼓聲沉禁網寛。", "三尺舊章閑玉律，八行優詔下金鑾。", "帝臨宣室方前席，民值唐年耻畫冠。", "終日訟庭無一事，早調伊鼎佐湯盤。"]'),
('8c41f517-3750-4c20-a972-0b1fad0c5cd0','葉秘書温知蜀州江原縣','楊億','宋','宋诗','song-poetry','','[]','秘省丞郎出字人，錦江偏好濯纓塵。',64,'全唐诗/poet.song.6000.json','["秘省丞郎出字人，錦江偏好濯纓塵。", "酒壚千古風流地，花縣三年爛漫春。", "白羽豫州慵草檄，青天蜀道厭摧輪。", "巴猿杜魄驚鄉夢，莫遣霜華髩畔新。"]'),
('9b3b3b5c-d22a-4162-bfea-0a9697edf2fb','和酬秘閣錢少卿夜直見寄次韻','楊億','宋','宋诗','song-poetry','','[]','甘瓜朱李郢醪濃，素綆銀牀蔭碧桐。',64,'全唐诗/poet.song.6000.json','["甘瓜朱李郢醪濃，素綆銀牀蔭碧桐。", "賜第舊連丹鳳闕，直廬今在未央宫。", "承雲仙掌延年露，轉蕙薰絃解愠風。", "此夕蓬山好逃暑，月軒清話恨難同。"]'),
('047cab2c-511b-4a23-90d6-2436e95e7c76','送石枕與參政王給事','楊億','宋','宋诗','song-poetry','','[]','千古碧潭秋水骨，琢成孤枕冷於冰。',64,'全唐诗/poet.song.6000.json','["千古碧潭秋水骨，琢成孤枕冷於冰。", "因爲江外朱輪守，得自林閒白足僧。", "月幌光寒吞桂魄，暑軒氣爽壓梅蒸。", "奇章好尚非流俗，願向蕭齋代曲肱。"]'),
('60f54c70-c5b4-45ad-9697-bd23cd4dafc4','黄小著震知興元府南鄭縣','楊億','宋','宋诗','song-poetry','','[]','藏室仙郎罷屬辭，暑天驅傳出京畿。',64,'全唐诗/poet.song.6000.json','["藏室仙郎罷屬辭，暑天驅傳出京畿。", "流年兩鬢生華髪，宰邑全家住翠微。", "九折坂長須叱馭，三聲猿苦莫霑衣。", "金門薦鶚知音在，不到瓜時捧詔歸。"]'),
('d4618514-29b1-4d5e-9e28-88ba4b90c1bb','陳堯拱廷評致仕歸蜀','楊億','宋','宋诗','song-poetry','','[]','一家今有十朱輪，獨憶雲山欲退身。',64,'全唐诗/poet.song.6000.json','["一家今有十朱輪，獨憶雲山欲退身。", "天邑繁華行樂厭，月曹清要命書新。", "西風躍馬經秦甸，東道椎牛讌孟鄰。", "秋稼萬箱僮百指，羲皇之上更何人。"]'),
('13597251-d29c-4614-82e9-a56634df0138','史館趙祠部况通判宿州','楊億','宋','宋诗','song-poetry','','[]','風流華省含香客，籍甚先朝奏賦人。',64,'全唐诗/poet.song.6000.json','["風流華省含香客，籍甚先朝奏賦人。", "竹使三年勞佐郡，柳堤千里待行春。", "文園避事心長笑，天禄讎書鬢漸新。", "帝念河渠在封部，特緣經義委名臣。"]'),
('7555d3ac-7415-4cec-98a0-4fb9ed317a57','擇良上人歸天台','楊億','宋','宋诗','song-poetry','','[]','片席然犀經水府，幾程登陸望霞標。',64,'全唐诗/poet.song.6000.json','["片席然犀經水府，幾程登陸望霞標。", "吟情晚日繁雲合，歸路秋風密葉凋。", "行道六時廬嶽漏，浮杯千里浙江潮。", "舊房宴坐觀空後，香積多年飯頓銷。"]'),
('ce5370e8-5716-4c32-b90f-ce156fe04a7f','表玄師歸縉雲有懷故雄闍黎成轉韻六十四句','楊億','宋','宋诗','song-poetry','','[]','括蒼古名郡，生齒三萬家。',288,'全唐诗/poet.song.6000.json','["括蒼古名郡，生齒三萬家。", "我昔自仙殿，捧詔臨軍牙。", "清心治朞月，訟息民無譁。", "雄公真大士，宴坐綿歲華。", "駕言造梵宇，室邇驚人遐。", "迎門虎溪屐，布地牛頭花。", "庭松偃翠蓋，澗泉漱金沙。", "坐聞師子吼，歸恨踆烏斜。", "驛召還上都，騰裝即修路。", "别師黄金園，贈我碧雲句。", "我歸步赤墀，代言紅藥署。", "彈指知苦空，觀心得降住。", "藏識慚宿薫，輪迴悲晚悟。", "折簡問南宗，寄言滿緗素。", "絕念契真如，忘筌離文字。", "刼燒雖洞然，龍華决同遇。", "師名達宸扆，恩詔頒方袍。", "歡喜黑白衆，蕭衰霜雪毛。", "毗邪見有疾，示身如幻泡。", "雙林忽歸寂，人天但哀號。", "堆案遺札在，滿鉢香飯銷。", "只應伸臂頃，未覺他方遙。", "犀柄挂空壁，鴈塔千層霄。", "七返暫來去，四大非堅牢。"]'),
('14a55fad-6876-4659-906b-cf467e15d4c6','蘇寺丞維甫知簡州陽安縣兼攜家之任','楊億','宋','宋诗','song-poetry','','[]','神雞縹碧馬金精，西海桑田一掌平。',64,'全唐诗/poet.song.6000.json','["神雞縹碧馬金精，西海桑田一掌平。", "苜蓿度關風漸勁，莓苔登棧雨新晴。", "琴齋盡室無歸夢，錦里當壚奈宿酲。", "麈柄清談且爲政，莫貪蒟醬學論兵。"]'),
('5c62dd61-870c-4d21-a19d-ba4a728f1f04','宿齋太乙宫答李寺丞次韻','楊億','宋','宋诗','song-poetry','','[]','泰畤齋居肅，梧楸蔭繚垣。',48,'全唐诗/poet.song.6000.json','["泰畤齋居肅，梧楸蔭繚垣。", "露葵深得味，風鐸乍成喧。", "綠髪松喬侣，丹經黄老言。", "心期阻良久，蝶夢繞朱門。"]'),
('038d90b6-31a7-40a4-a119-777281ce58db','建溪十詠 武夷山','楊億','宋','宋诗','song-poetry','','[]','靈嶽標真牒，孤峰入紫氛。',48,'全唐诗/poet.song.6000.json','["靈嶽標真牒，孤峰入紫氛。", "藤蘿暗仙穴，猿鳥駭人羣。", "古道千年在，懸流萬壑分。", "漢壇秋蘚駁，誰祀武夷君。"]'),
('d7a6adfb-d446-45a7-86ea-506c0c13445c','北苑焙','楊億','宋','宋诗','song-poetry','','[]','靈芽呈雀舌，北苑雨前春。',48,'全唐诗/poet.song.6000.json','["靈芽呈雀舌，北苑雨前春。", "入貢先諸夏，分甘及近臣。", "越甌猶借渌，蒙頂敢争新。", "鴻漸茶經在，區區不遇真。"]'),
('7beee3c2-08d6-4561-9921-67cc14d1eef1','北苑焙 朗山寺','楊億','宋','宋诗','song-poetry','','[]','層巒連近郭，占勝有招提。',48,'全唐诗/poet.song.6000.json','["層巒連近郭，占勝有招提。", "宿霧昏金像，飛泉濺石梯。", "鐘聲空谷答，塔影亂雲齊。", "千騎時來此，尋幽獨杖藜。"]'),
('113b4114-33a0-4eef-9644-5353ee4adfd7','北苑焙 陸羽井','楊億','宋','宋诗','song-poetry','','[]','陸羽不到此，標名慕昔賢。',48,'全唐诗/poet.song.6000.json','["陸羽不到此，標名慕昔賢。", "金瓶垂素綆，石甃湛寒泉。", "百汲甘寧竭，千金志不遷。", "真茶汎雲液，一歠可延年。"]'),
('5877d3e1-e189-48f9-b374-068807de1bba','北苑焙 梨山廟','楊億','宋','宋诗','song-poetry','','[]','唐季臨兹郡，生祠已薦馨。',48,'全唐诗/poet.song.6000.json','["唐季臨兹郡，生祠已薦馨。", "聲詩傳樂府，廟貎載圖經。", "畫壁流塵暗，金碑古蘚青。", "細民時請福，撾鼓賽遺靈。"]'),
('b15b93df-c494-492c-84a0-da670c7d1677','北苑焙 勤公亭','楊億','宋','宋诗','song-poetry','','[]','危亭壓波面，屹若抃靈鼇。',48,'全唐诗/poet.song.6000.json','["危亭壓波面，屹若抃靈鼇。", "浮蟻酡顔數，飛鴻送目勞。", "吏圍披簿領，僧伴話風騷。", "何日登懸榻，州民刺有毛。"]'),
('ec8f5059-e0ef-4285-abae-59d4f343b8e8','北苑焙 大中塔','楊億','宋','宋诗','song-poetry','','[]','鷄園開淨土，鴈塔倚寒空。',48,'全唐诗/poet.song.6000.json','["鷄園開淨土，鴈塔倚寒空。", "風鐸和清梵，晴幡映彩虹。", "香花傾海國，金碧擬天宫。", "絕頂登臨處，谿山一掌中。"]'),
('9ae497d4-e088-4711-a982-70b526f92988','北苑焙 仙人洲','楊億','宋','宋诗','song-poetry','','[]','寒潭吞别派，孤嶼屹中流。',48,'全唐诗/poet.song.6000.json','["寒潭吞别派，孤嶼屹中流。", "昔有驂鸞客，因名墜馬洲。", "洪波長赴海，碧樹幾經秋。", "城郭何年變，空聞鶴語愁。"]'),
('ae0c025d-3ef9-482e-ae2e-0a91672db9c0','北苑焙 延平津','楊億','宋','宋诗','song-poetry','','[]','積水深無際，神龍此屈蟠。',48,'全唐诗/poet.song.6000.json','["積水深無際，神龍此屈蟠。", "媚川珠彩動，射斗劍光寒。", "燕脯誰能寄，犀燈豈易看。", "負圖當瑞聖，何苦蟄洪瀾。"]'),
('1caa8445-141a-46bb-9cbe-f2d8b6d86f61','北苑焙 毛竹洞','楊億','宋','宋诗','song-poetry','','[]','洞門生異竹，冉冉接同亭。',48,'全唐诗/poet.song.6000.json','["洞門生異竹，冉冉接同亭。", "石迸狂鞭怒，霜封密葉青。", "實應容鳳食，杖欲變龍形。", "逋客歸何日，巖阿已勒銘。"]'),
('c97b632e-418e-4ae5-b789-7af45dfdd665','因與西廳參政侍郎奕棋予輸紙筆硯三物以詩見徵屬宣毫適盡但送蜀牋端硯繼以此章','楊億','宋','宋诗','song-poetry','','[]','多年燥吻蒼苔砌，秃盡江南石上毫。',64,'全唐诗/poet.song.6000.json','["多年燥吻蒼苔砌，秃盡江南石上毫。", "五色蠻牋猶有剩，一拳端硯豈勝勞。", "蕭齋幸預談賓末，謝墅深降奕思高。", "微物供堂方猶豫，丹青筆下枉風騷。"]'),
('d2053066-a3b1-495e-b907-b47a47c96ccb','又以建茶代宣筆别書一絕','楊億','宋','宋诗','song-poetry','','[]','青管演綸都已竭，文楸爭道恨非高。',32,'全唐诗/poet.song.6000.json','["青管演綸都已竭，文楸爭道恨非高。", "輒將花苑先春茗，聊代山中墮月毫。"]'),
('eb3f9585-3531-46e0-bd82-95f148cd6d94','遊王氏東園','楊億','宋','宋诗','song-poetry','','[]','名園聊得拂塵衣，深入春叢一逕微。',64,'全唐诗/poet.song.6000.json','["名園聊得拂塵衣，深入春叢一逕微。", "萬樹未饒金谷富，百畦猶有漢陰機。", "青蘋風暖天鷄出，文杏巢乾海鷰歸。", "向晚鳴騶九門路，柳堤回首獨依依。"]'),
('88909987-42e6-401e-b191-cd6ecca0f751','送僧歸蘇州','楊億','宋','宋诗','song-poetry','','[]','說法雄音敵海潮，一棲京寺葉頻凋。',64,'全唐诗/poet.song.6000.json','["說法雄音敵海潮，一棲京寺葉頻凋。", "水田三事衣將敝，香積多年飯頓銷。", "忽憶虎丘飛夢到，更聞蓮社寄書招。", "好傳祖印歸南土，莫遣宗風漸寂寥。"]'),
('e8e1d0d4-751e-4d02-a8f5-be080edaa2a8','送僧歸越州','楊億','宋','宋诗','song-poetry','','[]','舊房稽嶺鎖春苔，猿鳥歡迎振錫迴。',64,'全唐诗/poet.song.6000.json','["舊房稽嶺鎖春苔，猿鳥歡迎振錫迴。", "花雨六時飄講席，樵風千里送浮杯。", "一乘了義刳心學，三藏真文盥手開。", "跡似孤雲本無滯，飄飄新到帝鄉來。"]'),
('4b0582b9-3640-4c3a-8edb-9279f3bcbc69','張泌東遊','楊億','宋','宋诗','song-poetry','','[]','玉籍參差未策名，東遊聊得拂塵纓。',64,'全唐诗/poet.song.6000.json','["玉籍參差未策名，東遊聊得拂塵纓。", "長亭酒盡驪歌闋，下榻波狂鷁棹輕。", "澤國鱠鱸懸夢想，戟門羅雀斷逢迎。", "秋期莫到槐花老，待聽新文擲地聲。"]'),
('37301565-b02f-4160-898e-908a7fd9ee61','喜王虞部賜進士及第','楊億','宋','宋诗','song-poetry','','[]','中臺高應列星文，千騎驂驔擁畫輪。',64,'全唐诗/poet.song.6000.json','["中臺高應列星文，千騎驂驔擁畫輪。", "起草已誇雙筆健，登科更占一枝春。", "龍津召宴芝泥濕，鴈塔題名麝墨新。", "只待甘泉重奏賦，彯纓長奉屬車塵。"]'),
('99303dac-fc76-4acb-9b3a-6c4dbdfde5e5','送章四十舅翁東歸','楊億','宋','宋诗','song-poetry','','[]','鄉黨共推賢，干名二十年。',48,'全唐诗/poet.song.6000.json','["鄉黨共推賢，干名二十年。", "早懷荆岫璞，遲下祖生鞭。", "敢諫書無報，徒行履欲穿。", "聖朝公道在，搔首賦歸田。"]'),
('c3f35332-8834-4453-9fed-b87041a0572e','范儀下第東歸','楊億','宋','宋诗','song-poetry','','[]','君住武夷鄉，思歸便促裝。',48,'全唐诗/poet.song.6000.json','["君住武夷鄉，思歸便促裝。", "溪鱗絲縷細，園茗露牙香。", "雷火悲三上，金錢困一囊。", "長纓塵土滿，會待濯滄浪。"]'),
('dbfceaad-a20c-4eee-bd74-87492d39332d','送章頔寺丞之巴陵','楊億','宋','宋诗','song-poetry','','[]','涔陽從事有嘉聲，外計封章薦姓名。',64,'全唐诗/poet.song.6000.json','["涔陽從事有嘉聲，外計封章薦姓名。", "再命便爲千室宰，于飛又岀九重城。", "腰懸銅墨才猶屈，吟對江山思轉清。", "楚客十年偏遂意，秋風滿筯紫蓴羹。"]'),
('cd97f8ff-44cf-4849-b35f-76746ea4c9ec','外弟張湜西遊','楊億','宋','宋诗','song-poetry','','[]','六年隨我客梁園，西上孤飛徹九門。',64,'全唐诗/poet.song.6000.json','["六年隨我客梁園，西上孤飛徹九門。", "抱璞有瑕唯歎命，泣岐無託更銷魂。", "秦關百二聊乘興，漢牘三千待叫閽。", "赤日炎風兩京道，文章滿腹與誰論。"]'),
('e62f046d-ba59-4981-8685-faf6ad7f84d2','章羣下第東歸','楊億','宋','宋诗','song-poetry','','[]','卓犖修詞有古風，計偕西上劇飄蓬。',64,'全唐诗/poet.song.6000.json','["卓犖修詞有古風，計偕西上劇飄蓬。", "梁園失意三春月，閩嶺思歸一畝宫。", "且喜還家儀舌在，莫嗟爲客趙囊空。", "九天下詔崇儒術，好絕韋編待至公。"]'),
('86af87d8-db75-4fb0-af23-7d750ddb0f6d','賀資政學士王侍郎','楊億','宋','宋诗','song-poetry','','[]','瀝懇青規動帝心，秋曹月殿寵光深。',64,'全唐诗/poet.song.6000.json','["瀝懇青規動帝心，秋曹月殿寵光深。", "論思東序清閒宴，偃息西崑翰墨林。", "私第藏書皆有副，公庭種竹待成陰。", "卧龍禁闥應非久，救旱還須起作霖。"]'),
('da2c1aca-5e26-4e83-a12c-d1770b252530','表弟廷評章得象知信州玉山縣','楊億','宋','宋诗','song-poetry','','[]','懷玉烟霞接武夷，我思祖德涕霑衣。',64,'全唐诗/poet.song.6000.json','["懷玉烟霞接武夷，我思祖德涕霑衣。", "縣齋製錦留遺愛，庭樹藏鐶長舊圍。", "彭澤公田今已廢，遼東邑子半應非。", "津亭送别空搔首，籍在金門未得歸。"]'),
('e4f1b976-7030-495a-919c-793f6795a3bd','梁大諫自鳯翔乞留臺寄詩言志次韻酬之','楊億','宋','宋诗','song-poetry','','[]','聯飛仙掖舊心朋，笑我池籠出未能。',64,'全唐诗/poet.song.6000.json','["聯飛仙掖舊心朋，笑我池籠出未能。", "文陛彯纓空自愧，香山蠟屐與誰登。", "託身羿彀憂危甚，引領黄陂鄙吝增。", "二室風煙莫全占，會須攜手躡雲層。"]'),
('bc1e3b32-1664-459e-b3d6-1abb20e3b2f2','石殿丞通判濮州','楊億','宋','宋诗','song-poetry','','[]','龍虎遊從分不疏，忽聞新命佐魚符。',64,'全唐诗/poet.song.6000.json','["龍虎遊從分不疏，忽聞新命佐魚符。", "經旬苦雨淹行斾，幾曲洪河貫郡圖。", "浮蟻酒濃頻舉白，折膠風勁好彎弧。", "賢侯東道歡相得，期月民謠待袴襦。"]'),
('4ad0c524-6e82-4a47-bec0-acfd79e365c9','元奉宗宰績溪','楊億','宋','宋诗','song-poetry','','[]','遊梁度幾春，時譽藹天倫。',48,'全唐诗/poet.song.6000.json','["遊梁度幾春，時譽藹天倫。", "家寄汀蘋久，名題桂籍新。", "溪鱗清可數，澤雉到應馴。", "黟歙非難治，民風自古淳。"]'),
('c26f9797-233f-4e68-b32c-a0eebd25d6f6','李工部江南轉運','楊億','宋','宋诗','song-poetry','','[]','含香五字客，尚齒十年兄。',96,'全唐诗/poet.song.6000.json','["含香五字客，尚齒十年兄。", "舊奏梁園賦，新題漢柱名。", "出驅星使傳，入佐地官征。", "獻可方前笏，分憂又抗旌。", "富饒今澤國，佳麗古臺城。", "錯節投刀釋，頺綱攬轡清。", "沃心期密啓，銜尾待香秔。", "處處江山秀，行春莫計程。"]'),
('67282476-e265-4921-986f-36a390992a15','楊日華宰錢塘','楊億','宋','宋诗','song-poetry','','[]','洛社負才名，吾宗占寧馨。',72,'全唐诗/poet.song.6000.json','["洛社負才名，吾宗占寧馨。", "聞詩趨鯉室，襲慶墮鱣庭。", "力學窺堂奥，孤飛徹杳冥。", "一枝攀綠桂，百里應華星。", "漢網何曾密，吳歈正好聽。", "油囊滿醇酎，千日莫期醒。"]'),
('716ed98c-3399-42c3-9a2b-4909114d9555','柳紳歸縉雲','楊億','宋','宋诗','song-poetry','','[]','東甌别業寄秋雲，平昔題橋墨尚存。',64,'全唐诗/poet.song.6000.json','["東甌别業寄秋雲，平昔題橋墨尚存。", "故郡曾登太守榻，上都頻掃相君門。", "揮毫月殿香盈袖，錫讌星津酒滿樽。", "歸去吏民如問我，五年書命紫薇垣。"]'),
('8c407430-28e1-43ef-9c84-47616de46e22','表弟李宗元知桂州陽朔縣','楊億','宋','宋诗','song-poetry','','[]','桂林陽朔溪山秀，莫歎迢迢五嶺南。',64,'全唐诗/poet.song.6000.json','["桂林陽朔溪山秀，莫歎迢迢五嶺南。", "百里字人須敏政，千金酌水更懲貪。", "鳴榔下瀨潮程遠，曵彩升堂壽讌酣。", "遠地民淳無牒訴，縣齋終日好清談。"]'),
('4e41b3cd-571d-4705-acaa-77e9e8418fd2','高起居知廣州','楊億','宋','宋诗','song-poetry','','[]','作藩南越古稱雄，五管皆歸節制中。',64,'全唐诗/poet.song.6000.json','["作藩南越古稱雄，五管皆歸節制中。", "腰佩金龜三品綬，船開畵鷁一帆風。", "橘官手版趨塵遠，梅使星車附信通。", "暫阻螭頭夾香案，清宵應夢未央宫。"]'),
('612a3407-775c-4117-bbeb-7fbb735ee5d8','丁集賢通判餘杭','楊億','宋','宋诗','song-poetry','','[]','遼東羽客富仙材，仙殿飛觴接上台。',64,'全唐诗/poet.song.6000.json','["遼東羽客富仙材，仙殿飛觴接上台。", "便道歸寧白蘋渚，經時賜對柏梁臺。", "里中驅弩先行路，膝下斑衣慶壽杯。", "明詔許令過别墅，不憂郡閣簡書催。"]'),
('e3e180c7-ad4b-4083-8ecb-84c3e9bac53a','吳航赴宜興簿','楊億','宋','宋诗','song-poetry','','[]','家住武夷峰，眉間道氣濃。',48,'全唐诗/poet.song.6000.json','["家住武夷峰，眉間道氣濃。", "風塵久爲客，雷火近成龍。", "試吏江城僻，寧親嶺路重。", "一廛期沒齒，樂土定相容。"]'),
('fd1962fe-ff5c-4143-8f43-5a468dec4b7b','十六兄赴韶州從事','楊億','宋','宋诗','song-poetry','','[]','魏帝臺邉拂戰塵，初平山畔綵衣新。',64,'全唐诗/poet.song.6000.json','["魏帝臺邉拂戰塵，初平山畔綵衣新。", "又攀高柳隋隄暮，却寄寒梅庾嶺春。", "韶石閒尋張樂地，曹溪首訪悟空人。", "男兒平昔四方志，莫厭區區走隻輪。"]'),
('f7f6608b-bd66-44f8-8297-b00c0477e6ad','章頻宰南昌','楊億','宋','宋诗','song-poetry','','[]','孺亭洪井古南昌，曾是梅仙試吏鄉。',64,'全唐诗/poet.song.6000.json','["孺亭洪井古南昌，曾是梅仙試吏鄉。", "一邑絃歌榮製錦，幾程雞犬接維桑。", "年深爲客貂裘敝，秋晚還家菊徑荒。", "平昔題橋今遂志，且斟壽酒獻高堂。"]'),
('f18a6beb-d1ce-41b9-b5d7-b8659b4950f6','李廷評昭迪使淝上','楊億','宋','宋诗','song-poetry','','[]','畫舸西風五兩斜，淮淝将命去程賖。',64,'全唐诗/poet.song.6000.json','["畫舸西風五兩斜，淮淝将命去程賖。", "衣纓黄閣相君後，門巷青春學士家。", "驛路新袍欺草色，公筵大白醉榴花。", "謝庭蘭玉多才思，休澣裁詩對客誇。"]'),
('50897216-740e-4797-adf6-525cd805dbf0','書懷寄劉五','楊億','宋','宋诗','song-poetry','','[]','風波名路壮心殘，三逕荒凉未得還。',64,'全唐诗/poet.song.6000.json','["風波名路壮心殘，三逕荒凉未得還。", "病起東陽衣带緩，愁多騎省髩毛斑。", "五年書命塵西閣，千古移文愧北山。", "獨憶瓊枝苦霜霰，清罇歲晏强酡顔。"]'),
('a3ecdf99-738a-4f9e-a5ae-1fff4e583ba5','趙殿丞知河南縣','楊億','宋','宋诗','song-poetry','','[]','鼎邑閭閻有古風，清談爲治自從容。',64,'全唐诗/poet.song.6000.json','["鼎邑閭閻有古風，清談爲治自從容。", "官聯殿省通朝籍，路過津橋入縣封。", "柳蔭天街時案轡，雲生少室好搘笻。", "龍門舊有題名處，石壁蒼苔駮幾重。"]'),
('558bff34-e2e9-46c5-bb69-0f13fc883fe2','秘閣王校理知柳州','楊億','宋','宋诗','song-poetry','','[]','南越尉佗國，羅池子厚神。',72,'全唐诗/poet.song.6000.json','["南越尉佗國，羅池子厚神。", "桂林驅傳遠，芸閣解嘲頻。", "行槖黄金滿，歸程皂蓋新。", "一麾愁度嶺，五綵喜寧親。", "薏苡偏防疾，蒲蘆善化人。", "蓬山直廬在，几硯日生塵。"]'),
('7b664e12-475c-4b30-bf98-ed364548cd55','送僧歸越','楊億','宋','宋诗','song-poetry','','[]','中林宴坐赤髭繁，水月禪心出世間。',64,'全唐诗/poet.song.6000.json','["中林宴坐赤髭繁，水月禪心出世間。", "說法音同海潮震，隨緣身比嶽雲閒。", "曹溪嫡嗣多參見，碧落仙卿徧往還。", "歸去舊房秋色晚，澗松枝偃雨苔斑。"]'),
('21c4d456-8a2f-4c9c-8abe-378b6bbe3ec0','吳延年宰武義','楊億','宋','宋诗','song-poetry','','[]','精神滿腹富青春，燒尾曾看上禹門。',64,'全唐诗/poet.song.6000.json','["精神滿腹富青春，燒尾曾看上禹門。", "獻賦多年梁苑客，謫仙重世武夷孫。", "一同印綬光初命，幾驛桑麻接故園。", "澤國歸程秋欲盡，丹楓黄菊動吟魂。"]'),
('c1fd23a8-8441-49a7-b854-34ce764e6d6b','吳待問之蒙城簿','楊億','宋','宋诗','song-poetry','','[]','西來赴調合闗繻，黄綬風塵厭九衢。',64,'全唐诗/poet.song.6000.json','["西來赴調合闗繻，黄綬風塵厭九衢。", "祖席且同開口笑，公庭未免折腰趨。", "長安車馬偏欺客，魯國衣冠肯戲儒。", "共憶故園歸計晚，舊遊烟樹隔重湖。"]'),
('0c61abba-1a0b-4b6a-922e-637107c94902','黄少卿惠綠雲湯','楊億','宋','宋诗','song-poetry','','[]','新甫奇材百尺標，秋空高幹拂鵬霄。',64,'全唐诗/poet.song.6000.json','["新甫奇材百尺標，秋空高幹拂鵬霄。", "仙經藥品誇難老，人世霜天貴後凋。", "千古貞魂愁化實，九原荒壠恨爲樵。", "誰硏露葉和雲液，幾宿春酲一啜消。"]'),
('a1374b11-896b-4bfa-b7a9-ea98698425d3','靈隱長老歸舊山','楊億','宋','宋诗','song-poetry','','[]','浮杯心與海鷗親，駐錫王城忽過春。',64,'全唐诗/poet.song.6000.json','["浮杯心與海鷗親，駐錫王城忽過春。", "麟殿九旬談妙法，曹溪一滴渡迷津。", "狂翻竹箭波隨棹，側布黄金地絕塵。", "白黑歡迎猿鳥喜，紺園風定雨花新。"]'),
('8b14a89d-1027-403b-8352-0051fbf3c186','皇甫太博知蘇州','楊億','宋','宋诗','song-poetry','','[]','長洲連歲得賢君，十萬人家煦若春。',64,'全唐诗/poet.song.6000.json','["長洲連歲得賢君，十萬人家煦若春。", "激箭波狂浮畫舸，散絲雨細逐朱輪。", "郡齋詩石鋪輕蘚，公宴歌喉落暗塵。", "未得休官作逋客，河梁歸思滿鱸蓴。"]'),
('a180b0f6-ac42-4de5-8b13-95ed73420c05','懷寄樞密王左丞','楊億','宋','宋诗','song-poetry','','[]','高陪七聖從軒遊，帷幄深嚴日運籌。',64,'全唐诗/poet.song.6000.json','["高陪七聖從軒遊，帷幄深嚴日運籌。", "口裏雌黄歸品藻，盤中薤白想風流。", "珠宫地密妨趨謁，銅鉢聲沉斷唱酬。", "獨喜修書依絳帳，時登闕里受春秋。"]'),
('f64ff55b-cd42-4b2d-bf88-7cb68faca841','從叔郎中知潭州','楊億','宋','宋诗','song-poetry','','[]','藩閫分憂重，關山去路賖。',96,'全唐诗/poet.song.6000.json','["藩閫分憂重，關山去路賖。", "含香滯郎署，乘馹倦天涯。", "土貢千頭橘，神祠萬里沙。", "金碑紀風物，寶瑟怨年華。", "粉籜斑文簟，雲腴紫笋芽。", "民田兩岐麥，郡圃四時花。", "别恨休攀柳，歸期待及瓜。", "鱣庭有遺訓，清白自傳家。"]'),
('28249895-f352-4779-a05f-ae764171e7b7','黄刑部之陜西轉運','楊億','宋','宋诗','song-poetry','','[]','百二秦川四塞寛，甘泉烽火報平安。',64,'全唐诗/poet.song.6000.json','["百二秦川四塞寛，甘泉烽火報平安。", "泥書雙筆遷郎署，粒食千金仰縣官。", "江海半生抛别墅，闗山何日解征鞍。", "定将鞭筭資心計，流馬功成國史刊。"]'),
('1d4e9add-a8cf-4eea-824f-3cca53fccb36','史館張學士知婺州','楊億','宋','宋诗','song-poetry','','[]','鸞掖分符又出麾，津亭目送片帆飛。',64,'全唐诗/poet.song.6000.json','["鸞掖分符又出麾，津亭目送片帆飛。", "暫隨越鳥棲烟樹，重許吳儂見錦衣。", "屬邑行春熊軾稳，公堂卜夜蟹螯肥。", "隱侯带眼看成緩，雙闕恩深更憶歸。"]'),
('dce70bcf-5a5a-4860-babe-4f9c447b09ff','答李光丞','楊億','宋','宋诗','song-poetry','','[]','豹尾森森拂畫簷，久留雕輦閲牙籖。',64,'全唐诗/poet.song.6000.json','["豹尾森森拂畫簷，久留雕輦閲牙籖。", "字分三豕慚該博，饌費雙雞愧屬厭。", "濫跡搢紳同北枳，草儀封禪待南鶼。", "相門蘭玉裁新句，只恐京城紙價添。"]'),
('d8885c98-997a-4776-be38-32ab3ad64040','寄并州張給事','楊億','宋','宋诗','song-poetry','','[]','山河表裏絕狼煙，幕府朝朝醉玳筵。',64,'全唐诗/poet.song.6000.json','["山河表裏絕狼煙，幕府朝朝醉玳筵。", "合樂中軍雄鼓吹，傳杯四座豔花鈿。", "行春好駐桑郊騎，卜夜誰談雪竇禪。", "梁苑并門杳千里，離懷愁對月嬋娟。"]'),
('6d345a14-5627-4908-8c97-3cae0357f21e','寄劉秀州','楊億','宋','宋诗','song-poetry','','[]','騎置迢迢阻玉音，左魚江海遂初心。',64,'全唐诗/poet.song.6000.json','["騎置迢迢阻玉音，左魚江海遂初心。", "朱絃道直消浮謗，春草才多動苦吟。", "震澤析酲干樹橘，華亭驚夢九臯禽。", "郡樓晴日東西望，幾處甘棠接翠陰。"]'),
('b67b075b-4fef-4e4f-8c02-44cdb9c167bf','無爲軍王從事','楊億','宋','宋诗','song-poetry','','[]','奏牘曾蒙乙夜觀，擅場文價在金鑾。',64,'全唐诗/poet.song.6000.json','["奏牘曾蒙乙夜觀，擅場文價在金鑾。", "貂裘歲久京塵暗，鷁路風高旅翮殘。", "取酒黄金都已盡，食魚長鋏更須彈。", "時清水國無書檄，誰見揮毫一據鞍。"]'),
('92ec44a5-f9a0-443d-bf0e-64d53c074fec','密直任學士知益州','楊億','宋','宋诗','song-poetry','','[]','玉壘求賢牧，金門輟近臣。',120,'全唐诗/poet.song.6000.json','["玉壘求賢牧，金門輟近臣。", "龍荒使傳遠，雞省命書新。", "殿柱題名久，刀州入夢頻。", "懸魚喧舊政，叱馭繼芳塵。", "珠履平原客，壺漿左蜀人。", "北堂牽遠念，南詔撫殊鄰。", "宴榭峨眉雪，歌筵濯錦春。", "樂章傳辯士，卜肆訪逋民。", "幕府觴無筭，池塘思有神。", "知誰預交辟，空羡吐車茵。"]'),
('92a37ab9-7776-4076-8ff9-07f9b6f32125','休沐述懷寄秘閣錢少卿','楊億','宋','宋诗','song-poetry','','[]','風號電笑雨平堦，紈素微凉暗入懷。',64,'全唐诗/poet.song.6000.json','["風號電笑雨平堦，紈素微凉暗入懷。", "晝枕乍成園吏夢，晨蔬聊學太常齋。", "名慚引籍通丹地，心愧移文刻翠崖。", "大隱金門猶自適，日親方朔聽詼諧。"]'),
('039be399-54a7-4df0-a598-f029ffe90eb6','晏殊奉禮歸寧','楊億','宋','宋诗','song-poetry','','[]','垂髫婉孌便能文，驥子蘭筋迥不羣。',64,'全唐诗/poet.song.6000.json','["垂髫婉孌便能文，驥子蘭筋迥不羣。", "南國生芻人比玉，梁園修竹賦凌雲。", "堵墻看試三公府，反哺知千萬乘君。", "賜告歸寧來别我，亭臯木葉正紛紛。"]'),
('2634e34b-5cd9-445a-a864-db9596e4c640','送禪牀與樞密王左丞','楊億','宋','宋诗','song-poetry','','[]','北祖安禪唯看净，毗邪升座更談空。',32,'全唐诗/poet.song.6000.json','["北祖安禪唯看净，毗邪升座更談空。", "須知密勿萬機外，常在瑜伽三昧中。"]'),
('8bce4b18-4c97-4017-9767-de877d3c8b9a','受詔修書述懷感事三十韻','楊億','宋','宋诗','song-poetry','','[]','太極垂裳日，中原偃革初。',288,'全唐诗/poet.song.6000.json','["太極垂裳日，中原偃革初。", "樓船秋發詠，衡石夜程書。", "好問虚前席，徴賢走傳車。", "蓬莱侔漢制，煨燼訪秦餘。", "紬繹資金匱，規模出玉除。", "紛綸開四部，秘邃接千廬。", "飫賜雙雞膳，親迴六尺輿。", "華芝下閶闔，白羽擁儲胥。", "望氣成龍虎，披文辯魯魚。", "清光無咫尺，玄覽亦躊躇。", "羣彦揮鉛筆，微生濫石渠。", "嵇康真懶慢，謝客本空疏。", "講學情田埆，談經腹笥虚。", "月評依許劭，文體慕相如。", "雅飲歡娛洽，清言鄙吝祛。", "彌旬容出沐，終日喜羣居。", "撫已慚鳴玉，歸田憶荷鋤。", "池籠養魚鳥，章服裹猿狙。", "圜府愁尸禄，天閽愧弊裾。", "虚名同鄭璞，散質類荘樗。", "國士誰知我，鄰家或侮予。", "放懷齊指馬，屏息度羲舒。", "寡婦宜憂緯，三公亦灌蔬。", "危心惟觳觫，直道忍蘧蒢。"]'),
('68052fe5-4749-4776-bf0e-99019acad58d','分得朝野多歡娛','楊億','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','臯壤驚秋氣，倉箱有歲儲。',72,'全唐诗/poet.song.6000.json','["臯壤驚秋氣，倉箱有歲儲。", "梁園從臣頌，謝墅富人車。", "休沐新頒詔，珍符不絕書。", "天心游蠖濩，民樂在華胥。", "擊壤歡謠洽，凝脂密網除。", "行将封岱嶽，持槖奉金輿。"]'),
('f61c1661-990e-4221-8e79-55596e86e7b0','胡馬嘶北風','楊億','宋','宋诗','song-poetry','','[]','動地陰風勁，連雲白草齊。',72,'全唐诗/poet.song.6000.json','["動地陰風勁，連雲白草齊。", "聞琴空仰秣，踐雪憶歸蹄。", "金埒心寧戀，鹽車困欲嘶。", "過關拖疋練，渡水惜鄣泥。", "五路鸞旗緩，千金碣館迷。", "覉魂重懷土，不寐到晨鷄。"]'),
('4498274a-6c68-4bc0-bd2e-3880e342284a','金馬','楊億','宋','宋诗','song-poetry','','[]','茂異紛綸集漢庭，求賢詔在竹書青。',32,'全唐诗/poet.song.6000.json','["茂異紛綸集漢庭，求賢詔在竹書青。", "共趨金馬門前路，誰識東方是歲星。"]'),
('08894a6e-6afc-4c92-9691-b515a415584c','冬夜','楊億','宋','宋诗','song-poetry','','[]','香街鼓絕暝煙深，簷近孤釭射宿禽。',64,'全唐诗/poet.song.6000.json','["香街鼓絕暝煙深，簷近孤釭射宿禽。", "露井銀牀霜氣冷，瑣窗珠網月華侵。", "初沉遠籟聞疏漏，旋拂流塵撫素琴。", "坐久星河漸侵沒，蕭蕭朔吹度平林。"]'),
('1c5fecf4-1ba0-4054-bc5d-40f8bb399ebd','集賢李金部知潁州','楊億','宋','宋诗','song-poetry','','[]','汝陰名郡擁朱輪，洛宅霜威尚襲人。',64,'全唐诗/poet.song.6000.json','["汝陰名郡擁朱輪，洛宅霜威尚襲人。", "門籍舊通仙禁近，書囊纔補殿帷新。", "金華入侍知非晚，石柱題名又幾春。", "莫戀桑郊停五馬，蓬邱几硯自生塵。"]'),
('2b980246-15c4-4d93-b832-435e444d67ec','海印大師歸永嘉','楊億','宋','宋诗','song-poetry','','[]','都城供應幾經秋，海國歸心不少留。',64,'全唐诗/poet.song.6000.json','["都城供應幾經秋，海國歸心不少留。", "雨雪片帆過北固，煙霞丈室寄東甌。", "千燈續燄知無盡，一錫隨緣信自由。", "更到石門題雅句，碧雲從此掩湯休。"]'),
('f21b5ebf-7042-477a-bdf3-25207b58b9ee','故樞密宋給事挽歌三首  其一','楊億','宋','宋诗','song-poetry','','[]','宸遊方扈從，移疾廢樞機。',48,'全唐诗/poet.song.6000.json','["宸遊方扈從，移疾廢樞機。", "步輦親臨問，肩舁遽告歸。", "忽聞號左轂，旋見泣中闈。", "城郢遺言切，忠魂定有依。"]'),
('46cea844-86bc-4c32-87fa-b5dbe2b314a5','故樞密宋給事挽歌三首  其二','楊億','宋','宋诗','song-poetry','','[]','六龍初展義，七聖盡陪遊。',48,'全唐诗/poet.song.6000.json','["六龍初展義，七聖盡陪遊。", "塞外狼烟起，軍中羽檄稠。", "漢帷方借筯，荘壑忽沉舟。", "不奈良臣死，秦醫亦漫求。"]'),
('7724871d-d237-49d6-8b4a-d2f1a1bf291f','故樞密宋給事挽歌三首  其三','楊億','宋','宋诗','song-poetry','','[]','永辭温室地，長别諫書帷。',48,'全唐诗/poet.song.6000.json','["永辭温室地，長别諫書帷。", "玉恨埋黄壤，星愁析紫微。", "薤歌偏怨咽，衮歛更光輝。", "可惜岑文本，遼陽不共歸。"]'),
('a0c9b2bf-8c71-4b5b-a713-ea1b703f63f3','故蘄州王刑部閣老挽歌五首  其一','楊億','宋','宋诗','song-poetry','','[]','東觀未絕筆，西垣俄解龜。',48,'全唐诗/poet.song.6000.json','["東觀未絕筆，西垣俄解龜。", "罷裁青紙詔，重入白雲司。", "流落成三黜，聫翩換一麾。", "黄崗與滁上，應立去思碑。"]'),
('9a97f98e-fd52-498f-a9e8-44531dcbd08f','故蘄州王刑部閣老挽歌五首  其二','楊億','宋','宋诗','song-poetry','','[]','雞省曾三入，鼇峰近十旬。',48,'全唐诗/poet.song.6000.json','["雞省曾三入，鼇峰近十旬。", "命書批鳯尾，諫疏逆龍鱗。", "按部朱轓遠，悲秋素髮新。", "茂陵終不起，遺札滿埃塵。"]'),
('c37038da-b41c-4e42-98a6-67bfaa16f3a4','故蘄州王刑部閣老挽歌五首  其三','楊億','宋','宋诗','song-poetry','','[]','近署罹官謗，清淮綰郡章。',48,'全唐诗/poet.song.6000.json','["近署罹官謗，清淮綰郡章。", "平生不佞佛，晚歲尚爲郎。", "得疾因卑濕，爲文足感傷。", "纔蒙宣室召，奄忽歎云亡。"]'),
('75e5a723-5090-4614-8b4b-e989b7269f31','故蘄州王刑部閣老挽歌五首  其四','楊億','宋','宋诗','song-poetry','','[]','楚客離騷怨，子牟江海心。',48,'全唐诗/poet.song.6000.json','["楚客離騷怨，子牟江海心。", "積憂偏損壽，多病未妨吟。", "野鳥俄窺舍，甘棠已結陰。", "郡中應罷市，遺愛在人深。"]'),
('a34bb3a7-20f3-4667-9486-697310d015da','故蘄州王刑部閣老挽歌五首  其五','楊億','宋','宋诗','song-poetry','','[]','奏稿應盈篋，藏書復幾車。',48,'全唐诗/poet.song.6000.json','["奏稿應盈篋，藏書復幾車。", "門人誰漬酒，天子想投瓜。", "旅櫬闗山闊，銘旌道路賖。", "趨庭有令子，清白自傳家。"]'),
('66bce78c-74a5-4825-9e49-b4729f821710','故比部李郎中挽歌四首  其一','楊億','宋','宋诗','song-poetry','','[]','隴右華宗貴，朝端懿範存。',48,'全唐诗/poet.song.6000.json','["隴右華宗貴，朝端懿範存。", "哀烏光列宿，駟馬慶高門。", "謁帝承明署，娛賓金谷園。", "人生忽至此，天道亦難論。"]'),
('585f73d9-8895-48f1-9664-0c05f5a420f4','故比部李郎中挽歌四首  其二','楊億','宋','宋诗','song-poetry','','[]','睦族衣無主，傳家鼎有銘。',48,'全唐诗/poet.song.6000.json','["睦族衣無主，傳家鼎有銘。", "沙堤連里巷，玉樹接堦庭。", "北海樽常滿，西山藥不靈。", "肯堂歸棣萼，含笑入泉扄。"]'),
('193153b7-1bbe-46c1-bdd1-0d756d6b94e7','故比部李郎中挽歌四首  其三','楊億','宋','宋诗','song-poetry','','[]','鴈序分臺閣，春卿有職司。',48,'全唐诗/poet.song.6000.json','["鴈序分臺閣，春卿有職司。", "雲屏三殿宴，綿蕝一王儀。", "風韻靈和柳，襟懷叔度陂。", "善人無復見，執紼淚空垂。"]'),
('60650ad1-47cd-4572-b369-2774f936bc07','故比部李郎中挽歌四首  其四','楊億','宋','宋诗','song-poetry','','[]','美疢漳濵卧，營魂東岱歸。',48,'全唐诗/poet.song.6000.json','["美疢漳濵卧，營魂東岱歸。", "故人空漬酒，侍史罷薰衣。", "畫像留家廟，銘旌出帝畿。", "浮生除壽考，享福似君稀。"]'),
('c2601817-2664-4c09-8fab-228d63b8c866','明德皇太后挽歌詞五首  其一','楊億','宋','宋诗','song-poetry','','[]','母儀垂二紀，坤順翊玄功。',48,'全唐诗/poet.song.6000.json','["母儀垂二紀，坤順翊玄功。", "望斷蒼梧野，尊歸長樂宫。", "金塗烘曉日，椒壁起香風。", "奄忽違塵世，攀號泣舜瞳。"]'),
('4901265e-4b3b-4bb4-965e-854c99bb5014','明德皇太后挽歌詞五首  其二','楊億','宋','宋诗','song-poetry','','[]','軒星光太極，陰教正中闈。',48,'全唐诗/poet.song.6000.json','["軒星光太極，陰教正中闈。", "外戚黄金穴，深宫大練衣。", "雀臺愁霧隔，駒隙暗塵飛。", "貝闕三山路，飄颻仙馭歸。"]'),
('daea7b2f-a4e7-40a3-80ad-0e5f38f70796','明德皇太后挽歌詞五首  其三','楊億','宋','宋诗','song-poetry','','[]','德契河洲什，心依黄老書。',48,'全唐诗/poet.song.6000.json','["德契河洲什，心依黄老書。", "濯龍規誡在，飛羽豫遊疏。", "復土文園接，凝塵丙殿虚。", "蒸蒸天子孝，泣血望塗車。"]'),
('d99c8935-b0bd-404e-b1b3-7bbfa37dcd82','明德皇太后挽歌詞五首  其四','楊億','宋','宋诗','song-poetry','','[]','世載河山誓，門無恩澤侯。',48,'全唐诗/poet.song.6000.json','["世載河山誓，門無恩澤侯。", "公桑空繭館，仙藥阻蓬丘。", "愍冊藏幽壤，哀笳咽素秋。", "後宫彤管在，千古紀徽猷。"]'),
('773d675b-243f-445b-8fc2-848f1614ed6d','明德皇太后挽歌詞五首  其五','楊億','宋','宋诗','song-poetry','','[]','閫範留椒闥，神遊返玉清。',48,'全唐诗/poet.song.6000.json','["閫範留椒闥，神遊返玉清。", "魚燈照玄寢，騎吹咽重城。", "運迫升仙日，人傷喪妣情。", "宫中舊長御，行哭盡吞聲。"]'),
('05eab22c-f275-431c-8493-10614617509a','又五首  其一','楊億','宋','宋诗','song-poetry','','[]','太姒徽音盛，長秋命數崇。',48,'全唐诗/poet.song.6000.json','["太姒徽音盛，長秋命數崇。", "黄圖分丙殿，玄象應軒宫。", "記注無窮美，聲詩內助功。", "雲陽復土後，陵柏自悲風。"]'),
('9e298e0f-7e66-4d53-b839-fee3804ac9d9','又五首  其二','楊億','宋','宋诗','song-poetry','','[]','甲族傳仙李，遺言在濯龍。',48,'全唐诗/poet.song.6000.json','["甲族傳仙李，遺言在濯龍。", "後宫皆率職，外戚早辭封。", "彤管流陰教，金根盛國容。", "真遊一何遽，罷望九疑峰。"]'),
('40ea85ab-8918-4575-aa0f-eac0d457dc6a','又五首  其三','楊億','宋','宋诗','song-poetry','','[]','軒遊雲杳杳，舜孝日蒸蒸。',48,'全唐诗/poet.song.6000.json','["軒遊雲杳杳，舜孝日蒸蒸。", "椒壁還生沴，銅臺亦罷登。", "親桑寧復見，嘗藥遂無徴。", "拱木玄堂閔，凄凉烟霧凝。"]'),
('4accf62c-6969-4d87-b30b-e380b6d478b8','又五首  其四','楊億','宋','宋诗','song-poetry','','[]','外家金穴貴，曩日玉衣祥。',48,'全唐诗/poet.song.6000.json','["外家金穴貴，曩日玉衣祥。", "萬壽瑤觴舉，三朝複道長。", "小侯親爼豆，女史煥縑緗。", "遽厭人間世，乘雲歸帝鄉。"]'),
('ab4cebd1-0f93-4a05-80cd-fcdab318a1a9','又五首  其五','楊億','宋','宋诗','song-poetry','','[]','外族長安盛，尊名永樂崇。',48,'全唐诗/poet.song.6000.json','["外族長安盛，尊名永樂崇。", "初陵凄草露，舊殿閴椒風。", "鞏樹迷凶仗，周原掩壽宫。", "聖君悲望處，泪雨泣重瞳。"]'),
('109b39de-1d40-4b29-ac6b-41bfa79af229','太常樂章三十首 皇帝南郊前一日朝饗太廟奏理安曲迎神','楊億','宋','宋诗','song-poetry','','[]','肅肅清廟，昭事祖禰。',40,'全唐诗/poet.song.6000.json','["肅肅清廟，昭事祖禰。", "粢盛苾芬，四海來祭。", "皇靈格思，令容有睟。", "降福孔偕，以克永世。"]'),
('f832627a-847c-4704-9d5b-09a489c1acf2','太常樂章三十首 皇帝行奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','祼鬯漙将，賓尸在位。',40,'全唐诗/poet.song.6000.json','["祼鬯漙将，賓尸在位。", "玄德升聞，孝思光被。", "公卿庻政，傅御師氏。", "至諴感神，福禄來暨。"]'),
('c76f96f8-2de9-43f3-948c-21787e3c618b','太常樂章三十首 皇帝奠幣奏瑞文之曲','楊億','宋','宋诗','song-poetry','','[]','淳精育物，瑞木成文。',40,'全唐诗/poet.song.6000.json','["淳精育物，瑞木成文。", "元氣陶冶，非煙郁紛。", "玄貺昭格，至和所薫。", "登歌祼獻，肹蠁如聞。"]'),
('fe4530b4-b54e-439d-a9e8-d38265af88f9','太常樂章三十首 迎俎奏豐安之曲','楊億','宋','宋诗','song-poetry','','[]','麗碑割牲，以炰以烹。',40,'全唐诗/poet.song.6000.json','["麗碑割牲，以炰以烹。", "博碩肥腯，薦羞神明。", "祖考來格，享于克誠。", "如聞謦欬，式燕以寧。"]'),
('82f160b4-95e9-4e79-a258-68ea845402a7','太常樂章三十首 皇帝酌獻第一室奏大善之舞曲','楊億','宋','宋诗','song-poetry','','[]','肅肅藝祖，肇基洪源。',40,'全唐诗/poet.song.6000.json','["肅肅藝祖，肇基洪源。", "權輿光大，燕翼貽孫。", "載祀惟永，慶流後昆。", "威靈在天，顧我司存。"]'),
('f2349033-b076-4c05-8706-e7dc73918532','太常樂章三十首 酌獻第二室奏大寧之舞曲','楊億','宋','宋诗','song-poetry','','[]','文思聖祖，長發其祥。',40,'全唐诗/poet.song.6000.json','["文思聖祖，長發其祥。", "錫羡蕃衍，德厚流光。", "眷命自天，卜世聿昌。", "肅祗孝享，降福無疆。"]'),
('5649d492-5d92-4ab5-81b5-7e81a9779d45','太常樂章三十首 酌獻第三室奏大順之舞曲','楊億','宋','宋诗','song-poetry','','[]','明明我祖，積德累仁。',40,'全唐诗/poet.song.6000.json','["明明我祖，積德累仁。", "居晦匿曜，邁種惟勤。", "帝圖天錫，輝光日新。", "寢廟繹繹，昭事同寅。"]'),
('f74ec2ab-6434-49d5-8604-3ac5055442fc','太常樂章三十首 酌獻第四室奏大慶之舞曲','楊億','宋','宋诗','song-poetry','','[]','洸洸我祖，時惟鷹揚。',40,'全唐诗/poet.song.6000.json','["洸洸我祖，時惟鷹揚。", "潛德弗耀，發源靈長。", "肆類配天，永思不忘。", "来顧来享，百福是将。"]'),
('13175680-35fb-4b50-be06-8c74d67c9f36','太常樂章三十首 酌獻第五室奏大定之舞曲','楊億','宋','宋诗','song-poetry','','[]','赫赫太祖，受命于天。',40,'全唐诗/poet.song.6000.json','["赫赫太祖，受命于天。", "赤符啓運，威加八埏。", "神武戡難，功無間然。", "翼翼丕承，億萬斯年。"]'),
('9ed28fa7-5723-4379-8c67-5437d58d8459','太常樂章三十首 酌獻第六室奏大盛之舞曲','楊億','宋','宋诗','song-poetry','','[]','穆穆太宗，與天合德。',40,'全唐诗/poet.song.6000.json','["穆穆太宗，與天合德。", "昧旦丕顯，乾乾翼翼。", "敷祐下民，時帝之力。", "永懷聖神，孝思罔極。"]'),
('bbc7d65d-13a0-4f94-b4bb-469d7b065adf','太常樂章三十首 皇帝飲福酒奏禧安之曲','楊億','宋','宋诗','song-poetry','','[]','嘉栗旨酒，博腯牲牷。',40,'全唐诗/poet.song.6000.json','["嘉栗旨酒，博腯牲牷。", "神鍳孔昭，享兹吉蠲。", "夙夜毖祀，孝以奉先。", "永錫純嘏，功格于天。"]'),
('c90a7cc5-e652-4608-91d8-536e8eead468','太常樂章三十首 退文舞出奏正安之曲','楊億','宋','宋诗','song-poetry','','[]','左手執籥，右手秉翟。',20,'全唐诗/poet.song.6000.json','["左手執籥，右手秉翟。", "進旅退旅，萬舞有翼。"]'),
('b5beaaae-1203-4d66-9689-1eda60af17b2','太常樂章三十首 迎武舞入奏武功之曲','楊億','宋','宋诗','song-poetry','','[]','已象文治，乃觀武成。',20,'全唐诗/poet.song.6000.json','["已象文治，乃觀武成。", "總干山立，七德以貞。"]'),
('24565d24-beaa-429f-92e6-1ea6af093455','太常樂章三十首 亞獻終獻送神並奏理安之曲','楊億','宋','宋诗','song-poetry','','[]','神之来兮風肅然，神之去兮昇九天。',32,'全唐诗/poet.song.6000.json','["神之来兮風肅然，神之去兮昇九天。", "排凌兢兮還恍惚，羽旄紛兮蕭薌燔。"]'),
('4be3774a-a854-469d-abfb-8a06ccc2a7e8','太常樂章三十首 南郊降神奏高安之曲','楊億','宋','宋诗','song-poetry','','[]','爰卜吉土，在國之陽。',40,'全唐诗/poet.song.6000.json','["爰卜吉土，在國之陽。", "肆類于帝，錫羡無疆。", "備物致享，嘉生阜昌。", "純嘏昭答，長發其祥。"]'),
('937e58a2-e9d6-40d0-9207-0674a0e4f174','太常樂章三十首 皇帝行奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','禮備樂成，乾健天行。',20,'全唐诗/poet.song.6000.json','["禮備樂成，乾健天行。", "帝容有穆，佩玉鏘鳴。"]'),
('e7a0a35a-c30e-49dd-8512-b63e57afbf19','太常樂章三十首 皇帝奠玉幣奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','定位毖祀，告于神明。',20,'全唐诗/poet.song.6000.json','["定位毖祀，告于神明。", "嘉玉量幣，享于克誠。"]'),
('4062e0c4-8333-4d03-b9ce-8559a4e85803','太常樂章三十首 迎俎奏豐安之曲','楊億','宋','宋诗','song-poetry','','[]','有牲斯純，有爼斯陳。',20,'全唐诗/poet.song.6000.json','["有牲斯純，有爼斯陳。", "柔嘉登薦，昭事惟寅。"]'),
('92dd8213-e5fe-4893-bda4-a62967e075b4','太常樂章三十首 初獻奏禧安之曲','楊億','宋','宋诗','song-poetry','','[]','大報于帝，玄德升聞。',20,'全唐诗/poet.song.6000.json','["大報于帝，玄德升聞。", "醴齊良潔，粢盛苾芬。"]'),
('4c6df5b4-6c43-426a-9040-d51acc536522','太常樂章三十首 皇帝飲福酒奏禧安之曲','楊億','宋','宋诗','song-poetry','','[]','祀帝圓丘，九州獻力。',40,'全唐诗/poet.song.6000.json','["祀帝圓丘，九州獻力。", "禮行于郊，百神受職。", "靈祗格思，享我明德。", "天鍳孔彰，玄祉昭錫。"]'),
('cdf83cce-d02a-4875-8493-baff05cf7870','太常樂章三十首 皇帝迴仗乾元殿奏采茨之曲','楊億','宋','宋诗','song-poetry','','[]','禮成于郊，迎日之至。',40,'全唐诗/poet.song.6000.json','["禮成于郊，迎日之至。", "時乘六龍，天旋象魏。", "端門九重，虎賁萬騎。", "四夷来王，羣后輯瑞。"]'),
('d9cf9d26-ea0b-40ed-9cc7-e11219f0faec','太常樂章三十首 皇帝御殿迎升御座奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','金奏在懸，羣后在位。',40,'全唐诗/poet.song.6000.json','["金奏在懸，羣后在位。", "天威煌煌，嚮明負扆。", "玄覧穆清，弁冕端委。", "盛德日新，禮容有煒。"]'),
('ccc3aa87-fea9-4c56-9d85-a0df92f87f13','太常樂章三十首 引羣官作正安之曲','楊億','宋','宋诗','song-poetry','','[]','萬邦来同，九賓在位。',40,'全唐诗/poet.song.6000.json','["萬邦来同，九賓在位。", "奉璋薦紳，陟降庭止。", "文思安安，威儀棣棣。", "臣哉鄰哉，介爾蕃祉。"]'),
('03d3832e-fb97-470a-958e-4ff31a5da2e0','太常樂章三十首 皇帝正冬御殿文舞第一','楊億','宋','宋诗','song-poetry','','[]','八佾具陳，萬邦有奕。',40,'全唐诗/poet.song.6000.json','["八佾具陳，萬邦有奕。", "既以象功，又以觀德。", "進旅退旅，執籥秉翟。", "玄化懷柔，遠人来格。"]'),
('2d45bd7b-67e7-493c-9a7e-334847d2435d','太常樂章三十首 第二','楊億','宋','宋诗','song-poetry','','[]','閶闔天開，羣后在位。',40,'全唐诗/poet.song.6000.json','["閶闔天開，羣后在位。", "設業設虡，庭燎晰晰。", "斧扆當陽，虎賁夾陛。", "舞之蹈之，四隩來暨。"]'),
('44a5ab98-4e74-4b64-a025-5ac4f2024249','太常樂章三十首 武舞第一','楊億','宋','宋诗','song-poetry','','[]','武功既成，綴兆有翼。',40,'全唐诗/poet.song.6000.json','["武功既成，綴兆有翼。", "以節八音，以象七德。", "俁俁蹲蹲，朱干玉戚。", "發揚蹈厲，其儀不忒。"]'),
('ef9e7cc7-8194-4011-a077-aa368b0effae','太常樂章三十首 第二','楊億','宋','宋诗','song-poetry','','[]','偃伯靈臺，功成作樂。',40,'全唐诗/poet.song.6000.json','["偃伯靈臺，功成作樂。", "以昭德容，以清戎索。", "萬邦會同，羣慝簫勺。", "盡善盡美，侔彼韶箾。"]'),
('7400e5f0-0fff-429d-b701-ef3cbc631bbb','太常樂章三十首 皇帝南郊迴御樓将索扇奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','應門有翼，羽衞斯陳。',40,'全唐诗/poet.song.6000.json','["應門有翼，羽衞斯陳。", "山龍衮冕，律度聲身。", "峨峨奉璋，肅肅九賓。", "清明在躬，志氣如神。"]'),
('5eaa8c2f-6e90-435f-a034-d895d69ed3ab','太常樂章三十首 皇帝御樓奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','圜丘類上帝，六變降天神。',48,'全唐诗/poet.song.6000.json','["圜丘類上帝，六變降天神。", "禋燔禮云畢，使衛肅以陳。", "天顔瞻咫尺，王澤熙陽春。", "玉帛臻禹會，動植霑堯仁。"]'),
('bbd2a85c-3d61-451d-b3e2-f81d338dbf3f','太常樂章三十首 皇帝御樓畢奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','肆類云畢，淳熙漙将。',40,'全唐诗/poet.song.6000.json','["肆類云畢，淳熙漙将。", "雷雨麗澤，雲物効祥。", "禮容濟濟，天威煌煌。", "大賚四海，富壽無彊。"]'),
('65275b40-2481-452f-a529-1e8f85c657f3','又七首 白帝迎神高安曲','楊億','宋','宋诗','song-poetry','','[]','西顥騰精，天地始肅。',40,'全唐诗/poet.song.6000.json','["西顥騰精，天地始肅。", "盛德在金，百嘉阜育。", "彍弩射牲，築場登糓。", "明靈格思，旄罕紛属。"]'),
('f2fdca9a-5abe-4642-8798-9edf0dd48a7b','又七首 奉幣嘉安曲','楊億','宋','宋诗','song-poetry','','[]','博碩肥腯，以炰以烹。',40,'全唐诗/poet.song.6000.json','["博碩肥腯，以炰以烹。", "嘉栗旨酒，有瀰斯盈。", "殽蓛維旅，肅肅蒸蒸。", "吉蠲偹物，享于克誠。"]'),
('c4864f0d-6839-461e-9156-91b1aeedcdc1','又七首 送神理安曲','楊億','宋','宋诗','song-poetry','','[]','飈輪戾止，光燭靈壇。',20,'全唐诗/poet.song.6000.json','["飈輪戾止，光燭靈壇。", "金奏繹如，白露漙漙。"]'),
('998ceb79-0e72-49ec-a30f-7ad9a00e6232','又七首 朝日迎神','楊億','宋','宋诗','song-poetry','','[]','陽德之母，羲御寅賓。',40,'全唐诗/poet.song.6000.json','["陽德之母，羲御寅賓。", "得天久照，首兹三辰。", "正辭備物，肅肅振振。", "淪精降鑒，克享明禋。"]'),
('37211a22-5f8d-411f-9f53-4f305eb08297','又七首 奉幣','楊億','宋','宋诗','song-poetry','','[]','醴齊良潔，有牲斯純。',40,'全唐诗/poet.song.6000.json','["醴齊良潔，有牲斯純。", "大采玄冕，乃昭其文。", "王宫定位，粢盛苾芬。", "民事以叙，玄德升聞。"]'),
('bd616b33-6d1a-4755-aa21-a359aa0f1f15','又七首 送神','楊億','宋','宋诗','song-poetry','','[]','懸象著明，照臨下土。',20,'全唐诗/poet.song.6000.json','["懸象著明，照臨下土。", "降福穰穰，德施周普。"]'),
('48665097-c5ea-4e54-aa90-a549383da8e0','又七首 飲福酒廣安曲','楊億','宋','宋诗','song-poetry','','[]','簠簋既陳，吉蠲登薦。',40,'全唐诗/poet.song.6000.json','["簠簋既陳，吉蠲登薦。", "洗心防邪，肅祗祭典。", "陟降惟寅，籩豆有踐。", "百禄咸宜，淳耀丕顯。"]'),
('8cde9ff9-e3f8-4a84-bf7a-1d985f8ddd80','正冬御殿上壽樂章八首 皇帝舉壽酒宫懸奏和安之曲','楊億','宋','宋诗','song-poetry','','[]','天威煌煌，山龍采章。',40,'全唐诗/poet.song.6000.json','["天威煌煌，山龍采章。", "庭實旅百，上公奉觴。", "拱揖羣后，端委垂裳。", "永錫難老，萬壽無疆。"]'),
('98e94258-8079-43ce-8322-e6d61103edf3','正冬御殿上壽樂章八首 皇帝舉第二爵酒登歌奏祥麟之曲','楊億','宋','宋诗','song-poetry','','[]','帝圖會昌，仁獸効祥。',40,'全唐诗/poet.song.6000.json','["帝圖會昌，仁獸効祥。", "雙觡共觝，示武不傷。", "四靈爲畜，玄枵耀芒。", "公族信厚，元元阜康。"]'),
('863e9a32-0f23-491d-8364-cd7047f5e78a','正冬御殿上壽樂章八首 賜羣臣第一盞酒宫懸奏正安之曲','楊億','宋','宋诗','song-poetry','','[]','思皇多士，靖恭著位。',40,'全唐诗/poet.song.6000.json','["思皇多士，靖恭著位。", "鳴玉飛緌，鏘鏘濟濟。", "宴有折爼，以示慈惠。", "罔敢不祗，福禄来暨。"]'),
('ec32403f-8c82-480c-a858-9e9f85d80199','正冬御殿上壽樂章八首 皇帝舉第三爵酒登歌奏丹鳯之曲','楊億','宋','宋诗','song-poetry','','[]','矯矯長離，振羽来儀。',40,'全唐诗/poet.song.6000.json','["矯矯長離，振羽来儀。", "和音中律，藻翰揚輝。", "珍符沓至，品物攸宜。", "至德玄感，受天之祺。"]'),
('5eccd64b-1768-419a-9f24-d2c4393f6d2c','正冬御殿上壽樂章八首 賜羣臣第二盞酒宫懸作正安之曲','楊億','宋','宋诗','song-poetry','','[]','金奏在懸，有酒斯旨。',40,'全唐诗/poet.song.6000.json','["金奏在懸，有酒斯旨。", "顒顒卬卬，嚮明負扆。", "湛湛露斯，式宴以喜。", "佩玉蕊兮，罔不由禮。"]'),
('35e6a272-e879-41ff-ac2c-b23d3dd46eeb','正冬御殿上壽樂章八首 皇帝舉第四爵酒登歌奏河清之曲','楊億','宋','宋诗','song-poetry','','[]','德水湯湯，發源靈長。',40,'全唐诗/poet.song.6000.json','["德水湯湯，發源靈長。", "皎鑒澄澈，千年効祥。", "積厚流濕，資生阜昌。", "朝宗潤下，善利無疆。"]'),
('00fc7f2a-4561-4a0e-8e25-2f36871b2a69','正冬御殿上壽樂章八首 賜羣臣第三盞酒宫懸作正安之曲','楊億','宋','宋诗','song-poetry','','[]','酒以成禮，樂以侑食。',40,'全唐诗/poet.song.6000.json','["酒以成禮，樂以侑食。", "露湛朝陽，星環紫極。", "淑慎爾容，既飽以德。", "進退周旋，威儀抑抑。"]'),
('fe04ca46-8af4-4716-a6f8-30257c52cc99','正冬御殿上壽樂章八首 禮畢降坐宫懸奏隆安之曲','楊億','宋','宋诗','song-poetry','','[]','被衮當陽，穆穆皇皇。',40,'全唐诗/poet.song.6000.json','["被衮當陽，穆穆皇皇。", "擊石拊石，頌聲洋洋。", "和樂優洽，終然允臧。", "禮成而退，荷天百祥。"]'),
('31dd9fc4-d90e-457b-a25f-b04250af0a1f','南朝','楊億','宋','宋诗','song-poetry','','[]','五鼓端門漏滴稀，夜籖聲斷翠華飛。',64,'全唐诗/poet.song.6000.json','["五鼓端門漏滴稀，夜籖聲斷翠華飛。", "繁星曉埭聞雞度，細雨春場射雉歸。", "步試金蓮波濺襪，歌翻玉樹涕沾衣。", "龍盤王氣終三百，猶得澄瀾對敞扉。"]'),
('2a15d712-7760-4d3a-92cb-14b65bc61b38','禁中庭樹','楊億','宋','宋诗','song-poetry','','[]','直幹依金闥，繁陰覆綺楹。',48,'全唐诗/poet.song.6000.json','["直幹依金闥，繁陰覆綺楹。", "纍珠晨露重，嘒管夜蟬清。", "霜桂丹丘路，星榆北斗城。", "歲寒徒自許，蜀柳笑孤貞。"]'),
('20609bc5-6d08-450d-8623-f56f7330b97b','休沐端居有懷希聖少卿學士','楊億','宋','宋诗','song-poetry','','[]','凝塵滿榻素琴横，岸幘孤吟意未平。',64,'全唐诗/poet.song.6000.json','["凝塵滿榻素琴横，岸幘孤吟意未平。", "茗粥露芽消晝夜，柘漿雲液浣朝酲。", "水沈朱李金瓶澁，風獵幽蘭羽扇輕。", "獨憶當筵試湯餅，謫仙冰骨照人清。"]'),
('867f9fd7-b203-4fc7-9d35-ad5f067d7083','再次首唱韻和','楊億','宋','宋诗','song-poetry','','[]','碧樹銀塘接畫樓，天人誰肯降瓊輈。',64,'全唐诗/poet.song.6000.json','["碧樹銀塘接畫樓，天人誰肯降瓊輈。", "三山密信傳青雀，五日歸鞍躍紫騮。", "郢酒泛冰星弁側，吳歈倚瑟黛娥愁。", "雲峰得句懷真賞，瘦盡東陽沈隱侯。"]'),
('21ee97ba-9235-4606-9752-32425e6f339f','槿花','楊億','宋','宋诗','song-poetry','','[]','宿霧初披縠，晨霞暫照梁。',48,'全唐诗/poet.song.6000.json','["宿霧初披縠，晨霞暫照梁。", "千金經換笑，七駕未成章。", "塵暗神妃襪，衣殘侍史香。", "深情傳寶瑟，終古怨清湘。"]'),
('51165e4a-bd87-43e0-9970-779f1d107c4e','代意二首  其一','楊億','宋','宋诗','song-poetry','','[]','夢蘭前事悔成占，却羡歸飛拂畫簷。',64,'全唐诗/poet.song.6000.json','["夢蘭前事悔成占，却羡歸飛拂畫簷。", "錦瑟驚絃愁别鶴，星機促杼怨新縑。", "舞腰罷試收紈袖，博齒慵開委玉奩。", "幾夕離魂自無寐，楚天雲斷見涼蟾。"]'),
('77bdfcfd-f3c4-4db2-905b-33523b9b7828','代意二首  其二','楊億','宋','宋诗','song-poetry','','[]','短夢殘妝慘别魂，白頭詞苦怨文園。',64,'全唐诗/poet.song.6000.json','["短夢殘妝慘别魂，白頭詞苦怨文園。", "誰容五馬傳心曲，祗許雙鸞見淚痕。", "易變肯隨南地橘，忘憂虚對北堂萱。", "回文信斷衣香歇，猶憶章臺走畫轅。"]'),
('60c7bca1-120a-40fe-ac2d-9570de62ace2','漢武','楊億','宋','宋诗','song-poetry','','[]','蓬萊銀闕浪漫漫，弱水回風欲到難。',64,'全唐诗/poet.song.6000.json','["蓬萊銀闕浪漫漫，弱水回風欲到難。", "光照竹宫勞夜拜，露漙金掌費朝餐。", "力通青海求龍種，死諱文成食馬肝。", "待詔先生齒編貝，那敎索米向長安。"]'),
('45ded8e7-0995-4627-b008-ea88c5944999','館中新蟬','楊億','宋','宋诗','song-poetry','','[]','碧城青閣好追凉，高柳新聲逐吹長。',64,'全唐诗/poet.song.6000.json','["碧城青閣好追凉，高柳新聲逐吹長。", "貴伴金貂尊漢相，清含珠露怨齊王。", "蘭臺密侍初成賦，河朔歡遊正舉觴。", "雲鬢翠緌徒自許，先秋楚客已回腸。"]'),
('0a5058d2-52ae-4e6e-8b50-e27ab7021c05','夜宴','楊億','宋','宋诗','song-poetry','','[]','涼宵綺宴開，醽醁湛芳罍。',96,'全唐诗/poet.song.6000.json','["涼宵綺宴開，醽醁湛芳罍。", "鶴蓋留飛舄，珠喉怨落梅。", "薄雲齊鬢膩，流雪楚腰迴。", "巧笑傾城媚，雕章刻燭催。", "盤空珠有淚，罏冷蕙成灰。", "巾角彈棋勝，琴心促軫哀。", "醉羅驚夢枕，愁黛怯妝臺。", "風細傳疏漏，猶歌起夜來。"]'),
('f3d43fea-de5d-4e43-af02-3ac7d752f39a','鶴','楊億','宋','宋诗','song-poetry','','[]','悵望青田碧草齊，帝鄉歸路阻丹梯。',64,'全唐诗/poet.song.6000.json','["悵望青田碧草齊，帝鄉歸路阻丹梯。", "露濃漢苑宵猶警，雪滿梁園晝乍迷。", "瑞世鸞凰徒自許，繞枝烏鵲未成棲。", "終年已結雲羅恨，忍送西樓曉月低。"]'),
('0f3c8973-817a-485f-9640-09fe3b3c4e96','公子','楊億','宋','宋诗','song-poetry','','[]','夾道青樓拂綵霓，月軒宮袖按前溪。',64,'全唐诗/poet.song.6000.json','["夾道青樓拂綵霓，月軒宮袖按前溪。", "錦鱗河伯供烹鯉，金距鄰翁逐鬬雞。", "細雨墊巾過柳市，輕風側帽上銅堤。", "珊瑚擊碎牛心熱，香棗蘭芳客自迷。"]'),
('d91834e0-5cdb-43af-ad25-8fa302b0824c','舊將','楊億','宋','宋诗','song-poetry','','[]','平生苦戰憶山西，拊劍臨風氣吐霓。',64,'全唐诗/poet.song.6000.json','["平生苦戰憶山西，拊劍臨風氣吐霓。", "戟户當衢容駟馬，髯奴繞帳列生犀。", "新豐酒滿清商咽，武庫兵銷太白低。", "髀肉漸生衣带緩，早朝空聽汝南雞。"]'),
('e220c1f6-0820-49f2-a7c1-96e79f7b26ad','宣曲二十二韻','楊億','宋','宋诗','song-poetry','','[]','宣曲更衣寵，高堂薦枕榮。',264,'全唐诗/poet.song.6000.json','["宣曲更衣寵，高堂薦枕榮。", "十洲銀闕峻，三閣玉梯横。", "鸞扇裁紈製，羊車插竹迎。", "南樓看馬舞，北埭聽雞鳴。", "綵縷知延壽，靈符爲避兵。", "粟眉長占額，蠆髪俯侵纓。", "蓮菂沈寒水，芝房照畫楹。", "麝臍熏翠被，鹿爪試銀箏。", "秦鳳來何曉，燕蘭夢未成。", "絲囊晨露濕，椒壁夜寒輕。", "綺段餘霞散，瑤林密雪晴。", "流風秘舞罷，初日靚妝明。", "雷響金車度，梅殘玉管清。", "銀鐶添舊恨，瓊樹怯新聲。", "洛媛迷芝館，星妃滯斗城。", "七絲縆綠綺，六箸鬬明瓊。", "慣聽端門漏，愁聞上苑鶯。", "虚廊偏響屧，近署鎮嚴更。", "剉蘗心長苦，投籖夢自驚。", "雲波誰託意，璧月久含情。", "海闊桃難熟，天高桂漸生。", "銷魂璧臺路，千古樂池平。"]'),
('b253acef-faf2-4901-a40e-47f6d9cd7d30','赤日','楊億','宋','宋诗','song-poetry','','[]','赤日亭亭晝正賖，長風萬里憶星槎。',64,'全唐诗/poet.song.6000.json','["赤日亭亭晝正賖，長風萬里憶星槎。", "銅盤瓊蕋三危露，素綆寒漿五色瓜。", "蘭室冷光浮玉簟，柳營清吹逐金笳。", "翠微泉石終南路，千古離宮倚曙霞。"]'),
('f44c02ca-1c08-4351-acb3-479ae781410f','明皇','楊億','宋','宋诗','song-poetry','','[]','玉牒開觀檢未封，鬬雞三百遠相從。',64,'全唐诗/poet.song.6000.json','["玉牒開觀檢未封，鬬雞三百遠相從。", "紫雲度曲傳浮世，白石標年鑿半峰。", "河朔叛臣驚舞馬，渭橋遺老識真龍。", "蓬山鈿合愁通信，迴首風濤一萬重。"]'),
('9e2003a3-1ed4-482c-9bf7-2cc7e21f4ced','别墅','楊億','宋','宋诗','song-poetry','','[]','别墅過從數，當年意氣豪。',96,'全唐诗/poet.song.6000.json','["别墅過從數，當年意氣豪。", "象筵開旭日，金絡騁平臯。", "託乘爭飛蓋，銜杯更藉糟。", "麝烟凝藻梲，鱠縷落霜刀。", "雞聳花冠鬬，猿驚柘彈號。", "光風微轉蕙，露井正開桃。", "武子牛探炙，梁家兔刻毛。", "東城歸路晚，飛絮撲雲袍。"]'),
('0cf47bdf-c709-4594-8c24-15a0438e5c88','無題三首  其一','楊億','宋','宋诗','song-poetry','','[]','曲池波煖蕙風輕，頭白鴛鴦占綠萍。',64,'全唐诗/poet.song.6000.json','["曲池波煖蕙風輕，頭白鴛鴦占綠萍。", "纔斷歌雲成夢雨，斗迴笑電作嗔霆。", "湘蘭自古成幽怨，秦鳳何年入杳冥。", "不待萱蘇蠲薄怒，閒階鬬雀有遺翎。"]'),
('33309c3d-d3bb-4db7-867a-78f292d22bf4','無題三首  其二','楊億','宋','宋诗','song-poetry','','[]','合歡蠲忿亦休論，夢蝶翩翩逐怨魂。',64,'全唐诗/poet.song.6000.json','["合歡蠲忿亦休論，夢蝶翩翩逐怨魂。", "祗待傾城終未笑，不曾亾國自無言。", "風翩林葉迷歸燕，露裊池荷觸戯鴛。", "湘水東流何日竭，煙篁千古見啼痕。"]'),
('fa36cd10-198f-49aa-bebe-1e3db16af0ef','無題三首  其三','楊億','宋','宋诗','song-poetry','','[]','滿天飛絮罥游絲，釦砌苔錢晦履綦。',64,'全唐诗/poet.song.6000.json','["滿天飛絮罥游絲，釦砌苔錢晦履綦。", "北渚自應流怨淚，東鄰誰敢效顰眉。", "嫦娥桂獨成幽恨，素女絃多有剩悲。", "幾夕空機愁促杼，銀河休問報章遲。"]'),
('a4bf7b52-ebad-4c3f-871d-866b510e0420','荷花','楊億','宋','宋诗','song-poetry','','[]','絕岸疏烟合，回塘夕照和。',72,'全唐诗/poet.song.6000.json','["絕岸疏烟合，回塘夕照和。", "水仙猶度曲，川后自收波。", "銀漢橋横鵲，蘅臯襪濺羅。", "玉杯承露重，鈿扇起風多。", "翠羽芳洲近，青絲快騎過。", "石城秋信斷，搔首奈愁何。"]'),
('e33c0963-be7d-4df2-a728-ae2915d1d6e3','再賦','楊億','宋','宋诗','song-poetry','','[]','舒女清泉滿，黄姑别渚通。',72,'全唐诗/poet.song.6000.json','["舒女清泉滿，黄姑别渚通。", "巴天迷峽雨，楚澤映江楓。", "思逐鮫絲亂，香愁翠被空。", "灑從瓊蕋露，吹任石尤風。", "怨淚連疏竹，私書託過鴻。", "雙魚應共戯，休問葉西東。"]'),
('582debaa-07a4-4f8d-9623-a6ba82715397','再賦七言','楊億','宋','宋诗','song-poetry','','[]','翠幄飄香映綺襦，鈿盤清曉露成珠。',64,'全唐诗/poet.song.6000.json','["翠幄飄香映綺襦，鈿盤清曉露成珠。", "休啼爲近鮫人室，欲笑誰投玉女壺。", "雲氣乍迴巫峽夢，水嬉猶記曲池圖。", "金花却薦何人步，枉遣凌波襪縷濡。"]'),
('7be83995-b4ba-4174-8dbd-f937b614f01c','又贈一絕','楊億','宋','宋诗','song-poetry','','[]','瑤水霓旌綺宴陳，漢宮渠怨露華新。',32,'全唐诗/poet.song.6000.json','["瑤水霓旌綺宴陳，漢宮渠怨露華新。", "誰然百炬金花燭，渡襪歌梁暗落塵。"]'),
('d9ffadda-ac92-405d-ba61-bac7af44113c','梨','楊億','宋','宋诗','song-poetry','','[]','繁花如雪早傷春，千樹封侯未是貧。',64,'全唐诗/poet.song.6000.json','["繁花如雪早傷春，千樹封侯未是貧。", "漢苑漫傳盧橘賦，驪山曾識荔支塵。", "九秋青女霜添味，五夜方諸月溜津。", "楚客狂酲朝已解，水風猶自獵汀蘋。"]'),
('867aeef4-7058-40f1-b9b3-e31d64bf7f5c','淚二首  其一','楊億','宋','宋诗','song-poetry','','[]','錦字梭停掩夜機，白頭吟苦怨新知。',64,'全唐诗/poet.song.6000.json','["錦字梭停掩夜機，白頭吟苦怨新知。", "誰聞隴水迴腸後，更聽巴猿拭袂時。", "漢殿微涼金屋閉，魏宮清晚玉壺欹。", "多情不待悲秋氣，祗是傷春鬢已絲。"]'),
('b6304e17-f39b-4205-b062-9f4900fc7907','淚二首  其二','楊億','宋','宋诗','song-poetry','','[]','寒風易水已成悲，亡國何人見黍離。',64,'全唐诗/poet.song.6000.json','["寒風易水已成悲，亡國何人見黍離。", "枉是荆王疑美璞，更令楊子怨多歧。", "胡笳暮應三撾鼓，楚舞春臨百子池。", "未抵索居愁翠被，圓荷清曉露淋漓。"]'),
('c0125f17-55d8-4808-b17f-691b5e3fb746','七夕','楊億','宋','宋诗','song-poetry','','[]','清淺銀河暝靄收，漢宮還起曝衣樓。',64,'全唐诗/poet.song.6000.json','["清淺銀河暝靄收，漢宮還起曝衣樓。", "共瞻月樹憐飛鵲，誰泛星槎見飲牛。", "弄杼暫應停素手，穿針空待貺明眸。", "匆匆一夕填橋苦，不似人間有造舟。"]'),
('90ca1be8-8e8d-4c3b-9697-672077242262','成都','楊億','宋','宋诗','song-poetry','','[]','五丁力盡蜀川通，千古成都綠酎濃。',64,'全唐诗/poet.song.6000.json','["五丁力盡蜀川通，千古成都綠酎濃。", "白帝倉空蛙在井，青天路險劍爲峰。", "漫傳西漢祠神馬，已見南陽起卧龍。", "張載勒銘堪作戒，莫矜函谷一丸封。"]'),
('300ce9af-56e8-4677-b82f-577ab0c3d410','秋夜對月','楊億','宋','宋诗','song-poetry','','[]','孤雲飛隴首，顥氣滿商中。',96,'全唐诗/poet.song.6000.json','["孤雲飛隴首，顥氣滿商中。", "警鶴仙盤外，圓蟾浴殿東。", "浦寒珠有淚，巖迥樹生風。", "星彩沈榆莢，霜華襲桂叢。", "光摇銀燭亂，影射玉壺空。", "露館迷秦甸，冰臺接魏宮。", "繞枝驚暗鵲，促杼思陰蟲。", "更想離居恨，回腸幾處同。"]'),
('0b0c15f6-bf39-4125-80d8-e08635041bdc','前檻十二韻','楊億','宋','宋诗','song-poetry','','[]','前檻瓊鉤挂，深房斗帳褰。',144,'全唐诗/poet.song.6000.json','["前檻瓊鉤挂，深房斗帳褰。", "梨花飛白雪，蕙草吐青烟。", "彩鳳依珠樹，神龍護玉蓮。", "驚禽時格磔，戯蝶自翩翾。", "度繡金針澁，迷鉤畫蠟煎。", "怨眉顰翠羽，危涕迸朱絃。", "遠信三年字，空庭尺五天。", "行雲愁夢徹，初日妒妝妍。", "織爲回文亂，鬟非墮馬偏。", "風車來未定，月杵望長懸。", "寶鑑腸空斷，銀潢眼欲穿。", "曾波自東注，微意若爲傳。"]'),
('82c72fae-8951-4a6e-9131-b90da81b9e20','小園秋夕','楊億','宋','宋诗','song-poetry','','[]','鴻都歸晚直城賖，牆外連營咽暮笳。',64,'全唐诗/poet.song.6000.json','["鴻都歸晚直城賖，牆外連營咽暮笳。", "玉井梧傾猶待鳳，金塘柳密更藏鴉。", "心摇雲闕傳疏漏，目斷星津過迥槎。", "已是秋來移带眼，可堪玄髩有霜華。"]'),
('433a78d4-1805-40ce-a9c1-cbec8fc1c9fc','始皇','楊億','宋','宋诗','song-poetry','','[]','衡石量書夜漏深，咸陽宫闕杳沈沈。',64,'全唐诗/poet.song.6000.json','["衡石量書夜漏深，咸陽宫闕杳沈沈。", "滄波沃日虚鞭石，白刃凝霜枉鑄金。", "萬里長城穿地脉，八方馳道聽車音。", "儒坑未冷驪山火，三月青烟繞翠岑。"]'),
('ae2502b1-dd65-4567-a867-1058afd49681','初秋屬疾','楊億','宋','宋诗','song-poetry','','[]','潘郎已是入秋悲，屬疾猶貪桂補羸。',64,'全唐诗/poet.song.6000.json','["潘郎已是入秋悲，屬疾猶貪桂補羸。", "密雪才高閒賦筆，流波意遠託琴絲。", "離愁盡日吟青案，蠲渴何人寄紫梨。", "昨夜西樓凉月滿，清談偏憶庾元規。"]'),
('ed679ff6-aa92-46c6-839a-b876c8c68497','寄靈仙觀舒職方學士','楊億','宋','宋诗','song-poetry','','[]','綠髪郎潛不計年，却尋丹竈味靈篇。',64,'全唐诗/poet.song.6000.json','["綠髪郎潛不計年，却尋丹竈味靈篇。", "華陰學霧還成市，彭澤横琴豈要絃。", "曉案祗應餐沆瀣，夜灘誰見弄潺湲。", "須知吏隱金門客，待乞刀圭作地仙。"]'),
('ebe98538-6844-47cd-836f-31853cbe6c51','宋玉','楊億','宋','宋诗','song-poetry','','[]','蘭臺清吹拂冠緌，薙草新居對渺瀰。',64,'全唐诗/poet.song.6000.json','["蘭臺清吹拂冠緌，薙草新居對渺瀰。", "麗賦朝雲無處所，覊懷秋氣動齎咨。", "三年送目愁鄰媛，七澤迷魂怨楚詞。", "獨有江南哀句在，更傳餘恨到黄旗。"]'),
('d62fd305-48f3-46e7-9b2c-6d3e42db87ad','夕陽','楊億','宋','宋诗','song-poetry','','[]','夕籟起汀葭，秋空送目賖。',48,'全唐诗/poet.song.6000.json','["夕籟起汀葭，秋空送目賖。", "綠蕪平度鳥，紅樹遠連霞。", "水闊迷歸棹，風清咽迥笳。", "高樓未成下，天際玉鉤斜。"]'),
('7e200b7e-4f4d-4dea-aa90-7b1f9393ce65','樞密王左丞宅新菊','楊億','宋','宋诗','song-poetry','','[]','中樞多暇日，小圃占秋光。',96,'全唐诗/poet.song.6000.json','["中樞多暇日，小圃占秋光。", "雕玉新成檻，繁金乍泛觴。", "陶籬侵柳色，羅宅掩蘭芳。", "芝影連虚室，萱叢接後堂。", "傅巖猶借雨，豐嶺未飛霜。", "温樹徧分蔭，芸籖亦鬬香。", "交枝迷露井，墜葉點横塘。", "桐錄知延壽，千齡奉紫皇。"]'),
('9541ab9a-cb98-446e-b70b-059435f29869','直夜','楊億','宋','宋诗','song-poetry','','[]','繚垣嶤闕慶雲深，畫燭熏爐對擁衾。',64,'全唐诗/poet.song.6000.json','["繚垣嶤闕慶雲深，畫燭熏爐對擁衾。", "三殿夜籖傳漏箭，九秋霜籟入風琴。", "階前槁葉驚寒雨，天際孤鴻答迥砧。", "欹枕便成魚鳥夢，豈知名路有機心。"]'),
('e312a955-a055-4ce1-824d-5d1bf2dd4ba5','洞户','楊億','宋','宋诗','song-poetry','','[]','洞户飛甍接綺寮，一春幽恨寄蘭苕。',64,'全唐诗/poet.song.6000.json','["洞户飛甍接綺寮，一春幽恨寄蘭苕。", "書題枉是藏三歳，壺矢誰同賽百嬌。", "水國風霜凋社橘，仙山雲霧隔江潮。", "東城劍騎何曾出，祗爲離愁髀肉銷。"]'),
('898164a5-93a6-4a03-b61b-8b00a22a848d','柳絮','楊億','宋','宋诗','song-poetry','','[]','瓊蕊飄英逐吹繁，建章飛舞入千門。',64,'全唐诗/poet.song.6000.json','["瓊蕊飄英逐吹繁，建章飛舞入千門。", "羌人自怨殘梅曲，莊叟還迷夢蝶魂。", "漢苑風光隨獵騎，洛城花雪撲離樽。", "錦帆蔽日隋堤遠，枉逐東流箭浪翻。"]'),
('7312b2e6-50f4-4eac-b346-7a21f9a12833','與客啟明','楊億','宋','宋诗','song-poetry','','[]','越客逃名誤鑿坯，漢庭初聘碧雞才。',64,'全唐诗/poet.song.6000.json','["越客逃名誤鑿坯，漢庭初聘碧雞才。", "操心四十知無惑，削牘三千恥自媒。", "苦吟多年依洛社，賦成他日上蘭臺。", "郡齋懸榻流塵滿，七見東風落楚梅。"]'),
('b07fe529-cf0e-4eb1-81fc-22b9dff3ab83','無題','楊億','宋','宋诗','song-poetry','','[]','巫陽歸夢隔千峰，辟惡香銷翠被空。',64,'全唐诗/poet.song.6000.json','["巫陽歸夢隔千峰，辟惡香銷翠被空。", "桂魄漸虧愁曉月，蕉心不展怨春風。", "遙山黯黯眉長斂，一水盈盈語未通。", "漫託鵾絃傳恨意，雲鬟日夕似飛蓬。"]'),
('287f84a3-56a4-498b-9194-ea7a68501a00','譯經光梵大師','楊億','宋','宋诗','song-poetry','','[]','薪火滅雙林，誰傳七佛心。',144,'全唐诗/poet.song.6000.json','["薪火滅雙林，誰傳七佛心。", "譯筵香篆絕，經葉蠧魚侵。", "猊座雲雷歇，龍宮歳月深。", "青蓮流半偈，白馬度千岑。", "大士招提啟，明君羽葆臨。", "對翻天竺字，助發海潮音。", "空界花成雨，仁祠地布金。", "九旬談妙理，三接簡宸襟。", "淨社延居士，生臺集野禽。", "琅函香拂袂，奈苑樹交陰。", "文字蹄求兔，機緣芥值針。", "龍華他日會，應記洛生吟。"]'),
('9ac50513-ecc3-49db-aadf-575f86ead97b','霜月','楊億','宋','宋诗','song-poetry','','[]','月夕露爲霜，心知厭獨房。',48,'全唐诗/poet.song.6000.json','["月夕露爲霜，心知厭獨房。", "吟殘猶擁鼻，望極自回腸。", "鬢減前秋綠，衣消外國香。", "星津誰待報，織素未成章。"]'),
('fc8b374a-8786-4e14-aab5-c8637f8ab39f','此夕','楊億','宋','宋诗','song-poetry','','[]','此夕秋風獵敗荷，玉鉤斜影轉庭柯。',64,'全唐诗/poet.song.6000.json','["此夕秋風獵敗荷，玉鉤斜影轉庭柯。", "鮫人淚有千珠迸，楚客愁添萬斛多。", "錦里琴心誰滌器，石城桃葉自横波。", "程鄉酒薄難成醉，带眼頻移奈瘦何。"]'),
('fb56991c-651b-41fa-92b4-1311c3b924ad','劉校理屬疾','楊億','宋','宋诗','song-poetry','','[]','北窗風勁雪雲繁，移疾端居避世喧。',64,'全唐诗/poet.song.6000.json','["北窗風勁雪雲繁，移疾端居避世喧。", "載酒誰過楊子宅，張羅休署翟公門。", "多才最許飄飄氣，少别還銷黯黯魂。", "促爾徘徊憶真賞，遠天新月照黄昏。"]'),
('7f424f9c-ff95-46c3-b7ce-80d8281a9f6e','勸石集賢飲','楊億','宋','宋诗','song-poetry','','[]','日上三竿宿霧披，章臺走馬帽簷欹。',64,'全唐诗/poet.song.6000.json','["日上三竿宿霧披，章臺走馬帽簷欹。", "祗傳祖席觴無算，肯顧尚書對有期。", "芸省繙經終寂寞，柳隄飛鞚好追隨。", "靈均不醉真何益，千古離騷怨楚詞。"]'),
('ea909db0-e80d-4e46-bc46-e2f397f9e7e0','即日','楊億','宋','宋诗','song-poetry','','[]','急雨度前軒，池荷相對翻。',48,'全唐诗/poet.song.6000.json','["急雨度前軒，池荷相對翻。", "峰奇雲待族，蹊闇李無言。", "掩鼻生愁詠，披襟爽醉魂。", "一廛今已廢，猶戀漢庭恩。"]'),
('8e2d884d-b0fd-45e3-b3ed-408bc3b66c17','燈夕寄獻內翰虢略公','楊億','宋','宋诗','song-poetry','','[]','瓊樓十二玉梯斜，乾鵲南飛轉斗車。',64,'全唐诗/poet.song.6000.json','["瓊樓十二玉梯斜，乾鵲南飛轉斗車。", "有客郢中歌白雪，幾人天上醉流霞。", "金吾緹騎章臺陌，素女繁絃太帝家。", "秦痔未痊齊閣掩，夢回宫樹已啼鴉。"]'),
('7d7abe77-8a4d-46ae-a08c-785f2cef3fa8','李舍人獨直','楊億','宋','宋诗','song-poetry','','[]','閣鳳巢高拂綵霓，玉芝香雜武都泥。',64,'全唐诗/poet.song.6000.json','["閣鳳巢高拂綵霓，玉芝香雜武都泥。", "十行漢札如絲出，六幕堯天倚杵低。", "露井冰銷垂素綆，仙莖日轉射璇題。", "赫蹄雲落知誰見，餘力何妨頌碧雞。"]'),
('abedd6e4-ebe8-475d-81c9-0aceecef501c','無題二首  其一','楊億','宋','宋诗','song-poetry','','[]','銅盤蕙草起青烟，斗帳香囊四角懸。',64,'全唐诗/poet.song.6000.json','["銅盤蕙草起青烟，斗帳香囊四角懸。", "沈約愁多徒自瘦，相如意密有誰傳。", "金塘雨過猶疑夢，翠袖風迴祗恐仙。", "日上秦樓休寄詠，東方千騎擁輜軿。"]'),
('20d17b6e-dfc0-44d0-af0c-913235ce4c21','無題二首  其二','楊億','宋','宋诗','song-poetry','','[]','露冷星翻月上絃，九枝銀燭照金鈿。',64,'全唐诗/poet.song.6000.json','["露冷星翻月上絃，九枝銀燭照金鈿。", "應知韓掾偷香夜，猶記潘郎擲果年。", "天上明河雖可望，苑中高柳未經眠。", "烏啼人散青樓曉，堂下輕風轉莢錢。"]'),
('7f1e4af9-ba0a-46ab-85af-35980de5ba7e','懷舊居','楊億','宋','宋诗','song-poetry','','[]','武夷仙穴近吾廬，鬬鴨闌摧菌閣虚。',64,'全唐诗/poet.song.6000.json','["武夷仙穴近吾廬，鬬鴨闌摧菌閣虚。", "千匹歳儲妨種橘，百金春事廢觀漁。", "北山煙霧迷歸轍，南陌風塵化客裾。", "堂上金絲應已歇，豈惟蘭菊舊叢疏。"]'),
('72cc47a1-185b-4771-8405-010455fcdae8','偶懷','楊億','宋','宋诗','song-poetry','','[]','銀礫飛晴霰，蘭英湛凍膠。',48,'全唐诗/poet.song.6000.json','["銀礫飛晴霰，蘭英湛凍膠。", "年光侵葆髪，春恨寄雲袍。", "燕重銜泥遠，鴻驚避弋高。", "平生林壑志，誤佩呂虔刀。"]'),
('88b12bc4-41b3-4dbd-99df-538c236f059c','許洞歸吳中','楊億','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','春渚歸艎不暫留，青絲如葆恐逢秋。',64,'全唐诗/poet.song.6000.json','["春渚歸艎不暫留，青絲如葆恐逢秋。", "騷人已得江山助，賦客終陪霰雪遊。", "三徑未荒休歎鵩，十漿先饋定驚鷗。", "洞庭霜橘疁田粟，歳計猶堪比徹侯。"]'),
('44edd68d-11bb-4df6-9f3f-50fe26bc8704','上巳玉津園賜宴','楊億','宋','宋诗','song-poetry','','[]','禊飲逢元巳，春遊盛舞雩。',72,'全唐诗/poet.song.6000.json','["禊飲逢元巳，春遊盛舞雩。", "流杯傳楚俗，飫賜出堯厨。", "玉樹天開苑，銀潢水貫都。", "肆筵環曲沼，飛蓋塞交衢。", "洛邑聲詩逸，蘭亭歳月徂。", "顔王有遺韻，待子一操觚。"]'),
('f0a0d1d4-648e-46dc-addc-7108bfea7f07','致齋太一宮','楊億','宋','宋诗','song-poetry','','[]','漢帝祈年館，威神法太微。',96,'全唐诗/poet.song.6000.json','["漢帝祈年館，威神法太微。", "赤章修秘祝，盤石拂仙衣。", "雉雊靈光發，鸞歌彩霧霏。", "霓旌飄夕吹，瑤草泛春暉。", "瓊屑晨杯滿，芝苖晝茹肥。", "象樽猶一獻，鳬舄自雙飛。", "天迥飇輪度，宵殘素瑟希。", "回看葱鬱處，佳氣接彤闈。"]'),
('adbd2292-83d4-4f2d-afc3-5c849ba5d1e9','直夜二首  其一','楊億','宋','宋诗','song-poetry','','[]','月魄生宵暈，風烏送晚凉。',48,'全唐诗/poet.song.6000.json','["月魄生宵暈，風烏送晚凉。", "飛蠅隨鏤管，浮蟻溢清觴。", "負郭春耕廢，鈞天曉夢長。", "玉籖聲未斷，落宿半宮牆。"]'),
('1a95a24a-f174-47ab-a18a-c16498611055','直夜二首  其二','楊億','宋','宋诗','song-poetry','','[]','罏銷香篆靄餘芬，晏坐氍毹日易曛。',64,'全唐诗/poet.song.6000.json','["罏銷香篆靄餘芬，晏坐氍毹日易曛。", "虎圈微凉生夕籟，鶴天新霽見歸雲。", "通中夢穩春寒薄，肅唱聲沈夜漏分。", "誤濯塵纓成底事，巖阿千古有移文。"]'),
('c696fadf-584a-4742-9373-81844a5b5f45','櫻桃','楊億','宋','宋诗','song-poetry','','[]','離宮時薦罷，樂府艶歌新。',72,'全唐诗/poet.song.6000.json','["離宮時薦罷，樂府艶歌新。", "石髓凝秦洞，珠胎剖漢津。", "三桃聊竝列，百果獨先春。", "清籞來君賜，雕盤助席珍。", "甘餘應受和，圓極豈能神。", "楚客便羊酪，歸期負紫蓴。"]'),
('50202363-68de-41dc-b57d-02f4638ebae0','暑詠寄梅集賢','楊億','宋','宋诗','song-poetry','','[]','點綴鮮雲紫宙寛，微風淅淅起霜紈。',64,'全唐诗/poet.song.6000.json','["點綴鮮雲紫宙寛，微風淅淅起霜紈。", "魏臺清暑開冰井，漢殿延年啜露盤。", "天外一飛期汗漫，水邊千畝憶檀欒。", "流波意密知音少，可得延陵爲試觀。"]'),
('9bb8661a-234b-43bc-8702-a52dd72a7045','苦熱','楊億','宋','宋诗','song-poetry','','[]','極目長天度鳥稀，纖蘿不動轉晨暉。',64,'全唐诗/poet.song.6000.json','["極目長天度鳥稀，纖蘿不動轉晨暉。", "已裁圓月班姬扇，更換輕雲子産衣。", "河朔一時觴對舉，臨淄萬井汗交揮。", "冰丸雪散成虚設，欲借飇輪羾紫微。"]'),
('3843898c-b237-4f87-b9c4-34b412632443','屬疾','楊億','宋','宋诗','song-poetry','','[]','積日勞無補，彌天疾未瘳。',96,'全唐诗/poet.song.6000.json','["積日勞無補，彌天疾未瘳。", "馬卿非避事，盛憲自多憂。", "目眩花成果，心驚蟻鬬牛。", "豳冰那浣熱，洛笛更生愁。", "拂枕窗風度，穿簾隙日流。", "唾壺從已缺，博齒亦慵投。", "發篋尋桐錄，支頤動越謳。", "平生江海志，夕夢繞滄洲。"]'),
('3699792a-3da2-4fd0-be1c-de17c54b92bb','因人話建溪舊居','楊億','宋','宋诗','song-poetry','','[]','聽話吾廬憶翠微，石層懸瀑濺巖扉。',64,'全唐诗/poet.song.6000.json','["聽話吾廬憶翠微，石層懸瀑濺巖扉。", "風和林籟披襟久，月射溪光擊浪歸。", "露畹荒凉迷草带，雨牆陰濕長苔衣。", "終年已結南枝戀，更羡高鴻避弋飛。"]'),
('231115e9-36b9-4004-b52c-1048344adaed','清風十韻','楊億','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','素魄離箕舌，鳴鳶載錦綢。',120,'全唐诗/poet.song.6000.json','["素魄離箕舌，鳴鳶載錦綢。", "微凉生玉宇，餘韻泛蘭臯。", "竿轉相烏數，厨摇萐莆勞。", "渚蘋偏靃靡，苑樹更蕭騷。", "五斗酲初析，三年翼自高。", "陶窗時拂袵，楚榭正揮毫。", "塵篋悲鸞扇，雲帆戒鷺濤。", "洞庭驚木葉，騎省歎霜毛。", "勢好摶羊角，心終憶蟹螯。", "泠然知有待，仙寇異吾曹。"]'),
('98a0fd94-17e0-446a-b2d7-7b99313ed4d1','戊申年七夕五絕  其一','楊億','宋','宋诗','song-poetry','','[]','六幕西迴斗轉車，鮮雲點綴玉鉤斜。',32,'全唐诗/poet.song.6000.json','["六幕西迴斗轉車，鮮雲點綴玉鉤斜。", "天孫已渡黄姑渚，阿母還來漢帝家。"]'),
('470c916b-f03b-4f6c-b9de-e72b2471f863','戊申年七夕五絕  其二','楊億','宋','宋诗','song-poetry','','[]','明河左界鵲南飛，漢苑高樓正曝衣。',32,'全唐诗/poet.song.6000.json','["明河左界鵲南飛，漢苑高樓正曝衣。", "一夕匆匆停弄杼，誰將錦石暫支機。"]'),
('67b32dbc-cd49-4239-961e-b6a21eb0e570','戊申年七夕五絕  其三','楊億','宋','宋诗','song-poetry','','[]','蘭夜沈沈鵠漏移，羽車雲幄有佳期。',32,'全唐诗/poet.song.6000.json','["蘭夜沈沈鵠漏移，羽車雲幄有佳期。", "應將機上回文縷，分作人間乞巧絲。"]'),
('a7378441-28bc-43e7-8309-09e26161bdaa','戊申年七夕五絕  其四','楊億','宋','宋诗','song-poetry','','[]','神女歡娛一夕休，月娥孀獨已千秋。',32,'全唐诗/poet.song.6000.json','["神女歡娛一夕休，月娥孀獨已千秋。", "爭如靈匹年年會，莫恨牛津隔鳳輈。"]'),
('dbcdc7cf-9504-4405-a3d3-1e6d266cbaf4','戊申年七夕五絕  其五','楊億','宋','宋诗','song-poetry','','[]','玉女壺傾笑電頻，白榆晴影接星津。',32,'全唐诗/poet.song.6000.json','["玉女壺傾笑電頻，白榆晴影接星津。", "神光奕奕雲容薄，誰見凌波襪起塵。"]'),
('4c2f19e6-f58a-42f3-9766-1ebbddb1784b','秋夕池上','楊億','宋','宋诗','song-poetry','','[]','蓮塘带弋林，清吹滌煩襟。',48,'全唐诗/poet.song.6000.json','["蓮塘带弋林，清吹滌煩襟。", "泉咽猶鳴玉，臺傾舊築金。", "僵桃蟲自蠧，怪石蘚交侵。", "此夜悲秋客，烟蛩亦伴吟。"]'),
('3a952445-0f1d-4841-8007-279debe5d045','偶作','楊億','宋','宋诗','song-poetry','','[]','翹車蕊佩謁明光，禁籞多年費稻粱。',69,'全唐诗/poet.song.6000.json','["翹車蕊佩謁明光，禁籞多年費稻粱。", "祗羡泥塗龜曵尾，翻嫌霧雨豹成章。", "鳴鳩春{殻几=子}先疇廢，寒蝶秋菘老圃荒。", "歸計未成芳節晚，更憂禽鹿頓纓狂。"]'),
('fd963472-75cb-444c-b1ab-d2115ccb0490','螢','楊億','宋','宋诗','song-poetry','','[]','爽籟生遙圃，斜暉落半岑。',72,'全唐诗/poet.song.6000.json','["爽籟生遙圃，斜暉落半岑。", "微芒浮草際，零亂起牆陰。", "武子窗塵積，隋家苑樹深。", "燈光透疏隙，珠彩射清潯。", "野燐宵爭出，星榆曉共沈。", "長門秋漏永，偏照淚涔涔。"]'),
('ae43e178-3271-485f-b710-fc4828a6f978','送覲道人歸故','楊億','宋','宋诗','song-poetry','','[]','跡寄浮屠教，心将汗漫遊。',120,'全唐诗/poet.song.6000.json','["跡寄浮屠教，心将汗漫遊。", "無眠長達曙，却立動經秋。", "秘訣神仙授，靈苖洞壑求。", "誅茅探虎穴，投杖涸龍湫。", "丹熟爐應冷，禪餘室更幽。", "登山不累息，入夏亦重裘。", "名已標真籍，身猶隱沃洲。", "逍遙訪巖穴，迢遞别林丘。", "徧覽縉雲境，還浮一葉舟。", "三千功欲滿，鶴馭恐難留。"]'),
('92bab4dc-7f86-4a48-8b82-33725140ceff','送高學士知越','楊億','宋','宋诗','song-poetry','','[]','萬壑千巖古剡中，錦旗朱轂此臨戎。',64,'全唐诗/poet.song.6000.json','["萬壑千巖古剡中，錦旗朱轂此臨戎。", "酒廚歲取公田秫，樵舸朝分射的風。", "閣吏蒸青藏史牘，席賓簪玳奉談叢。", "海邦訟息多幽賞，禹穴奇書爲一空。"]'),
('f654ed29-3ba6-46c3-9213-43255fcd457d','喜朝京闕','楊億','宋','宋诗','song-poetry','','[]','七閩波渺邈，雙闕氣岧嶢。',36,'全唐诗/poet.song.6000.json','["七閩波渺邈，雙闕氣岧嶢。", "曉登雲外嶺，夜渡月中潮。", "願秉清忠節，終身立聖朝。"]'),
('a91783a5-14ba-4c9f-ad66-7be0e35af705','貽諸館閣','楊億','宋','宋诗','song-poetry','','[]','聞戴宮花滿鬢紅，上林絲筦侍重瞳。',32,'全唐诗/poet.song.6000.json','["聞戴宮花滿鬢紅，上林絲筦侍重瞳。", "蓬萊咫尺無因到，始信仙凡迥不同。"]'),
('b685630f-ffbb-44f5-a3e7-f2d9ff9a6654','傀儡','楊億','宋','宋诗','song-poetry','','["\u548f\u7269", "\u8bbd\u523a", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u548f\u7269\u8bd7"]','鮑老當筵笑郭郎，笑他舞袖太郎當。',32,'全唐诗/poet.song.6000.json','["鮑老當筵笑郭郎，笑他舞袖太郎當。", "若教鮑老當筵舞，轉更郎當舞袖長。"]'),
('44066509-7894-4e0c-becb-7881129f4245','登樓','楊億','宋','宋诗','song-poetry','','["\u540d\u697c\u3001\u5e99\u5b87", "\u7eaa\u6e38", "\u5199\u666f"]','危樓高百尺，手可摘星辰。',24,'全唐诗/poet.song.6000.json','["危樓高百尺，手可摘星辰。", "不敢高聲語，恐驚天上人。"]'),
('a1aec188-ccd8-441b-abd2-d5da52c3899a','禁直','楊億','宋','宋诗','song-poetry','','[]','鳳樓鴛瓦蟾波濕，衆籟聲沈百蟲蟄。',160,'全唐诗/poet.song.6000.json','["鳳樓鴛瓦蟾波濕，衆籟聲沈百蟲蟄。", "仙盤雲表露成霜，何人夜半牛衣泣。", "芝泥香熟封詔書，河漢西傾移斗車。", "陰風摵摵起庭樹，寒澌戛戛鳴宫渠。", "千廬迭唱傳宵警，海山鼇背蓬壺頂。", "金釭珠網結綺錢，玉井銀牀垂素綆。", "前席受釐詢碩生，觀書百斤須中程。", "投籖乍應嚴鼓節，求衣誤聽蒼蠅聲。", "渴烏漏盡繁星曙，魚鑰建章開萬户。", "初日曈曨艷屋梁，鳴鞭一聲下天路。"]'),
('90744546-0629-43c2-99af-c70b7028efd2','至郡累旬惡風','楊億','宋','宋诗','song-poetry','','[]','鄧禹功曹器，馬周令長才。',48,'全唐诗/poet.song.6000.json','["鄧禹功曹器，馬周令長才。", "叨臨萬室郡，驟致五風災。", "大木行將拔，繁雲黯不開。", "自知蒙闇極，民吏竊相咍。"]'),
('a87bcae2-1cbb-4a49-9844-6bef92eb3be3','獄多重囚','楊億','宋','宋诗','song-poetry','','[]','鐵鎖銀鐺衆，金科伏念頻。',48,'全唐诗/poet.song.6000.json','["鐵鎖銀鐺衆，金科伏念頻。", "絕聞空獄奏，深愧片言人。", "清潁黄公接，甘棠邵伯鄰。", "懷賢不能繼，多辟豈由民。"]'),
('f2b560be-36c7-4046-9e34-c850574cc6c7','民牛多疫死','楊億','宋','宋诗','song-poetry','','[]','南海逸風如失性，東吳喘月不逢醫。',64,'全唐诗/poet.song.6000.json','["南海逸風如失性，東吳喘月不逢醫。", "一元祀典古所重，九穀民天命在斯。", "真相柅車寜致問，族庖更刃亦焉施。", "炎神厲鬼爭爲虐，渡虎消蝗復是誰。"]'),
('a6a181f7-af7e-49f3-b218-58147ca0bcaf','奉和御製中和','楊億','宋','宋诗','song-poetry','','[]','佳節更春晦，長標令甲名。',48,'全唐诗/poet.song.6000.json','["佳節更春晦，長標令甲名。", "天淵搖綠浪，仙杏吐丹榮。", "連皷將驚蟄，高枝已變鶯。", "雲謠傳下土，漢曲被新聲。"]'),
('d54bb5cf-2592-4f95-95ed-f617e9bf3b5e','七夕','楊億','宋','宋诗','song-poetry','','[]','天開翠帟暮氛消，盤薰朱煤惜易飄。',64,'全唐诗/poet.song.6000.json','["天開翠帟暮氛消，盤薰朱煤惜易飄。", "月出南樓蟾桂長，笙來北里鳳簧調。", "巧蛛露濕千絲網，倦鵲波橫一夕橋。", "曬腹曝衣傳故俗，阮庭布犢若爲標。"]'),
('121cd138-371a-4630-9ee5-938f171bcbb1','上元','楊億','宋','宋诗','song-poetry','','[]','天碧銀河欲下來，月華如水浸樓臺。',32,'全唐诗/poet.song.6000.json','["天碧銀河欲下來，月華如水浸樓臺。", "誰將萬斛金蓮之，撤向星都五夜開。"]'),
('eb207727-af6a-417d-9d08-6fd3e7ad31d4','櫻桃','楊億','宋','宋诗','song-poetry','','[]','團於火色貝，燦極日光珠。',48,'全唐诗/poet.song.6000.json','["團於火色貝，燦極日光珠。", "西海瑤池苑，曾城寶樹區。", "鳳幘生猶嫩，龍睛未脫枯。", "彤標與霞彩，紫府閟雲腴。"]'),
('d17baa20-380b-4b00-89a8-b97f127f6b33','送張無夢歸天台山','楊億','宋','宋诗','song-poetry','','[]','小隱瓊臺布水邊，獨披金誥味重玄。',64,'全唐诗/poet.song.6000.json','["小隱瓊臺布水邊，獨披金誥味重玄。", "晨鳬化舄趨軒室，秋鷺翻濤逐楚船。", "養鶴七年知善舞，種芝三秀舊成田。", "飇輪不駐勞宸眷，犀管裁章與世傳。"]'),
('18bc0bce-50f3-4812-b64d-3f090c29329b','送僧歸天寧萬年禪院','楊億','宋','宋诗','song-poetry','','[]','暫別雲山幾度瓜，方袍初日耀蘭芽。',64,'全唐诗/poet.song.6000.json','["暫別雲山幾度瓜，方袍初日耀蘭芽。", "吟詩池上生春草，說法庭中散寶華。", "桂檝去依隨岸柳，松軒歸賞赤城霞。", "御書滿篋新頒得，應向三吳到處誇。"]'),
('4893e252-1aa9-4319-b603-42dbe72cdea2','送錢易','楊億','宋','宋诗','song-poetry','','[]','霜葉飛梁苑，風檣指上饒。',24,'全唐诗/poet.song.6000.json','["霜葉飛梁苑，風檣指上饒。", "江山應有助，別恨寄蘭苕。"]'),
('38a1880d-449f-4943-ba3b-f832e3f2f489','柳噪竹','楊億','宋','宋诗','song-poetry','','[]','好在碧壇灣，叢底度歲寒。',48,'全唐诗/poet.song.6000.json','["好在碧壇灣，叢底度歲寒。", "何堪栽鳳律，祇好製魚竿。", "拂水煙稍潤，含風劍葉攢。", "芳蔭聊奉庇，君試仰天看。"]'),
('a0fddea9-4c9b-4bfd-94dd-5f5411bcbf91','竹答柳','楊億','宋','宋诗','song-poetry','','[]','我自虛心者，君能百尺芳。',48,'全唐诗/poet.song.6000.json','["我自虛心者，君能百尺芳。", "未聞凌雪秀，唯解刺天長。", "葉密招禽宿，皮枯任蠹藏。", "他年丹穴鳳，恐不集垂楊。"]'),
('6c1e62d4-6cca-4502-9f38-eaa5b70ee358','書懷寄劉五','楊億','宋','宋诗','song-poetry','','[]','世事悠悠未遽央，虛名真意兩相忘。',64,'全唐诗/poet.song.6000.json','["世事悠悠未遽央，虛名真意兩相忘。", "休誇失馬曾歸塞，未省牽牛解服箱。", "四客高風驚楚漢，五君新詠棄山王。", "秋來安有漁樵夢，多在箕峰潁水傍。"]'),
('c7e39fb8-07e0-484b-9d46-e312009e100d','洛意','楊億','宋','宋诗','song-poetry','','[]','蘅臯駐馬獨依依，寄恨微波带減圍。',64,'全唐诗/poet.song.6000.json','["蘅臯駐馬獨依依，寄恨微波带減圍。", "淚迹不成雙玉筯，身輕誰賦六銖衣。", "穿針靜夜星榆出，擺手清晨雪絮飛。", "目斷風簾舊巢燕，新看先傍杏梁歸。"]'),
('c92c9617-76a2-48ad-9b18-a4c2fc37ae7f','白蓮','楊億','宋','宋诗','song-poetry','','[]','昨夜三更裏，嫦娥墜玉簪。',24,'全唐诗/poet.song.6000.json','["昨夜三更裏，嫦娥墜玉簪。", "馮夷不敢受，捧出碧波心。"]'),
('b7de3ba7-a3c6-4de9-b72e-4fb5c15ea4cf','昇山','楊億','宋','宋诗','song-poetry','','[]','層巒連近郭，占勝有招提。',48,'全唐诗/poet.song.6000.json','["層巒連近郭，占勝有招提。", "宿霧昏金像，飛泉濺石梯。", "鐘聲空谷答，塔影亂雲齊。", "千騎時來此，尋幽獨杖藜。"]'),
('2f5a5085-6b09-4e77-bd20-1b4ee182821b','贈張季常','楊億','宋','宋诗','song-poetry','','[]','疊巘參差翠繞門，雕梁賀燕自成羣。',64,'全唐诗/poet.song.6000.json','["疊巘參差翠繞門，雕梁賀燕自成羣。", "殺雞日夕期嘉客，種竹寒暄對此君。", "且向東臯輸黍稷，便應北闕降玄纁。", "子真漫說耕巖石，不奈聲名四遠聞。"]'),
('518d016c-55f2-400c-bd4c-6e9c9e75c66f','留別','楊億','宋','宋诗','song-poetry','','[]','夢筆山前君別我，下沙橋上我思君。',32,'全唐诗/poet.song.6000.json','["夢筆山前君別我，下沙橋上我思君。", "黄昏更過西陽嶺，滿目青山與白雲。"]'),
('648b905b-4d0c-4ceb-afe8-fd7a609bd653','獨懷','楊億','宋','宋诗','song-poetry','','[]','獨依青桐聽鼓聲，參旗歷落上三更。',64,'全唐诗/poet.song.6000.json','["獨依青桐聽鼓聲，參旗歷落上三更。", "涼風捲雨忽中斷，明月背雲還倒行。", "賴有清吟消意馬，豈無美酒破愁城。", "是非人世何須較，方外吾師阮步兵。"]'),
('67825ccb-0f79-47e4-b0d4-e94784b291d8','詩一首','楊億','宋','宋诗','song-poetry','','[]','漚生稱漚滅，二法本來齊。',24,'全唐诗/poet.song.6000.json','["漚生稱漚滅，二法本來齊。", "要識真歸處，趙州東院西。"]'),
('f393362d-3544-4a2d-aeea-c0e3d3400cd2','詠華林書院','楊億','宋','宋诗','song-poetry','','[]','聞說華林院，名將闕里偕。',120,'全唐诗/poet.song.6000.json','["聞說華林院，名將闕里偕。", "生徒似東魯，書籍勝西齋。", "俎豆儒風盛，塤箎樂韻諧。", "門閭雙桂茂，編秩九流排。", "講學搴紗幕，題詩掛粉牌。", "荀陳傳舊族，游夏結同儕。", "紅實洲生橘，清陰世種槐。", "夜蟾穿戶牖，晴瀑瀉巖崖。", "遠客來千里，新恩出兩階。", "橫經定何日，凭此寄幽懷。"]'),
('fb7f18ce-e1eb-4d29-83c6-7aecde2ee92f','靈嶽','楊億','宋','宋诗','song-poetry','','[]','靈嶽標真牒，孤峰入紫氛。',48,'全唐诗/poet.song.6000.json','["靈嶽標真牒，孤峰入紫氛。", "藤蘿暗仙穴，猿鳥駭人羣。", "白道千年在，縣流萬壑分。", "漢壇秋蘚駁，曾祀武夷君。"]'),
('8f401ed0-c67f-4fd9-b539-7b4929b42b30','句  其一','楊億','宋','宋诗','song-poetry','','[]','眼中是面前人。',7,'全唐诗/poet.song.6000.json','["眼中是面前人。"]'),
('05b34d2f-e3d7-421e-9422-731b2790ef6c','句  其二','楊億','宋','宋诗','song-poetry','','[]','關榆漸落邊鴻過，誰勸劉郎酒十分。',16,'全唐诗/poet.song.6000.json','["關榆漸落邊鴻過，誰勸劉郎酒十分。"]'),
('7625a7ed-61c2-4ef5-adeb-22ab23e6d9d4','句  其三','楊億','宋','宋诗','song-poetry','','[]','峭帆橫渡官橋柳，疊鼓警飛海岸鷗。',16,'全唐诗/poet.song.6000.json','["峭帆橫渡官橋柳，疊鼓警飛海岸鷗。"]'),
('9df74dd5-9589-4057-bbc3-d8b88f6dda39','句  其四','楊億','宋','宋诗','song-poetry','','[]','前瞰琵琶洲，後枕思禪寺。',12,'全唐诗/poet.song.6000.json','["前瞰琵琶洲，後枕思禪寺。"]'),
('1d649f30-99bb-46d1-aa9a-68f60cb43216','句  其五','楊億','宋','宋诗','song-poetry','','[]','連天漢水鴨頭春，樂府銅鞮艷曲新。',16,'全唐诗/poet.song.6000.json','["連天漢水鴨頭春，樂府銅鞮艷曲新。"]'),
('95ce34f7-99d4-4ec5-a1a8-71cdd012f41a','句  其六','楊億','宋','宋诗','song-poetry','','[]','渡海鯨波息，登山豹霧清。',12,'全唐诗/poet.song.6000.json','["渡海鯨波息，登山豹霧清。"]'),
('cf1bf4f3-8771-4185-876e-60910861bfe0','句  其七','楊億','宋','宋诗','song-poetry','','[]','不把一言裨萬乘，祇叉雙手揖三公。',16,'全唐诗/poet.song.6000.json','["不把一言裨萬乘，祇叉雙手揖三公。"]'),
('f967e582-7057-4776-bbaf-609664f82fb9','句  其八','楊億','宋','宋诗','song-poetry','','[]','世人何人最得閑，司諫拂衣歸華山。',16,'全唐诗/poet.song.6000.json','["世人何人最得閑，司諫拂衣歸華山。"]'),
('e534cd56-5fc5-411c-89c4-9821a3e9124d','句  其九','楊億','宋','宋诗','song-poetry','','[]','江南堤柳拂人頭，李白題詩徧酒樓。',16,'全唐诗/poet.song.6000.json','["江南堤柳拂人頭，李白題詩徧酒樓。"]'),
('7f2b2b75-808a-4855-bf49-f919d4bf0754','句  其一○','楊億','宋','宋诗','song-poetry','','[]','獨自憑闌干，衣襟生暮寒。',12,'全唐诗/poet.song.6000.json','["獨自憑闌干，衣襟生暮寒。"]'),
('c03279a3-d115-4ef4-99c3-226ffcaf29b1','句  其一一','楊億','宋','宋诗','song-poetry','','[]','相公坐處幕瞞天。',8,'全唐诗/poet.song.6000.json','["相公坐處幕瞞天。"]'),
('97c2b155-dc2b-4203-a590-02328e26361f','句  其一二','楊億','宋','宋诗','song-poetry','','[]','禰狂無自屈岑牟。',8,'全唐诗/poet.song.6000.json','["禰狂無自屈岑牟。"]'),
('3cda3b21-6dca-4e7d-8c68-5427425a0e1b','句  其一三','楊億','宋','宋诗','song-poetry','','[]','愁裏酒盃浮太白，夢回香塚上孤青。',16,'全唐诗/poet.song.6000.json','["愁裏酒盃浮太白，夢回香塚上孤青。"]'),
('423df3d4-ceda-4887-8a05-0a80f1dc78aa','句  其一四','楊億','宋','宋诗','song-poetry','','[]','仙盤露冷蛛絲濕，綺閣香風風吹傳。',16,'全唐诗/poet.song.6000.json','["仙盤露冷蛛絲濕，綺閣香風風吹傳。"]'),
('c7fa7f2c-cbc5-4bce-b6af-96506ceab5b1','句  其一五','楊億','宋','宋诗','song-poetry','','[]','巍巍百尺樓上槐，夾樓清密葉已繁。',16,'全唐诗/poet.song.6000.json','["巍巍百尺樓上槐，夾樓清密葉已繁。"]'),
('fde17f03-ac18-4531-a3c4-7a78f9e83c08','句  其一六','楊億','宋','宋诗','song-poetry','','[]','好把長鞭便一揮。',8,'全唐诗/poet.song.6000.json','["好把長鞭便一揮。"]'),
('696e142a-8e5f-4df5-b95e-19cd60c0dd8c','雙蓮堂','楊備','宋','宋诗','song-poetry','','[]','雙蓮仙影面波光，翠蓋摇風紅粉香。',32,'全唐诗/poet.song.6000.json','["雙蓮仙影面波光，翠蓋摇風紅粉香。", "中有畫船鳴鼓吹，瞥然驚起兩鴛鴦。"]'),
('092e304f-9eb2-4951-b403-a0b1db0bc546','題木蘭堂','楊備','宋','宋诗','song-poetry','','[]','木蘭枝密樹仍高，堂下花光照節旄。',32,'全唐诗/poet.song.6000.json','["木蘭枝密樹仍高，堂下花光照節旄。", "列鼎重茵歌舞地，金章同色使君袍。"]'),
('18338fd1-d2db-4083-9ffc-c5d02eae2cfe','觀風樓','楊備','宋','宋诗','song-poetry','','[]','觀風危堞與雲齊，樓下開門畫戟西。',32,'全唐诗/poet.song.6000.json','["觀風危堞與雲齊，樓下開門畫戟西。", "鼓角聲沉絲管沸，卷簾晴黛遠山低。"]'),
('f4ab3a1d-84f5-4143-afc7-5bbbba51e2a4','姑蘇臺','楊備','宋','宋诗','song-poetry','','[]','山花野草一荒丘，雲裏驕奢舊跡留。',32,'全唐诗/poet.song.6000.json','["山花野草一荒丘，雲裏驕奢舊跡留。", "珠翠管絃人不見，上頭麋鹿至今遊。"]'),
('48b72fe9-712d-4b96-9626-a378ba8f178a','吳王井','楊備','宋','宋诗','song-poetry','','[]','石甃遺蹤傍古臺，一泓寒影鑑光開。',32,'全唐诗/poet.song.6000.json','["石甃遺蹤傍古臺，一泓寒影鑑光開。", "何人照面金釵落，曾見越溪紅粉來。"]'),
('a01c77a2-4806-433d-ab07-8e29a843caa0','響屧廊','楊備','宋','宋诗','song-poetry','','[]','步步香翻羅襪塵，粉紅花艷滿宮春。',32,'全唐诗/poet.song.6000.json','["步步香翻羅襪塵，粉紅花艷滿宮春。", "傾城一笑無遺跡，不見長廊響屧人。"]'),
('c22458b6-559b-4608-8065-147006305411','採香徑','楊備','宋','宋诗','song-poetry','','[]','館娃南面即香山，畫軻爭浮日往還。',32,'全唐诗/poet.song.6000.json','["館娃南面即香山，畫軻爭浮日往還。", "翠蓋風翻紅袖影，芙蓉一路照波間。"]'),
('25ac06bf-c043-48aa-94e1-372388a14a40','蠡口','楊備','宋','宋诗','song-poetry','','[]','霸越勳名間世才，五湖煙浪一帆開。',32,'全唐诗/poet.song.6000.json','["霸越勳名間世才，五湖煙浪一帆開。", "猶防烏喙傷同輩，此地復招文種回。"]'),
('27b98372-0341-439a-85d5-97c91ed5a56d','洗馬池','楊備','宋','宋诗','song-poetry','','[]','一一牽來種是龍，臨深欲下更嘶風。',32,'全唐诗/poet.song.6000.json','["一一牽來種是龍，臨深欲下更嘶風。", "金鞍玉勒拋何處，騰踏渥漥寒影中。"]'),
('d01979fe-050d-4eb0-8147-099eb4d1d140','伍員廟','楊備','宋','宋诗','song-poetry','','[]','出境鞭屍報父讎，吳兵勇銳越兵憂。',32,'全唐诗/poet.song.6000.json','["出境鞭屍報父讎，吳兵勇銳越兵憂。", "忠魂怨氣江雲在，日見爐香煙上浮。"]'),
('9056ac11-dd42-4a22-8607-d29f6e7afd13','天平山','楊備','宋','宋诗','song-poetry','','[]','久厭城居適野情，搘筇躡屐傍山行。',32,'全唐诗/poet.song.6000.json','["久厭城居適野情，搘筇躡屐傍山行。", "人間多少險巇路，縱是天平還不平。"]'),
('d49c06eb-d761-4678-bdf6-1f2cd3b942e6','穹窿山','楊備','宋','宋诗','song-poetry','','[]','吳郡名山第一山，翠微心在碧霄間。',32,'全唐诗/poet.song.6000.json','["吳郡名山第一山，翠微心在碧霄間。", "林泉瀟灑煙嵐秀，直擬結廬終老閑。"]'),
('166d66e2-2e1a-4424-89dc-44df75f19029','華山','楊備','宋','宋诗','song-poetry','','[]','巖屏晚樹噪寒鴉，嵐翠樓臺釋子家。',32,'全唐诗/poet.song.6000.json','["巖屏晚樹噪寒鴉，嵐翠樓臺釋子家。", "池面鏡光功德水，金波影裏石蓮花。"]'),
('61566b89-f454-4fc9-80fc-675d941857bb','二獄山','楊備','宋','宋诗','song-poetry','','[]','雷霆號令雪霜威，二獄東西鎖翠微。',32,'全唐诗/poet.song.6000.json','["雷霆號令雪霜威，二獄東西鎖翠微。", "彷彿酆都叢棘地，巖扉應是古圜扉。"]'),
