('fbeb228f-281f-466b-a1a1-999e58bf18b7','絕地','楊備','宋','宋诗','song-poetry','','[]','列戟高門氣自雄，主人應是偶相逢。',32,'全唐诗/poet.song.6000.json','["列戟高門氣自雄，主人應是偶相逢。", "由來禍福皆人召，此地無辜喚作凶。"]'),
('475379f8-c203-400f-bfe8-dacd617b9410','清暑殿','楊備','宋','宋诗','song-poetry','','[]','窣地簾光掛水精，玉鈎斜處月初生。',32,'全唐诗/poet.song.6000.json','["窣地簾光掛水精，玉鈎斜處月初生。", "龍皮席上鵝毛扇，何必風來暑自清。"]'),
('19d30c50-ccfc-4bf7-b762-ee8ddb7df25c','促粧鐘','楊備','宋','宋诗','song-poetry','','[]','枕面鐘聲及早催，錦衾香疊百花堆。',32,'全唐诗/poet.song.6000.json','["枕面鐘聲及早催，錦衾香疊百花堆。", "蟾蜍影落珊瑚架，照得僊城下界來。"]'),
('2f52bd13-f22d-4b1f-a38e-931dd0edc3ae','披香殿','楊備','宋','宋诗','song-poetry','','[]','獸口金昏煙穗濃，螭頭玉照露華融。',32,'全唐诗/poet.song.6000.json','["獸口金昏煙穗濃，螭頭玉照露華融。", "蕭郎的是春光主，曾作春衣此殿中。"]'),
('86607f81-8683-470f-8775-f578894efbcc','青溪姑','楊備','宋','宋诗','song-poetry','','[]','曩不乘龍即跨魚，岸傍人復乞靈無。',32,'全唐诗/poet.song.6000.json','["曩不乘龍即跨魚，岸傍人復乞靈無。", "柳如眉黛花如面，聞是青溪一小姑。"]'),
('cddf4284-4437-4eeb-bc15-eb39376be6af','冥漠君墓','楊備','宋','宋诗','song-poetry','','[]','柴壘穿壕見古墳，元嘉東府惠連文。',32,'全唐诗/poet.song.6000.json','["柴壘穿壕見古墳，元嘉東府惠連文。", "可憐名字知音少，祇使雙棺萬古聞。"]'),
('90f32b50-88b2-4f77-8a43-b82af47b4b2a','蔣帝廟','楊備','宋','宋诗','song-poetry','','[]','深逼巖扉敞廟門，靈風時動戟衣翻。',32,'全唐诗/poet.song.6000.json','["深逼巖扉敞廟門，靈風時動戟衣翻。", "禦災捍患陰功大，玉冊榮加帝者尊。"]'),
('e7355bd2-b8ca-4e1d-b26b-957e5a49332c','巖因崇報禪寺','楊備','宋','宋诗','song-poetry','','[]','一炷香銷百和焚，有時鐘磬梵天聞。',32,'全唐诗/poet.song.6000.json','["一炷香銷百和焚，有時鐘磬梵天聞。", "上方結草如高枕，不獨棲霞可臥雲。"]'),
('b80b29d9-8bd5-47d8-b949-49e3b964f4a7','江令宅','楊備','宋','宋诗','song-poetry','','[]','竹木池臺尚儼然，歸時白頭雪霜寒。',32,'全唐诗/poet.song.6000.json','["竹木池臺尚儼然，歸時白頭雪霜寒。", "青溪隱隱朱門處，曾屬中書一品官。"]'),
('5fcc6968-9d16-4145-a11a-0397e8fb9e83','石室大巖','楊備','宋','宋诗','song-poetry','','[]','玉洞雲深夏亦寒，客來尋勝久盤桓。',32,'全唐诗/poet.song.6000.json','["玉洞雲深夏亦寒，客來尋勝久盤桓。", "其間隱約聞雞犬，應有仙桃待一餐。"]'),
('6c0698a7-8b21-41ef-adde-d64080e16070','句  其一','楊備','宋','宋诗','song-poetry','','[]','雲竇穿銀井，冰甃貯玉漿。',12,'全唐诗/poet.song.6000.json','["雲竇穿銀井，冰甃貯玉漿。"]'),
('aa106538-8423-4a01-8dd2-ddc5d7f6524b','句  其二','楊備','宋','宋诗','song-poetry','','[]','生來葬魚腹，死後觸龍鱗。',12,'全唐诗/poet.song.6000.json','["生來葬魚腹，死後觸龍鱗。"]'),
('68074348-5e6d-4300-91fe-9776e2c5fd34','寄題武當郡守吏隱亭','釋希晝','宋','宋诗','song-poetry','','[]','郡亭傳吏隱，閑自使君心。',48,'全唐诗/poet.song.6000.json','["郡亭傳吏隱，閑自使君心。", "卷幕知來祝，懸燈見宿禽。", "茶煙逢石斷，棊響入花深。", "會逐南帆便，乘秋寄此吟。"]'),
('1a157ab3-dae8-40e7-ad33-790a1e856f27','送信南歸雁蕩山','釋希晝','宋','宋诗','song-poetry','','[]','千峰鄰積水，秋勢遠相依。',48,'全唐诗/poet.song.6000.json','["千峰鄰積水，秋勢遠相依。", "路在深雲裏，人思絕頂歸。", "長天來月正，危木度猿稀。", "誰得同無念，寥寥此掩扉。"]'),
('a61eebfb-efef-4659-aa91-513836a53a52','懷廣南轉運陳學士狀元','釋希晝','宋','宋诗','song-poetry','','[]','極望隨南斗，迢迢思欲迷。',48,'全唐诗/poet.song.6000.json','["極望隨南斗，迢迢思欲迷。", "春生桂嶺外，人在海門西。", "殘日依山盡，長天向水低。", "遙知仙館夢，夜夜怯猿啼。"]'),
('64661d6c-1194-4cb2-b3c4-3f4c5b754769','書惠崇師房','釋希晝','宋','宋诗','song-poetry','','[]','詩名在四方，獨此寄閑房。',48,'全唐诗/poet.song.6000.json','["詩名在四方，獨此寄閑房。", "故國寒濤闊，春城夜夢長。", "禽聲沈遠木，花影動回廊。", "幾爲分題客，殷勤掃石牀。"]'),
('3e7db564-5e50-4cbc-b3e1-0b9208b61b91','斷碑','釋希晝','宋','宋诗','song-poetry','','[]','片玉侵寒折，零文見斷蟲。',48,'全唐诗/poet.song.6000.json','["片玉侵寒折，零文見斷蟲。", "遠沈岡草際，半露塹冰中。", "跡著人何在，年銷事已空。", "唯聞壞陵柏，相弔起悲風。"]'),
('8aeef6e2-0f40-40e0-b8fa-161bd123bbef','寄懷古','釋希晝','宋','宋诗','song-poetry','','[]','見說雕陰僻，人煙半雜羌。',48,'全唐诗/poet.song.6000.json','["見說雕陰僻，人煙半雜羌。", "秋深邊日短，風勁曉笳長。", "樹勢分孤壘，河流出遠荒。", "遙知林下客，吟苦夜禪忘。"]'),
('b4dd4bb7-f5fa-4cff-b1d8-5438a99b24f2','留題承旨宋侍郎林亭','釋希晝','宋','宋诗','song-poetry','','[]','翰苑營嘉致，到來山意深。',48,'全唐诗/poet.song.6000.json','["翰苑營嘉致，到來山意深。", "會榮多野客，啼竹半沙禽。", "雪溜懸顧石，棋燈射遠林。", "言詩素非苦，虛答侍臣心。"]'),
('b4ae1233-344e-4ab3-bb05-4be87289c9a2','送嗣端東歸','釋希晝','宋','宋诗','song-poetry','','[]','遠念生泉石，人中事欲銷。',48,'全唐诗/poet.song.6000.json','["遠念生泉石，人中事欲銷。", "卷衣城要落，尋寺海山遙。", "帆影迷寒雁，經聲隱暮潮。", "後期俱未定，況我鬢先凋。"]'),
('da4b0933-7033-4c54-9972-7b405754bb4d','寄河陽察推駱員外','釋希晝','宋','宋诗','song-poetry','','[]','郡齋鄰少室，夏木冷垂陰。',48,'全唐诗/poet.song.6000.json','["郡齋鄰少室，夏木冷垂陰。", "況是多閑日，應懸長臥心。", "角當中島起，檣背遠橋沈。", "獨愛南樓月，終期宿此吟。"]'),
('24a46702-ae31-4874-a064-9bec9b87f1f3','送惟鳳之終南山','釋希晝','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','闕內寒生早，南山萬木凋。',48,'全唐诗/poet.song.6000.json','["闕內寒生早，南山萬木凋。", "長空人望絕，積雪獨尋遙。", "靜息非同隱，閑吟忽背樵。", "幾侵峰頂月，相念起中宵。"]'),
('d6b825b8-db25-4f57-839b-e901994f1dad','寄壽春使君陳學士','釋希晝','宋','宋诗','song-poetry','','[]','三處波濤郡，連年輟謝公。',48,'全唐诗/poet.song.6000.json','["三處波濤郡，連年輟謝公。", "春齋山藥徧，夜舶海書通。", "樓潤星河露，川寒鼓角風。", "誰當刊惠政，一一古賢同。"]'),
('ec968463-c5d1-464a-9115-3fb3902f5782','送從律之關中','釋希晝','宋','宋诗','song-poetry','','[]','西遊無舊識，何處寄吟身。',48,'全唐诗/poet.song.6000.json','["西遊無舊識，何處寄吟身。", "客路秦關暮，鄉心海樹春。", "河濤行不盡，嶽翠望空新。", "早晚回孤錫，東浮結近鄰。"]'),
('0a4518ea-1962-419b-b204-835b935f714b','寄答桂府黄殿院','釋希晝','宋','宋诗','song-poetry','','[]','桂水在天末，登高生遠思。',48,'全唐诗/poet.song.6000.json','["桂水在天末，登高生遠思。", "來書逢歲闕，去夢歷峰危。", "別浦珠全返，空臺柏半衰。", "詩成見新月，幾負郡齋期。"]'),
('aecff85f-b23d-4c28-9dba-819c9c62c190','送可倫赴廣南轉運凌使君見招','釋希晝','宋','宋诗','song-poetry','','[]','別語畏殘漏，心懸瘴海邊。',48,'全唐诗/poet.song.6000.json','["別語畏殘漏，心懸瘴海邊。", "回期無定日，去路極遙天。", "苦霧沈山郭，寒沙漲隰田。", "幾宵尋使府，清話廢閑眠。"]'),
('4d4cf65d-f766-4d92-8a31-19c66427d394','早春闕下寄觀公','釋希晝','宋','宋诗','song-poetry','','[]','客心長念隱，早晚解書招。',48,'全唐诗/poet.song.6000.json','["客心長念隱，早晚解書招。", "看月前期阻，論山靜會遙。", "微陽生遠道，殘雪下中宵。", "坐見青門柳，依依又結條。"]'),
('408c47b0-2933-4e48-8707-dfcafa085441','送李堪','釋希晝','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','要地無深託，飄然又出關。',48,'全唐诗/poet.song.6000.json','["要地無深託，飄然又出關。", "秋聲動羣木，暮色起千山。", "岸草隨秋遠，江雲入望閑。", "何宵發孤詠，月冷洞庭閑。"]'),
('c168cd3e-2e80-4232-acbc-3c8ea550e6a9','送朱扆','釋希晝','宋','宋诗','song-poetry','','[]','別業滄波外，秋風歸去心。',48,'全唐诗/poet.song.6000.json','["別業滄波外，秋風歸去心。", "玉繩天闕遠，金柝海城深。", "素瑟沈幽意，寒螿共苦吟。", "鄰漁知有約，乘月夜相尋。"]'),
('db9cc1c6-d855-4efd-b854-e07893c5a36e','過巴峽','釋希晝','宋','宋诗','song-poetry','','[]','遠望知無極，窮秋日向殘。',49,'全唐诗/poet.song.6000.json','["遠望知無極，窮秋日向殘。", "孤泉瀉空白，衆木倚雲寒。", "靜想猿高祖苦，危聞客過難。", "寸心寧可寄，前去雪漫漫。"]'),
('c732b079-086b-4e8b-9143-54e361693dc0','草','釋希晝','宋','宋诗','song-poetry','','[]','漠漠更離離，閑吟笑復悲。',48,'全唐诗/poet.song.6000.json','["漠漠更離離，閑吟笑復悲。", "六朝鳥戰處，千載寂寥時。", "陣闊圍空壘，叢疏露斷碑。", "不堪殘照外，牧笛隔煙吹。"]'),
('55158d95-dee5-4081-abb0-53a3621a1066','句  其一','釋希晝','宋','宋诗','song-poetry','','[]','漱齒冰溪遠，聞蟬雪屋深。',12,'全唐诗/poet.song.6000.json','["漱齒冰溪遠，聞蟬雪屋深。"]'),
('283832e3-9ffc-4067-ace3-da37f4b817e0','句  其二','釋希晝','宋','宋诗','song-poetry','','[]','曉天金馬路，晚歲石霜心。',12,'全唐诗/poet.song.6000.json','["曉天金馬路，晚歲石霜心。"]'),
('29e0fabe-a757-459d-bd5b-d7f4f6d84285','句  其三','釋希晝','宋','宋诗','song-poetry','','[]','山日秋光短，江虹晚影低。',12,'全唐诗/poet.song.6000.json','["山日秋光短，江虹晚影低。"]'),
('b3aab5ac-0f5b-4490-9273-8652ef38d502','句  其四','釋希晝','宋','宋诗','song-poetry','','[]','劍月啼猿苦，江沙濯錦寒。',12,'全唐诗/poet.song.6000.json','["劍月啼猿苦，江沙濯錦寒。"]'),
('357e07fd-c33d-438e-8ee0-a3a4dd7695e2','句  其五','釋希晝','宋','宋诗','song-poetry','','[]','花露盈蟲穴，梁塵墮燕泥。',12,'全唐诗/poet.song.6000.json','["花露盈蟲穴，梁塵墮燕泥。"]'),
('8579d987-7055-4917-b4fc-c09ec09fd6e2','句  其六','釋希晝','宋','宋诗','song-poetry','','[]','寄禪關樹老，乞食塞城羌。',12,'全唐诗/poet.song.6000.json','["寄禪關樹老，乞食塞城羌。"]'),
('b857a26f-6205-4df7-a7f1-fc87272aef40','句  其七','釋希晝','宋','宋诗','song-poetry','','[]','風泉舊聽僧窗改，雲穴曾行鳥徑殘。',16,'全唐诗/poet.song.6000.json','["風泉舊聽僧窗改，雲穴曾行鳥徑殘。"]'),
('98d9bd0b-6f4d-4a69-b85f-9f1a2524ee2c','句  其八','釋希晝','宋','宋诗','song-poetry','','[]','芳樹侵雲老，孤泉落石危。',12,'全唐诗/poet.song.6000.json','["芳樹侵雲老，孤泉落石危。"]'),
('d7e94539-576d-48de-831c-7bb8678fa110','句  其九','釋希晝','宋','宋诗','song-poetry','','[]','落日橫秋島，寒濤兀夜船。',12,'全唐诗/poet.song.6000.json','["落日橫秋島，寒濤兀夜船。"]'),
('73080560-a6d1-43bd-9563-7406fd9a250d','句  其一○','釋希晝','宋','宋诗','song-poetry','','[]','去路正黄葉，別君堪白頭。',12,'全唐诗/poet.song.6000.json','["去路正黄葉，別君堪白頭。"]'),
('6301d5d5-0e57-4ff2-9293-3811de1ca0d2','江行','釋保暹','宋','宋诗','song-poetry','','[]','渺渺沈清際，回頭望即賒。',48,'全唐诗/poet.song.6000.json','["渺渺沈清際，回頭望即賒。", "幽禽飛共闊，野客泛無涯。", "浦暗微分樹，灘遙半漲沙。", "今宵應有月，重得宿蘆花。"]'),
('359be96a-a76f-41ba-a763-2c1132e85f95','寄從弟','釋保暹','宋','宋诗','song-poetry','','[]','天外跡如萍，何人慰遠情。',48,'全唐诗/poet.song.6000.json','["天外跡如萍，何人慰遠情。", "煙霄滯秋薦，水國廢春耕。", "旅夢寒應斷，吟髭白恐生。", "無因話消息，一雁度江城。"]'),
('12c01298-917d-48fe-9fcd-b0bac4022801','金陵懷古','釋保暹','宋','宋诗','song-poetry','','[]','石城秋月滿，煙水冷蕭蕭。',48,'全唐诗/poet.song.6000.json','["石城秋月滿，煙水冷蕭蕭。", "戰氣悲千古，歌聲散六朝。", "螢飛宮草暗，霜白井桐凋。", "竟日秦淮上，思賢莫可招。"]'),
('9ced2098-c8f7-457a-bb67-c4d2c0cde2d9','秋徑','釋保暹','宋','宋诗','song-poetry','','[]','杉竹青陰合，閑行意有憑。',48,'全唐诗/poet.song.6000.json','["杉竹青陰合，閑行意有憑。", "涼生初過雨，靜極忽歸僧。", "蟲跡穿幽穴，苔痕接斷稜。", "翻思深隱處，峰頂下層層。"]'),
('cc0708d2-4991-48dc-a153-038dd2a3d799','宿宇昭師房','釋保暹','宋','宋诗','song-poetry','','[]','與我難忘舊，多期宿此房。',48,'全唐诗/poet.song.6000.json','["與我難忘舊，多期宿此房。", "眠雲歸未得，靜夜話空長。", "草際沈螢影，杉西露月光。", "天明共無寐，南去水茫茫。"]'),
('ad5e1444-a29e-4451-a3a1-0e72a1f0dfb7','途次望太行山','釋保暹','宋','宋诗','song-poetry','','[]','盤影遮空黑，愁生入望賒。',48,'全唐诗/poet.song.6000.json','["盤影遮空黑，愁生入望賒。", "高來難客路，深去斷人家。", "翠死寒溪水，香殘別洞花。", "今宵何處宿，山口日將斜。"]'),
('b15a27f5-7a27-4e64-9045-1664d0f6e6d3','書惟鳳師壁','釋保暹','宋','宋诗','song-poetry','','[]','草徑通深院，秋來心更閑。',48,'全唐诗/poet.song.6000.json','["草徑通深院，秋來心更閑。", "城中無舊識，門外是他山。", "究寂生吟思，持齋得病顔。", "寒宵多約我，靜話出人閑。"]'),
('4646d3d0-906d-4814-8ec0-fcfce4a255cf','石席','釋保暹','宋','宋诗','song-poetry','','[]','有狀卷不得，閑齋惜夜長。',48,'全唐诗/poet.song.6000.json','["有狀卷不得，閑齋惜夜長。", "坐來消暑氣，睡去入秋鄉。", "隱隱生寒骨，沈沈發冷光。", "何時遂深遁，移取置山房。"]'),
('dd696b87-8951-49e4-ab17-7b655ac4e825','重登文兆師水閣','釋保暹','宋','宋诗','song-poetry','','[]','重來久凭欄，臨水景多閑。',48,'全唐诗/poet.song.6000.json','["重來久凭欄，臨水景多閑。", "高樹下殘照，寒潮平遠山。", "夜吟長負宿，秋病幾思閑。", "早晚離城裏，從茲寄掩關。"]'),
('0a49f2a4-52d0-4f03-85ea-0dc3779bc8e7','寄徐任','釋保暹','宋','宋诗','song-poetry','','[]','鄉園書久斷，寒夜起歸心。',48,'全唐诗/poet.song.6000.json','["鄉園書久斷，寒夜起歸心。", "遠路秦關外，啼猿劍樹深。", "貧遊年暗改，醉臥月空沈。", "幾夕疏林下，相思廢靜吟。"]'),
('07847935-8bf3-4126-9adb-6c68a02b2744','送簡上人之洛陽','釋保暹','宋','宋诗','song-poetry','','[]','閑身無所滯，獨去背春城。',48,'全唐诗/poet.song.6000.json','["閑身無所滯，獨去背春城。", "望越鄉心斷，迎嵩隱思生。", "野禪依樹遠，中飯傍泉清。", "相府如投刺，分題有竺卿。"]'),
('b4bd2b93-5948-4ab1-a65e-0adb9cf9a705','寄白閣元貞','釋保暹','宋','宋诗','song-poetry','','[]','一聞歸白閣，更不入長安。',48,'全唐诗/poet.song.6000.json','["一聞歸白閣，更不入長安。", "絕頂無人上，西風徹夜寒。", "懸崖乘雪度，飛瀑過雲看。", "應念馳名者，青門得路難。"]'),
('e4622280-aeee-44f2-8d4c-aeebaa8adc32','老僧','釋保暹','宋','宋诗','song-poetry','','[]','鬢毛垂似雪，無語答閑人。',48,'全唐诗/poet.song.6000.json','["鬢毛垂似雪，無語答閑人。", "擁衲坐終日，浮生知幾春。", "乘船應夢越，提錫記遊秦。", "半夜寒堂掩，磬聲聞四鄰。"]'),
('d3000b76-c7dd-46d7-9b0a-c40e1bb3ec82','登蕪城古臺','釋保暹','宋','宋诗','song-poetry','','[]','無處堪高望，城邊上古臺。',48,'全唐诗/poet.song.6000.json','["無處堪高望，城邊上古臺。", "窮秋人獨立，落日雁空回。", "地險千峰出，霜嚴萬木摧。", "遲吟不能下，滿眼是塵埃。"]'),
('4bd86a87-2dcd-43b5-818a-186be8f98d3e','寄行肇上人','釋保暹','宋','宋诗','song-poetry','','[]','舊隱湖西寺，青青千萬峰。',48,'全唐诗/poet.song.6000.json','["舊隱湖西寺，青青千萬峰。", "來書度深雪，歸夢斷疏鐘。", "開口與時避，論心似我慵。", "流年共衰鬢，昨夜又聞蛩。"]'),
('08543b8d-2858-4a9d-9532-7aaa9eb040f1','送蔣白歸越','釋保暹','宋','宋诗','song-poetry','','[]','會稽連照水，歸意兩何親。',48,'全唐诗/poet.song.6000.json','["會稽連照水，歸意兩何親。", "山影到平地，湖光生四鄰。", "虛窗寒對曉，孤棹遠浮春。", "未可從耕釣，青雲懶致身。"]'),
('f50e3685-5b0a-4aae-8b6d-5aaa07344718','書派河徐希秀才別業','釋保暹','宋','宋诗','song-poetry','','[]','渺渺渡頭路，客心難解攜。',48,'全唐诗/poet.song.6000.json','["渺渺渡頭路，客心難解攜。", "半空山遠近，寒日水東西。", "漾浦漁罾小，飛沙雁陣低。", "霜風起深夜，只是欠猿啼。"]'),
('06f49340-d318-4c74-8675-fa9348219d9c','秋居言懷','釋保暹','宋','宋诗','song-poetry','','[]','默默疏林下，獨知秋氣濃。',48,'全唐诗/poet.song.6000.json','["默默疏林下，獨知秋氣濃。", "半生猶是客，昨夜更聞蛩。", "吟苦人成癖，年衰自長慵。", "終期拂衣去，江上有諸峰。"]'),
('9ea24a54-f4e7-4d43-84bf-8c23050c3df5','早秋閑寄宇昭','釋保暹','宋','宋诗','song-poetry','','[]','窗虛枕簟明，微覺早涼生。',48,'全唐诗/poet.song.6000.json','["窗虛枕簟明，微覺早涼生。", "深院無人語，長松滴雨聲。", "詩來禪外得，愁入靜中平。", "遠念西林下，相思合慰情。"]'),
('95cd0684-0f11-4fc6-acb9-93ebc2fdc121','憶松江','釋保暹','宋','宋诗','song-poetry','','[]','曾向長洲泛渺漫，沈青空闊鳥飛難。',64,'全唐诗/poet.song.6000.json','["曾向長洲泛渺漫，沈青空闊鳥飛難。", "平沙杳杳夜潮落，別浦依依秋樹寒。", "閑浸客亭浮去棹，冷淹漁屋漾垂竿。", "歸心早晚懸帆到，是處僧樓更上看。"]'),
('d94cbd29-452e-4da8-bc69-9d4c8cb91b9b','寄洪州新建和縣張康','釋保暹','宋','宋诗','song-poetry','','[]','遠聽弦歌樂部封，放衙乘醉半疏慵。',64,'全唐诗/poet.song.6000.json','["遠聽弦歌樂部封，放衙乘醉半疏慵。", "家辭南越無千里，縣管西山有幾峰。", "人望廢田禾影合，吏愁空獄蘚痕重。", "孺亭應更悲前事，煙草萋萋叫夜蛩。"]'),
('38bb45f7-fde7-4381-af02-5b1fa6197c05','磻溪','釋保暹','宋','宋诗','song-poetry','','[]','不肯隨波自直鈎，一朝以道佐成周。',32,'全唐诗/poet.song.6000.json','["不肯隨波自直鈎，一朝以道佐成周。", "後來亦有人於此，只把漁竿空白頭。"]'),
('39a0182e-9b81-4f52-8aad-dd50c9ff1238','送人自闕下歸天柱','釋保暹','宋','宋诗','song-poetry','','[]','卻歸天柱峰前去，高謝浮名似了心。',32,'全唐诗/poet.song.6000.json','["卻歸天柱峰前去，高謝浮名似了心。", "林下孤燈一聲磬，青猿啼斷白雲深。"]'),
('3193f190-0c22-4763-ba17-a9699eb3140f','巴江秋夕','釋保暹','宋','宋诗','song-poetry','','[]','巴水寒聲去渺茫，半空雲樹落秋光。',32,'全唐诗/poet.song.6000.json','["巴水寒聲去渺茫，半空雲樹落秋光。", "離人此夜和愁宿，不聽啼猿亦斷腸。"]'),
('307770e2-3e1f-431c-88b2-7d336a5c2868','書杭州西湖涉公堂','釋保暹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孤舟孤鶴與孤雲，湖上深居自不羣。',32,'全唐诗/poet.song.6000.json','["孤舟孤鶴與孤雲，湖上深居自不羣。", "高臥可能容一榻，青山西岸且平分。"]'),
('09b92986-484f-46d1-994b-c5b33b606f37','幽圃','釋文兆','宋','宋诗','song-poetry','','[]','遠與村橋接，深春積雨時。',48,'全唐诗/poet.song.6000.json','["遠與村橋接，深春積雨時。", "蘭芳人未採，花發蝶先知。", "草密封閑徑，林疏露短籬。", "別來鋤久廢，身老恨歸遲。"]'),
('df3ae3d5-57dd-46bb-b002-f13fabaea49b','江上書懷寄希晝','釋文兆','宋','宋诗','song-poetry','','[]','扁舟宿江上，脈脈興何窮。',48,'全唐诗/poet.song.6000.json','["扁舟宿江上，脈脈興何窮。", "吳楚十年客，蒹葭一夜風。", "東林秋信斷，南越石房空。", "向此都忘寐，君應與我同。"]'),
('8f473a5d-7b54-47cb-abdd-aea076149a11','弔屈原呈王內翰','釋文兆','宋','宋诗','song-poetry','','[]','抱清誰可羣，委質在湘濆。',48,'全唐诗/poet.song.6000.json','["抱清誰可羣，委質在湘濆。", "今日不同楚，無人更似君。", "滄波沈夜魄，古廟聚寒雲。", "弔罷踟躕處，漁歌忍獨聞。"]'),
('b240f076-b8ee-439e-9ffb-0f5fc3168a3f','寄行肇上人','釋文兆','宋','宋诗','song-poetry','','[]','詩禪同所尚，邂逅在長安。',48,'全唐诗/poet.song.6000.json','["詩禪同所尚，邂逅在長安。", "爲客閑相似，趨時懶一般。", "分題秋閣迥，對坐夜堂寒。", "未遂歸山計，流年鬢已乾。"]'),
('4eac6682-f316-4a88-827a-cb1d5ed2bd75','送史館李學士任和州','釋文兆','宋','宋诗','song-poetry','','[]','事主惟公直，承恩赴歷陽。',48,'全唐诗/poet.song.6000.json','["事主惟公直，承恩赴歷陽。", "舟浮淮水遠，路繞楚山長。", "館謁僧侵月，郊迎吏蹋霜。", "下車難久滯，飛詔即徵黄。"]'),
('0f80387e-a078-4de6-a16b-1fbe1fe9993d','寄保暹師','釋文兆','宋','宋诗','song-poetry','','[]','近聞高靜趣，猶寄廣陵居。',48,'全唐诗/poet.song.6000.json','["近聞高靜趣，猶寄廣陵居。", "夜會聽琴阻，秋期看月疏。", "幾成歸越夢，久絕入梁書。", "四釋分題處，年來一榻虛。"]'),
('b7f51f55-1f1a-4616-bf3b-678f32064212','巴峽聞猿','釋文兆','宋','宋诗','song-poetry','','[]','倚棹望雲際，寥寥出峽清。',48,'全唐诗/poet.song.6000.json','["倚棹望雲際，寥寥出峽清。", "心如無一事，愁不在三聲。", "带露諸峰迥，懸空片月明。", "何人同此聽，徹曉得詩成。"]'),
('58c4fa22-c2e3-48db-9050-dc755d5bbb21','送宇昭師','釋文兆','宋','宋诗','song-poetry','','[]','相見又相別，無言感倍興。',48,'全唐诗/poet.song.6000.json','["相見又相別，無言感倍興。", "諸峰微下雪，一路獨行僧。", "午飯煙村磬，宵吟石屋燈。", "他方人請住，又得繼南能。"]'),
('b7f7b1c8-d8e4-4d84-9550-574070f646a6','莎庭','釋文兆','宋','宋诗','song-poetry','','[]','苒苒從莎長，凄涼雨乍晴。',48,'全唐诗/poet.song.6000.json','["苒苒從莎長，凄涼雨乍晴。", "窮秋要客步，落日亂蛩鳴。", "近接苔階迥，遙連竹徑平。", "杖痕兼鶴跡，來往自縱橫。"]'),
('055d2e32-e355-49cc-b33c-d78117433b51','送惟鳳師之終南','釋文兆','宋','宋诗','song-poetry','','[]','終南關內見，寒翠疊空虛。',48,'全唐诗/poet.song.6000.json','["終南關內見，寒翠疊空虛。", "明代誰招隱，深秋自卜居。", "宵晴吟洞月，日曉飯溪蔬。", "此後嫌名出，應無入闕書。"]'),
('07d2c16e-68ea-4c48-9f42-7846492b932c','宿西山精舍','釋文兆','宋','宋诗','song-poetry','','[]','西山乘興宿，靜稱寂寥心。',48,'全唐诗/poet.song.6000.json','["西山乘興宿，靜稱寂寥心。", "一徑杉松老，三更雨雪深。", "草堂僧語息，雲閣磬聲沈。", "未遂長棲此，雙峰曉待尋。"]'),
('b022d1c5-dd8b-4d1c-b378-888e32a5b4ba','送簡長師之洛','釋文兆','宋','宋诗','song-poetry','','[]','動靜非常態，超然西去心。',48,'全唐诗/poet.song.6000.json','["動靜非常態，超然西去心。", "水期經洛聽，雲約到嵩吟。", "齋訪煙村遠，禪依竹寺深。", "祇應風雅道，相府是知音。"]'),
('c6ed7334-e070-48de-ba27-02fc3b05e8e3','贈天柱山盺禪老','釋文兆','宋','宋诗','song-poetry','','[]','幾年天柱居，韜光外浮世。',96,'全唐诗/poet.song.6000.json','["幾年天柱居，韜光外浮世。", "禪心混沌先，詩思雲霞際。", "山雪滌茶鐺，谿泉濯祖毳。", "富德鄙利徒，貴道輕權勢。", "竹牖晴長開，松扉夜不閉。", "霜嚴庭樹萎，雨暴龕燈翳。", "紅葉遇寒燒，白頭逢暖剃。", "終期爲近鄰，清話素相契。"]'),
('3884d434-0e05-48c0-911a-b2697d591ac7','詩一首','釋文兆','宋','宋诗','song-poetry','','[]','河分崗勢司空曙，春入燒痕劉長卿。',32,'全唐诗/poet.song.6000.json','["河分崗勢司空曙，春入燒痕劉長卿。", "不是師兄偷古句，古人詩句犯師兄。"]'),
('774d75b7-fb73-403f-b992-edd73ea8ef59','中秋對月','釋行肇','宋','宋诗','song-poetry','','[]','暮雨過寥廓，江天正青蒼。',48,'全唐诗/poet.song.6000.json','["暮雨過寥廓，江天正青蒼。", "列樹無殘陰，積水有異光。", "幽蟲鳴欲徧，宿鳥驚忽翔。", "永夜如至公，鑑我吟清章。"]'),
('cbc0cb0d-ad0d-4d34-aa3a-186f33e4540e','聽宇昭師琴','釋行肇','宋','宋诗','song-poetry','','[]','遙空雨初霽，深徑蟬未鳴。',48,'全唐诗/poet.song.6000.json','["遙空雨初霽，深徑蟬未鳴。", "忽品文王弦，若聽宣尼聲。", "月色半峰出，秋光四簷清。", "韻斷意轉冥，塵心若爲情。"]'),
('1edcb3ac-ba2a-49d8-aee1-4e19da545ee9','湘江有感上王內翰','釋行肇','宋','宋诗','song-poetry','','[]','達士弦性直，佞人膠辭柔。',48,'全唐诗/poet.song.6000.json','["達士弦性直，佞人膠辭柔。", "靳尚一言巧，靈均千古愁。", "孤蟾魄長在，寒雲恨難收。", "空使湘江水，至今無濁流。"]'),
('dd1bea95-2fdd-49a6-bebd-3c94ec7c691c','送希晝之九華','釋行肇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','忽起塵外心，跡謝人中境。',48,'全唐诗/poet.song.6000.json','["忽起塵外心，跡謝人中境。", "雲去竹堂空，鷺下秋池靜。", "野宿清溪深，月在諸峰頂。", "日暮立長江，遙看片帆影。"]'),
('49dc461b-9805-44fb-8776-606fb2bd634a','臥病吟','釋行肇','宋','宋诗','song-poetry','','[]','杉窗秋氣深，入夜四簷雨。',48,'全唐诗/poet.song.6000.json','["杉窗秋氣深，入夜四簷雨。", "枕冷夢忽醒，獨對孤燈語。", "流螢隱回廊，驚鴻度寒渚。", "空令一寸心，悠悠生萬縷。"]'),
('02a2fabb-82ab-4f04-9540-5288d6d42ed4','送惟風之衡陽','釋行肇','宋','宋诗','song-poetry','','[]','重城獨隱居，世人寡相識。',60,'全唐诗/poet.song.6000.json','["重城獨隱居，世人寡相識。", "回塘路寂寥，深徑花狼籍。", "西風思忽生，南泉語還憶。", "遙山去意長，大江歸夢直。", "日暮立荒原，迢迢望空碧。"]'),
('02b4c4b4-a6f1-4547-8015-66074ab0df88','泛若耶溪','釋行肇','宋','宋诗','song-poetry','','[]','霽雨牽野情，孤舟遂茲賞。',48,'全唐诗/poet.song.6000.json','["霽雨牽野情，孤舟遂茲賞。", "積水連遠空，落日垂萬象。", "岸迴雲獨隨，山轉泉更響。", "望望極寒源，由言放輕槳。"]'),
('4c8af3cc-2b6e-4e0f-9851-7163bb2e811c','送從律師西遊','釋行肇','宋','宋诗','song-poetry','','[]','蟄鱗伺新春，望極融融歸。',84,'全唐诗/poet.song.6000.json','["蟄鱗伺新春，望極融融歸。", "驚禽別舊巢，念遠遲遲飛。", "吁君腹至業，歲故志獨違。", "心弦世寡聽，意鑑古亦稀。", "出關自荷篋，入秦扣誰扉。", "埃目若忽失，風雨遠漸微。", "將看吐虹章，冷射仙掌輝。"]'),
('93ad22ea-4ce2-4a7d-a124-d28a07ce9bb4','寄終南種徵君','釋行肇','宋','宋诗','song-poetry','','[]','紫閣浮清漢，高眠稱此心。',48,'全唐诗/poet.song.6000.json','["紫閣浮清漢，高眠稱此心。", "住溪人未識，歸路鶴知深。", "峰晚迴寒翠，猿孤發夜吟。", "霜天獨西向，無復夢山陰。"]'),
('65d815b5-c21d-442d-bc69-e063f6aeb9db','送簡師南遊','釋行肇','宋','宋诗','song-poetry','','[]','古岸侵煙出，揚帆拂曙星。',48,'全唐诗/poet.song.6000.json','["古岸侵煙出，揚帆拂曙星。", "層城關海日，列樹隱沙汀。", "潮落家遙見，梅香檝暫停。", "舊峰歸計晚，長憶隔吳青。"]'),
('ed9fcccd-cb8c-4510-b57b-e9a006ccf711','郊居吟','釋行肇','宋','宋诗','song-poetry','','[]','靜室簾孤捲，幽光墜露多。',48,'全唐诗/poet.song.6000.json','["靜室簾孤捲，幽光墜露多。", "徑寒杉影轉，窗晚雪聲過。", "茗味沙泉合，鑪香竹靄和。", "遙懷起深夕，舊寺隔滄波。"]'),
('b3a0ce68-fb3a-44c5-ba15-d50a2b0272e7','送懷古師歸蜀','釋行肇','宋','宋诗','song-poetry','','[]','山落雲陽外，去程寒接巴。',48,'全唐诗/poet.song.6000.json','["山落雲陽外，去程寒接巴。", "劍江連漢直，棧閣掛空斜。", "聽錫樵停斧，窺禪鳥立槎。", "舊房春到晚，深徑始開花。"]'),
('243f875a-06db-40e7-a20a-420ca7909213','送文兆歸廬山','釋行肇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','劍峰雙倚漢，蕩槳月中歸。',48,'全唐诗/poet.song.6000.json','["劍峰雙倚漢，蕩槳月中歸。", "潮白島西出，帆孤岸際飛。", "香連潭影直，磬度雪聲微。", "幾夕□詩坐，相思入定稀。"]'),
('a3949d40-7e02-4d8b-b58f-2813b1927ed9','酬贈夢真上人','釋行肇','宋','宋诗','song-poetry','','[]','禪舍因吟往，晴來坐徹宵。',48,'全唐诗/poet.song.6000.json','["禪舍因吟往，晴來坐徹宵。", "春通三徑晚，家別九江遙。", "巢重禽初宿，窗明葉旋飄。", "住期應未定，謝守有詩招。"]'),
('087b3d33-e162-483a-963e-ddf6df8f2b0a','送蒲奉禮之鄞江','釋行肇','宋','宋诗','song-poetry','','[]','官舍仙山裏，全家去若歸。',48,'全唐诗/poet.song.6000.json','["官舍仙山裏，全家去若歸。", "江聲鼇背出，帆影斗邊飛。", "宿館荷香接，吟亭島色圍。", "前秋賞明月，況對謝玄暉。"]'),
('f65166d2-b931-4335-8dc5-63d0def2a078','送文光上人西遊','釋行肇','宋','宋诗','song-poetry','','[]','高木墜殘葉，關河入遠心。',48,'全唐诗/poet.song.6000.json','["高木墜殘葉，關河入遠心。", "嵩遊忘楚夢，華近識秦音。", "塔古懸圖認，碑荒背燒尋。", "幾思興替事，獨上灞陵吟。"]'),
('00308ff0-4ee7-49e7-9ec0-e1eb60cb93ed','夜感','釋簡長','宋','宋诗','song-poetry','','[]','無眠動歸心，寒燈坐將滅。',24,'全唐诗/poet.song.6000.json','["無眠動歸心，寒燈坐將滅。", "長恐浮雲生，奪我西窗月。"]'),
('e46aa87c-f408-4dee-a3dc-2b6d11fa7bf0','懷盧叔微','釋簡長','宋','宋诗','song-poetry','','[]','病起啟秋匣，素琴生塵埃。',36,'全唐诗/poet.song.6000.json','["病起啟秋匣，素琴生塵埃。", "朱弦愁零落，古意工徘徊。", "子期不我至，獨上高高臺。"]'),
('b296003e-4e4b-4293-86a5-6479b20faff4','贈峽山清倫師','釋簡長','宋','宋诗','song-poetry','','[]','褰衣汲靈水，混滌巾履塵。',60,'全唐诗/poet.song.6000.json','["褰衣汲靈水，混滌巾履塵。", "煙靄霽杉竹，澄凝此心神。", "高僧灑真雨，澤彼寒草春。", "華月寫空印，清霜肅齋身。", "猶言振金策，歸作耶溪鄰。"]'),
('eb877141-4d94-421f-88eb-22818739c2fb','步春謠','釋簡長','宋','宋诗','song-poetry','','[]','春景欲饒物，客心獨優柔。',48,'全唐诗/poet.song.6000.json','["春景欲饒物，客心獨優柔。", "藉茲徘徊芳，彊起寂寞遊。", "新愁來易積，舊歡去難收。", "步春不得侶，不如步高秋。"]'),
('07366c2c-9dad-4b3e-997d-cde492f861a9','送方仲荀','釋簡長','宋','宋诗','song-poetry','','[]','行客心如何，借劍爲君歌。',36,'全唐诗/poet.song.6000.json','["行客心如何，借劍爲君歌。", "雨昏山未開，花盡春無多。", "欲知貧別情，涕淚空滂沱。"]'),
('bde8d3d9-b844-4590-a4de-4d5c7b466861','晚次江陵','釋簡長','宋','宋诗','song-poetry','','[]','楚路接江陵，倦行愁問程。',48,'全唐诗/poet.song.6000.json','["楚路接江陵，倦行愁問程。", "異鄉無舊識，多難足離情。", "落日懸秋樹，寒蕪上廢城。", "前山不可望，斷續暮猿聲。"]'),
('11c59711-45a0-4f16-a13c-2924358517f8','書行肇師壁','釋簡長','宋','宋诗','song-poetry','','[]','禪徑秋苔合，寒窗带雨痕。',48,'全唐诗/poet.song.6000.json','["禪徑秋苔合，寒窗带雨痕。", "心真冥自契，句好與誰論。", "露冷蛩聲咽，風微葉影翻。", "白雲如有意，終日在前軒。"]'),
('3f6303d9-11d6-4db1-8bd3-312cc2a01a20','寄丁學士','釋簡長','宋','宋诗','song-poetry','','[]','想極南溟外，江園草樹秋。',48,'全唐诗/poet.song.6000.json','["想極南溟外，江園草樹秋。", "浮生如寄夢，幾夕是離愁。", "仙館閑明月，星車背遠流。", "祇應西掖吏，時復望滄洲。"]'),
('8ad1c3db-19ac-4aa5-a2e3-36588596fa32','李氏山莊留別','釋簡長','宋','宋诗','song-poetry','','[]','鶴氅輕冠冕，誰人不羨君。',48,'全唐诗/poet.song.6000.json','["鶴氅輕冠冕，誰人不羨君。", "松齋秋掩月，石竇醉眠雲。", "遠墅竈煙合，寒原驛路分。", "前行鞭瘦馬，餘恨暫離羣。"]'),
('bbd21863-1ca6-45e2-bb17-febfd071a968','贈郝禮丞','釋簡長','宋','宋诗','song-poetry','','[]','住近城西寺，門無俗客登。',48,'全唐诗/poet.song.6000.json','["住近城西寺，門無俗客登。", "朝回簾捲雪，吟冷硯生冰。", "鳥影罇中過，茶煙竹際凝。", "遙思來夜月，虛閣與誰凭。"]'),
('0bb6b49d-d0df-4000-bb21-61e4d218e248','感王太守見訪','釋簡長','宋','宋诗','song-poetry','','[]','行春擁隼旟，十里訪禪居。',48,'全唐诗/poet.song.6000.json','["行春擁隼旟，十里訪禪居。", "煮茗沙泉白，調琴竹閣虛。", "致君公望重，對客宦情疏。", "向夕回軒冕，林僧識佩魚。"]'),
('8c2a2332-0fe3-43da-b25c-2769f891ed75','宿許山人別業','釋簡長','宋','宋诗','song-poetry','','[]','嵐霽景初分，溪橋對石門。',48,'全唐诗/poet.song.6000.json','["嵐霽景初分，溪橋對石門。", "犬聲知遠客，燒影見前村。", "古木秋生菌，空山夜答猿。", "幾因留我宿，靜話極詩源。"]'),
('5089f8f2-6654-47dc-b77b-b8741d2d11da','送僧南歸','釋簡長','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u601d\u4e61"]','漸老念鄉國，先歸獨羨君。',48,'全唐诗/poet.song.6000.json','["漸老念鄉國，先歸獨羨君。", "吳山全接漢，江樹半藏雲。", "振錫林煙斷，添瓶澗月分。", "重棲上方夜，孤狖雪中聞。"]'),
('aac2827c-05fe-481c-8c41-dfa04375b57b','送居壽師西遊','釋簡長','宋','宋诗','song-poetry','','[]','迢遞咸秦路，東風送子游。',48,'全唐诗/poet.song.6000.json','["迢遞咸秦路，東風送子游。", "幾程看日落，孤影背河流。", "古戍煙微斂，遙峰雨半收。", "行行吟此景，應不念滄洲。"]'),
('01805779-30fe-485b-89b6-f0a4b5658048','送行禪師','釋簡長','宋','宋诗','song-poetry','','[]','南國山重疊，歸心向石門。',48,'全唐诗/poet.song.6000.json','["南國山重疊，歸心向石門。", "寄禪依鳥道，絕食過漁村。", "楚雪黏瓶凍，江沙濺衲昏。", "白雲深隱處，枕上海濤翻。"]'),
('cf0487bc-1f3c-485c-a7e3-9dbce3790e13','送僧遊五臺山','釋簡長','宋','宋诗','song-poetry','','[]','五峰橫絕漢，寒翠倚蒼冥。',48,'全唐诗/poet.song.6000.json','["五峰橫絕漢，寒翠倚蒼冥。", "積雪無煩暑，高杉礙落星。", "磧雪簷外見，邊角坐中聽。", "師到棲禪夜，龍湫獨灌瓶。"]'),
('b0b3710e-073b-46f8-9e05-7b6c4929a409','暮春言懷寄浙東轉運黄工部','釋簡長','宋','宋诗','song-poetry','','[]','花落前林春又殘，舍深蒼蘚擁柴關。',64,'全唐诗/poet.song.6000.json','["花落前林春又殘，舍深蒼蘚擁柴關。", "十年霜雪獨爲客，萬里夢魂空到山。", "溪竹舊憐同性直，嶺雲終約伴身閑。", "遙思謝傅多公暇，應徧留題水石閑。"]'),
('eea83fe7-5507-4116-8d1a-74a6384ddbb5','贈浩律師','釋簡長','宋','宋诗','song-poetry','','[]','浩也毘尼學，精於玉帳嚴。',48,'全唐诗/poet.song.6000.json','["浩也毘尼學，精於玉帳嚴。", "蟻酣停掃砌，燕乳記鈎簾。", "茶鼎敲冰煮，花壺漉水添。", "夢回池草綠，忍踐綠纖纖。"]'),
('4e543481-11ce-48bf-9dbf-9b0badedb766','寄雲水禪師','釋簡長','宋','宋诗','song-poetry','','[]','千峰聳寒翠，古剎凌秋雲。',48,'全唐诗/poet.song.6000.json','["千峰聳寒翠，古剎凌秋雲。", "高人斂幽跡，世事何由聞。", "禪石抱蒼蘚，祖衣含凈氛。", "有時溪上步，自與鳥猿羣。"]'),
('8fc3f4be-1d05-47ee-98f8-37b0aa79056f','句','釋簡長','宋','宋诗','song-poetry','','[]','煙壘沉寒笛，霜空擊雕。',11,'全唐诗/poet.song.6000.json','["煙壘沉寒笛，霜空擊雕。"]'),
('80b5ead6-9beb-48fc-861a-2133f6746232','與行肇師宿廬山棲賢寺','釋惟鳳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','冰瀑寒侵室，圍鑪靜話長。',48,'全唐诗/poet.song.6000.json','["冰瀑寒侵室，圍鑪靜話長。", "詩心全大雅，祖意會諸方。", "磬斷危杉月，燈殘古塔霜。", "無眠向遙夕，又約去衡陽。"]'),
('027a4e9b-ecbf-44d7-bd08-49c216ee62ce','送史館李學士任和州','釋惟鳳','宋','宋诗','song-poetry','','[]','歷陽南望極，岸遠石城危。',48,'全唐诗/poet.song.6000.json','["歷陽南望極，岸遠石城危。", "去夢驚潮斷，行吟見雁隨。", "淮帆向風闊，楚木落秋遲。", "到日應閑臥，公心帝自知。"]'),
('0b6edc10-27a0-4d32-89a6-ca5322562138','答宇昭師','釋惟鳳','宋','宋诗','song-poetry','','[]','要地無閑日，吟蹤肯暫過。',48,'全唐诗/poet.song.6000.json','["要地無閑日，吟蹤肯暫過。", "林泉歸計晚，雨雪向春多。", "徑僻稀來客，庭荒半長莎。", "獨眠思舊約，寒夢繞煙蘿。"]'),
('c49785fe-3f4c-4ca2-802a-33f2e4763a2b','寄登封宰韓殿丞','釋惟鳳','宋','宋诗','song-poetry','','[]','前秋登閣晚，吟次見晴雲。',48,'全唐诗/poet.song.6000.json','["前秋登閣晚，吟次見晴雲。", "中嶽聳當縣，三年靜對君。", "朱衣借客典，清俸買書分。", "別後逢搖落，相思隔晉汾。"]'),
('cf6a169a-b7a9-4e88-82a8-bd6ddff5e9d6','送陳豸處士','釋惟鳳','宋','宋诗','song-poetry','','[]','草長開路微，離思更依依。',48,'全唐诗/poet.song.6000.json','["草長開路微，離思更依依。", "家遠知琴在，時清買劍歸。", "孤城回短角，獨樹隔殘輝。", "別有鄰漁約，相迎掃釣磯。"]'),
('640854b9-aa57-4b00-b8c4-ae9a3659e19a','寄希晝','釋惟鳳','宋','宋诗','song-poetry','','[]','關中吟鬢改，多事與心違。',48,'全唐诗/poet.song.6000.json','["關中吟鬢改，多事與心違。", "客路逢人少，家書入關稀。", "秋聲落晚木，夜魄透寒衣。", "幾想林閑社，他年許共歸。"]'),
('26294aed-3bcc-4723-9a2b-01eec1a0c0e5','留題河中柴給事望雲亭','釋惟鳳','宋','宋诗','song-poetry','','[]','郡閑思退隱，嘉致望雲秋。',48,'全唐诗/poet.song.6000.json','["郡閑思退隱，嘉致望雲秋。", "舊客容誰訪，新詩許我留。", "棋窗寒日短，琴幌夜燈幽。", "青瑣無歸夢，期僧話沃洲。"]'),
('5b63d556-99d8-4331-b197-0774259fe20a','秋燈','釋惟鳳','宋','宋诗','song-poetry','','[]','耿耿銷深暗，孤窗豈暫忘。',48,'全唐诗/poet.song.6000.json','["耿耿銷深暗，孤窗豈暫忘。", "照回秋夢斷，靜引夜吟長。", "病鼠驚空穴，寒螢聚缺牆。", "鄰居還共惜，及物有餘光。"]'),
('0e1774fb-78a2-4984-b80b-b1cf4d85d5bc','寄昭文館陳學士','釋惟鳳','宋','宋诗','song-poetry','','[]','秋深荒外客，獨上望京臺。',48,'全唐诗/poet.song.6000.json','["秋深荒外客，獨上望京臺。", "遠信未封去，新鴻又見來。", "地寒邊樹短，天靜瘴雲開。", "無限心相向，南宮臥錦才。"]'),
('942f2794-9558-49d6-a591-d6de76ff9b7f','送徐涉南歸','釋惟鳳','宋','宋诗','song-poetry','','[]','長安來雁急，相顧話離心。',48,'全唐诗/poet.song.6000.json','["長安來雁急，相顧話離心。", "日落思家遠，天寒歸路深。", "秋光生獨樹，夕吹響孤砧。", "漸入雲鄉望，應無越客吟。"]'),
('9d789157-a97c-4f39-96e5-22a95cc4a38f','弔長禪師','釋惟鳳','宋','宋诗','song-poetry','','[]','霜鐘侵漏急，相弔曉悲濃。',48,'全唐诗/poet.song.6000.json','["霜鐘侵漏急，相弔曉悲濃。", "海客傳遺偈，林僧寫病容。", "漱泉流落葉，定石集鳴蛩。", "回首雲門望，殘陽下遠峰。"]'),
('504e8a0e-ba51-4797-b612-e6ec3eac496a','寄兆上人','釋惟鳳','宋','宋诗','song-poetry','','[]','久負中條約，深秋興若何。',48,'全唐诗/poet.song.6000.json','["久負中條約，深秋興若何。", "白雲歸望遠，黄葉意空多。", "靜臥侵仙掌，微吟隔楚波。", "飛書答招隱，迢遞寄煙蘿。"]'),
('68eb56c4-14e2-4a9e-bab6-b736778126ea','姑射山詩題曾山人壁','釋惟鳳','宋','宋诗','song-poetry','','["\u5c71", "\u8d5e\u9882", "\u5199\u4eba"]','東西望朔漠，姑射獨崔嵬。',96,'全唐诗/poet.song.6000.json','["東西望朔漠，姑射獨崔嵬。", "一片兩片雲，終南太華來。", "根繞黄河曲，影落清渭隈。", "深澗飲渴虹，邃洞生秋雷。", "古徑窮難盡，晴嵐撥不開。", "海鵬飛上遲，邊風勁觸回。", "傲隱非他古，依靈有奇才。", "曾生心若何，猿聲終夜哀。"]'),
('22e13c8a-af45-4972-aa7d-4ca190f71797','寄劉處士','釋惟鳳','宋','宋诗','song-poetry','','[]','度月阻相尋，應爲苦雨吟。',48,'全唐诗/poet.song.6000.json','["度月阻相尋，應爲苦雨吟。", "井渾茶味失，地潤屐痕深。", "鳥背長湖色，門間古樹陰。", "想君慵更甚，華髪晝方簪。"]'),
('a00c9d24-73da-4c97-9fa1-22d32e06ddb0','贈維陽呂爲處士','釋惟鳳','宋','宋诗','song-poetry','','[]','爲儒師古道，清苦少人知。',48,'全唐诗/poet.song.6000.json','["爲儒師古道，清苦少人知。", "心散暫因酒，鬢班多爲詩。", "著書秋閣靜，曬藥夕陽遲。", "何必文明代，垂鈎渭水湄。"]'),
('ab811f85-6980-4df0-8a9c-bfcdddefcc8c','句  其一','釋惟鳳','宋','宋诗','song-poetry','','[]','草檄飛燕壘，降幡入漢營。',12,'全唐诗/poet.song.6000.json','["草檄飛燕壘，降幡入漢營。"]'),
('00064739-2589-4f98-8533-d443c8579fde','句  其二','釋惟鳳','宋','宋诗','song-poetry','','[]','岸盡吳山出，潮平越樹低。',12,'全唐诗/poet.song.6000.json','["岸盡吳山出，潮平越樹低。"]'),
('49b0ceb6-4e84-469b-823e-c406caf4ef73','句  其三','釋惟鳳','宋','宋诗','song-poetry','','[]','寺近東溟日，山連北固春。',12,'全唐诗/poet.song.6000.json','["寺近東溟日，山連北固春。"]'),
('bd132688-813c-4c08-b69a-e39efac3fa72','句  其四','釋惟鳳','宋','宋诗','song-poetry','','[]','衆星隨手舉，萬物應心平。',12,'全唐诗/poet.song.6000.json','["衆星隨手舉，萬物應心平。"]'),
('a44610e7-c3e1-43e2-9c81-e9f785928fdc','訪楊雲卿淮上別墅','釋惠崇','宋','宋诗','song-poetry','','[]','地近得頻到，相攜向野亭。',48,'全唐诗/poet.song.6000.json','["地近得頻到，相攜向野亭。", "河分岡勢斷，春入燒退青。", "望久人收釣，吟餘鶴振翎。", "不愁歸路晚，明月上前汀。"]'),
('321798ff-5246-416a-930e-d23397f317fb','塞上贈王太尉','釋惠崇','宋','宋诗','song-poetry','','[]','飛將是嫖姚，行營已近遼。',48,'全唐诗/poet.song.6000.json','["飛將是嫖姚，行營已近遼。", "河冰堅度馬，塞雪密藏雕。", "敗虜殘旗在，全軍列帳遙。", "傳呼更號令，今夜取天驕。"]'),
('29e41ec5-ba5e-4210-b03a-aa49c3e92771','贈文兆','釋惠崇','宋','宋诗','song-poetry','','[]','偶依京寺住，誰復得相尋。',48,'全唐诗/poet.song.6000.json','["偶依京寺住，誰復得相尋。", "獨鶴窺朝講，鄰僧聽夜琴。", "注瓶沙井遠，鳴磬雪房深。", "久與松蘿別，空懸王屋心。"]'),
('ed625cda-6587-4f8e-aafc-013637ab8c37','送安學士守睦州','釋惠崇','宋','宋诗','song-poetry','','[]','白浪滿遙程，公衙□□聲。',48,'全唐诗/poet.song.6000.json','["白浪滿遙程，公衙□□聲。", "海帆通夜市，山雨徧春耕。", "古意隨琴遠，離愁對酒輕。", "三吳窺列宿，知傍隼旟明。"]'),
('3ac1103c-0b39-4e39-846c-60798561fefa','贈吳黔山人','釋惠崇','宋','宋诗','song-poetry','','[]','三年不下嶽，衣屨古苔侵。',48,'全唐诗/poet.song.6000.json','["三年不下嶽，衣屨古苔侵。", "石澗探幽步，風泉得句心。", "黄猿知日暝，青樹覺春深。", "又向南峰住，時時許我尋。"]'),
('d85508f8-f2a2-4a30-992a-8933d70367e4','晚夏夜簡程至','釋惠崇','宋','宋诗','song-poetry','','[]','中夕坐清簟，繁星時復流。',48,'全唐诗/poet.song.6000.json','["中夕坐清簟，繁星時復流。", "扇聲微變暑，井氣忽生秋。", "爲客方經楚，思鄉欲上樓。", "雲山殊未返，相顧兩悠悠。"]'),
('161d469e-d457-4cdb-bcf5-9687e0f460b2','書林逸人壁','釋惠崇','宋','宋诗','song-poetry','','[]','詩語動驚衆，誰知慕隱淪。',48,'全唐诗/poet.song.6000.json','["詩語動驚衆，誰知慕隱淪。", "水煙常似暝，林雪乍如春。", "薄酒懶邀客，好書愁借人。", "豕時行藥去，忘卻戴紗巾。"]'),
('c6b0827e-cd59-48cf-bc7e-aad0acc78d9e','古塞曲','釋惠崇','宋','宋诗','song-poetry','','[]','邊烽久不息，戍鼓何鼟鼟。',72,'全唐诗/poet.song.6000.json','["邊烽久不息，戍鼓何鼟鼟。", "五月無青草，滂沱流斷冰。", "胡兒昧形勝，漢騎恣憑陵。", "出號朔風起，受降沙壘崩。", "樓煩已納款，天意□威稜。", "歸佩封侯印，喧然世所稱。"]'),
('2ab323d5-a96e-454d-b5a9-3317241c85c8','剡中秋懷晝師','釋惠崇','宋','宋诗','song-poetry','','[]','秋生剡江濆，清氣日泱漭。',60,'全唐诗/poet.song.6000.json','["秋生剡江濆，清氣日泱漭。", "雲歸樹欲無，潮落山疑長。", "偶坐還獨謠，故人在遐想。", "夕景孤嶼明，暗蟲四鄰響。", "神會如目存，安知途路廣。"]'),
('bc342d70-2b5c-4488-92d1-62610ec3fd45','擬古','釋惠崇','宋','宋诗','song-poetry','','[]','幽禽迎曙響，佳木含春榮。',48,'全唐诗/poet.song.6000.json','["幽禽迎曙響，佳木含春榮。", "獨有綺窗婦，耿耿萬里情。", "塵色皓鴛幌，日華明風箏。", "高蓋久不返，中宵自懷貞。"]'),
('3c37a836-fc8f-4288-96c0-f91c5b424bcc','中夜起','釋惠崇','宋','宋诗','song-poetry','','[]','初月不到曉，夜色何冥冥。',24,'全唐诗/poet.song.6000.json','["初月不到曉，夜色何冥冥。", "獨立秋江上，風波卷寒星。"]'),
('7f4d35ae-1aa2-4bf1-80ce-dba6dbfcfb2c','池上鷺分賦得明字','釋惠崇','宋','宋诗','song-poetry','','[]','雨絕方塘溢，遲徊不復驚。',48,'全唐诗/poet.song.6000.json','["雨絕方塘溢，遲徊不復驚。", "曝翎沙日暖，引步島風清。", "照水千尋迥，棲煙一點明。", "主人池上鳳，見爾憶蓬瀛。"]'),
('c1b2807e-c9eb-421a-8f05-609f29f0263d','題石橋','釋惠崇','宋','宋诗','song-poetry','','[]','千尋亘絕險，危步想仙翁。',48,'全唐诗/poet.song.6000.json','["千尋亘絕險，危步想仙翁。", "日上霞紋斷，春生雪溜空。", "虹形離碧水，輪勢入青穹。", "人世何由及，唯應天漢通。"]'),
('f9797c06-5017-4f9c-8f87-82d29c12a970','效古','釋惠崇','宋','宋诗','song-poetry','','[]','清都綠玉樹，灼爍瑤臺春。',60,'全唐诗/poet.song.6000.json','["清都綠玉樹，灼爍瑤臺春。", "攀花弄秀色，遠贈天仙人。", "香風送紫蕊，直到扶桑津。", "取掇世上艷，所貴心之珍。", "相思傳一笑，聊欲示情親。"]'),
('5189661b-3e13-445d-a64d-424206edb15f','句  其一','釋惠崇','宋','宋诗','song-poetry','','[]','陰井生秋早，明河轉曙遲。',12,'全唐诗/poet.song.6000.json','["陰井生秋早，明河轉曙遲。"]'),
('dcad7797-7f69-4717-8275-657517274074','句  其二','釋惠崇','宋','宋诗','song-poetry','','[]','地形吞蜀盡，江勢抱蠻迴。',12,'全唐诗/poet.song.6000.json','["地形吞蜀盡，江勢抱蠻迴。"]'),
('b96eee62-8722-4512-b644-32e0d7bed5b5','句  其三','釋惠崇','宋','宋诗','song-poetry','','[]','嶺暮清猿急，江寒白鳥稀。',12,'全唐诗/poet.song.6000.json','["嶺暮清猿急，江寒白鳥稀。"]'),
('bcf07591-f31f-4c5b-9615-b2b49ab32772','句  其四','釋惠崇','宋','宋诗','song-poetry','','[]','歸禽動疏竹，落果響寒塘。',12,'全唐诗/poet.song.6000.json','["歸禽動疏竹，落果響寒塘。"]'),
('db23218b-da5e-46af-b98e-7b6858dca0ed','句  其五','釋惠崇','宋','宋诗','song-poetry','','[]','野人傳相鶴，山叟學彈琴。',12,'全唐诗/poet.song.6000.json','["野人傳相鶴，山叟學彈琴。"]'),
('5a1daf34-6b06-4d28-a37f-137e327d0887','句  其六','釋惠崇','宋','宋诗','song-poetry','','[]','春淺冰生井，宵分月上軒。',12,'全唐诗/poet.song.6000.json','["春淺冰生井，宵分月上軒。"]'),
('741f8137-f298-4dcd-80ee-c524e86b8b47','句  其七','釋惠崇','宋','宋诗','song-poetry','','[]','掩門青檜老，山寺白髭長。',12,'全唐诗/poet.song.6000.json','["掩門青檜老，山寺白髭長。"]'),
('46e29d00-5454-4636-ace9-c9e00ab75d69','句  其八','釋惠崇','宋','宋诗','song-poetry','','[]','浪經蛟浦闊，山入鬼門寒。',12,'全唐诗/poet.song.6000.json','["浪經蛟浦闊，山入鬼門寒。"]'),
('dad85c6e-4437-4783-91f5-cb0c7e7d1ac8','句  其九','釋惠崇','宋','宋诗','song-poetry','','[]','遺偈傳諸國，留真在一峰。',12,'全唐诗/poet.song.6000.json','["遺偈傳諸國，留真在一峰。"]'),
('f4c25c44-2029-4f98-be67-3f3161f97bc3','句  其一○','釋惠崇','宋','宋诗','song-poetry','','[]','久別年顔改，相逢夜話長。',12,'全唐诗/poet.song.6000.json','["久別年顔改，相逢夜話長。"]'),
('3518d7dd-44e5-49f8-b9da-3c704bc4a3b5','句  其一一','釋惠崇','宋','宋诗','song-poetry','','[]','多年不道姓，幾日旋移家。',12,'全唐诗/poet.song.6000.json','["多年不道姓，幾日旋移家。"]'),
('8b5ac079-6204-4b30-af5b-953d7c6d1576','句  其一二','釋惠崇','宋','宋诗','song-poetry','','[]','鳥歸杉隨雪，僧去石沉雲。',12,'全唐诗/poet.song.6000.json','["鳥歸杉隨雪，僧去石沉雲。"]'),
('bf59cd49-6b7e-450e-b48b-dcc9e88855f2','句  其一三','釋惠崇','宋','宋诗','song-poetry','','[]','露寒金掌重，天近玉繩低。',12,'全唐诗/poet.song.6000.json','["露寒金掌重，天近玉繩低。"]'),
('0d639c47-01ff-4ed3-8ee9-92d51ddc6db9','句  其一四','釋惠崇','宋','宋诗','song-poetry','','[]','著書驚日短，彈劍惜春深。',12,'全唐诗/poet.song.6000.json','["著書驚日短，彈劍惜春深。"]'),
('ab8d512f-c062-4bb5-bcce-7b487bb7a715','句  其一五','釋惠崇','宋','宋诗','song-poetry','','[]','探騎通番壘，降兵逐漢旗。',12,'全唐诗/poet.song.6000.json','["探騎通番壘，降兵逐漢旗。"]'),
('bb62a0cd-9d3e-4ce1-9104-6e8d32eeccca','句  其一六','釋惠崇','宋','宋诗','song-poetry','','[]','露下牛羊靜，河明桑柘空。',12,'全唐诗/poet.song.6000.json','["露下牛羊靜，河明桑柘空。"]'),
('0ceb2eb4-7802-42ae-b54c-0965fb942651','句  其一七','釋惠崇','宋','宋诗','song-poetry','','[]','林斷城隍出，江分島嶼迴。',12,'全唐诗/poet.song.6000.json','["林斷城隍出，江分島嶼迴。"]'),
('7b9a4fc5-123d-495c-8dd1-3f2c30c78395','句  其一八','釋惠崇','宋','宋诗','song-poetry','','[]','鎖城山月上，吹角海鷗驚。',12,'全唐诗/poet.song.6000.json','["鎖城山月上，吹角海鷗驚。"]'),
('5904b74c-1524-4cd8-8024-f2257f1eeb12','句  其一九','釋惠崇','宋','宋诗','song-poetry','','[]','卷幔來風遠，移牀得月多。',12,'全唐诗/poet.song.6000.json','["卷幔來風遠，移牀得月多。"]'),
('848ae876-bd93-4eab-837e-58297f109b59','句  其二○','釋惠崇','宋','宋诗','song-poetry','','[]','白浪分吳國，青山隔楚天。',12,'全唐诗/poet.song.6000.json','["白浪分吳國，青山隔楚天。"]'),
('d84aedeb-a303-432e-bbd9-d72345cb6d6e','句  其二一','釋惠崇','宋','宋诗','song-poetry','','[]','空潭聞鹿飲，疏樹見僧行。',12,'全唐诗/poet.song.6000.json','["空潭聞鹿飲，疏樹見僧行。"]'),
('f82ddaa6-d9ae-4c6b-b376-51201dd8d1fb','句  其二二','釋惠崇','宋','宋诗','song-poetry','','[]','劍佩明山雪，旌旗濕海雲。',12,'全唐诗/poet.song.6000.json','["劍佩明山雪，旌旗濕海雲。"]'),
('3c68f532-1274-4ed9-b74f-bf0af88db2ee','句  其二三','釋惠崇','宋','宋诗','song-poetry','','[]','曠野行人少，長河去鳥平。',12,'全唐诗/poet.song.6000.json','["曠野行人少，長河去鳥平。"]'),
('19207c5b-7c32-4338-94dd-2d2e26007d4f','句  其二四','釋惠崇','宋','宋诗','song-poetry','','[]','月高山舍迥，霜落石門深。',12,'全唐诗/poet.song.6000.json','["月高山舍迥，霜落石門深。"]'),
('52e72d4d-dd58-4846-80bf-0ca627708f53','句  其二五','釋惠崇','宋','宋诗','song-poetry','','[]','霜多秦木迥，雲盡漢山孤。',12,'全唐诗/poet.song.6000.json','["霜多秦木迥，雲盡漢山孤。"]'),
